-- Poems batch 92
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7e796c52-36aa-49ae-ae55-6723520b6fa4','和溫其對月之什','劉子翬','宋','宋诗','song-poetry','','[]','意根如亂苗，已薙仍復生。',84,'全唐诗/poet.song.111000.json','["意根如亂苗，已薙仍復生。", "讀君對月吟，知君懷未平。", "懷悽有豐恨，吟苦無和聲。", "雄豪睨一世，失路鴻毛輕。", "所以達觀士，榮枯兩忘情。", "蒼蒼古松林，下有寒泉清。", "醉倒石上眠，山禽喚人耕。"]'),
('ec33007d-6eb2-4ebe-b818-4968fd94e020','讀平險銘寄李漢老','劉子翬','宋','宋诗','song-poetry','','[]','官侯鑿平劍浦灘，遊子不歌行路難。',384,'全唐诗/poet.song.111000.json','["官侯鑿平劍浦灘，遊子不歌行路難。", "李公作銘垂不刊，峻峰激流生筆端。", "斯文豈但夸雄觀，寓理之奧開聾眢。", "惟人性天同廣胖，橫目立見分庭壇。", "紛敷蔽翳榛葦萑，騰逃鬰屈猿蛇蚖。", "銛剡獵利劍戟攢，離睽截裂趙魏韓。", "千崖百瀨中繞蟠，覆溺嵬岸糜堅完。", "胡爲氣舒貌顢頇，旁觀已洞其肺肝。", "浮思一縱坂走丸，不極不止巧力殫。", "塗膏然萁卒焦乾，萬古乾坤元自安。", "堂堂靈君司五官，乍臣乍叛勞控摶。", "日漸月磨如印刓，壯哉情枿牢盤還。", "躁謀欲驟加雕剜，慘若蕭斧臨髀髖。", "自腥夷之良可歎，何如含垢休索瘢。", "洒洒落落從中看，豁然四通裂囊簞。", "有如灘流平不湍，鑑靜天空秋月寒。", "療性此寔言中丹，至味淡薄誰能餐。", "我昔蒙公分剩殘，桐花城西路漫漫。", "裁牋屢喚南飛翰，何當澡瀹紉椒蘭。", "厚地爲屨天爲冠，從公上征鞭龍鸞。", "訪瞿追孔聊遊般，物外虛明如許寬。", "脚底日轉紅團欒，瑶池簉席一笑闌。", "春著萬象流餘懽，茲遊未遂心慱慱。", "吟餘北窗睡長鼾，清風時來撼琅玕。"]'),
('d26ef99c-c136-4728-9c59-07deaad36e97','同胡原仲吳公路遊清湍亭賦詩得流字','劉子翬','宋','宋诗','song-poetry','','[]','出山曾幾時，桂露颯已秋。',132,'全唐诗/poet.song.111000.json','["出山曾幾時，桂露颯已秋。", "興來任兩屐，散此默默憂。", "嵐光近仍滅，鳥語靜忽流。", "新亭迥臨危，急澗循巖陬。", "上有獨樹蔭，下有鳴湍幽。", "長飆一振蕩，俯仰聞颼飀。", "平生塵累心，浄盡迥此遊。", "徘徊嘯詠發，瞻眺窮林丘。", "天寒雲已歸，山好客自留。", "悠然百不知，日月過則休。", "人生樂在我，何必遂所求。"]'),
('46d7dbc2-3bbd-41a2-93aa-7fb80ebc011d','和熊叔雅四詠 石峰春靄','劉子翬','宋','宋诗','song-poetry','','[]','寒山遠欲無，春在冥濛處。',24,'全唐诗/poet.song.111000.json','["寒山遠欲無，春在冥濛處。", "何如掃浮陰，盡放岧嶢露。"]'),
('0ac36605-3aa4-4888-b0c7-dcc0b770043a','和熊叔雅四詠 清湖驟雨','劉子翬','宋','宋诗','song-poetry','','[]','快雨不相期，平湖忽蕭颯。',24,'全唐诗/poet.song.111000.json','["快雨不相期，平湖忽蕭颯。", "坐久日明簷，繁聲靜中滅。"]'),
('d55994ca-60da-4960-8fa3-a7544064f6b9','和熊叔雅四詠 潭溪秋碧','劉子翬','宋','宋诗','song-poetry','','[]','秋空晚自明，孤烟澹難起。',24,'全唐诗/poet.song.111000.json','["秋空晚自明，孤烟澹難起。", "適意一枝筇，時來對寒水。"]'),
('b1d9fc89-26d8-4f50-b919-bb8cbfd8cbe4','和熊叔雅四詠 屏山夜雪','劉子翬','宋','宋诗','song-poetry','','[]','誰憐組練寒，夜雪連營積。',24,'全唐诗/poet.song.111000.json','["誰憐組練寒，夜雪連營積。", "有客卧衡茅，淮山夢中白。"]'),
('be40ad81-d442-4489-9d6b-16645557b887','次韵李漢老詩','劉子翬','宋','宋诗','song-poetry','','[]','蒙莊歎隙駒，孔聖悲逝川。',180,'全唐诗/poet.song.111000.json','["蒙莊歎隙駒，孔聖悲逝川。", "百年生有涯，萬感情無邊。", "賢愚真唯阿，繫心同一緣。", "內熱蠱其中，伊誰肯求痊。", "樂哉今日遊，衆賓肅初筵。", "社樗間羣材，嫫母參衆妍。", "謔弄既莞爾，獻酬亦頹然。", "胡爲發爭端，咄咄論深禪。", "擊水但增波，止薪自無煙。", "便應三宜休，敢論四不遷。", "公如高車馳，揚塵絕通廛。", "我如馭小駟，交綏已回旋。", "初謀不自量，取困大敵前。", "金化質不亡，冰融水非堅。", "市門有真樓，相從待他年。"]'),
('e26e247e-efec-415c-92cd-dc72e9ca7752','次韵致明七言','劉子翬','宋','宋诗','song-poetry','','[]','春風摇溪溪摇天，劉郎詩思如涌泉。',96,'全唐诗/poet.song.111000.json','["春風摇溪溪摇天，劉郎詩思如涌泉。", "已憐飛花太狼藉，却愛芳草長芊綿。", "癡兒了事從渠了，萬古寒空沒飛鳥。", "北海樽中興味長，邯鄲枕裏功名小。", "南山北山雲崔嵬，君胡不歌歸去來。", "山中交遊苦相憶，玉柱瑶瑟生浮埃。"]'),
('26a052e2-f76e-453b-8c80-c211a593ff9f','謝方德順古風','劉子翬','宋','宋诗','song-poetry','','[]','吾聞滄溟深，浸灌東南維。',240,'全唐诗/poet.song.111000.json','["吾聞滄溟深，浸灌東南維。", "長風一蕩潏，莽蒼天爲低。", "中藏百怪珍，文彩光陸離。", "潛鯤盡鵬材，游魚悉龍資。", "罔象溯波浮，天吳躍空飛。", "蚌雖辱泥塗，猶能吐珠璣。", "地靈物固然，在人必多奇。", "英英方家郎，秀發如瓊枝。", "裝懷素王書，落筆幼婦詞。", "我昔官壺山，邂逅初見之。", "賓筵爲勸駕，一武登雲梯。", "鴻鶱九霄快，驥騁天路夷。", "似聞東諸侯，辟書已交馳。", "惠然訪吾廬，窈窕窮山谿。", "夜燈一笑歡，愁抱忽若遺。", "語妙時脫塵，飲豪屢反巵。", "領新意自失，佳處昔未窺。", "胡爲遽改轅，歸袂風披披。", "上祈養德業，下祝慎鼎幃。", "敬言崇道公，久別良佇思。"]'),
('e95c3ca7-dfcf-435f-b438-a541b49090d3','少稷遠訪弊廬仍留佳句書此寫懷抱不足爲報也','劉子翬','宋','宋诗','song-poetry','','[]','常嫌門外車，驅馳但揚塵。',240,'全唐诗/poet.song.111000.json','["常嫌門外車，驅馳但揚塵。", "今朝故人來，喜聽聲轔轔。", "昔別自梁苑，分飛湘吳閩。", "痛心鳴鏑禍，事往勿復陳。", "共載諧寥閴，分筇上嶙峋。", "山川舊賞識，挾友意彌新。", "徘徊小精廬，劇談口翻津。", "爲言漂蕩餘，投迹荒寒濱。", "夕火斧僧林，朝餐糴鄰囷。", "官閑非所恨，有祿不濟貧。", "牢愁寫萬斛，語壯眉不顰。", "定知撐腸書，爲君發精神。", "調鐘尚變啞，畫龍孰窺真。", "吾聞倜儻才，韜默貴自珍。", "量海浚宜廣，豪山磨欲磷。", "十科世所重，羣公謂當仁。", "向來薦牘飛，璧光動高旻。", "陳編論糟粕，中有王道諄。", "謀國必張國，療民須活民。", "但得君名揚，何異我志伸。"]'),
('5491a316-44b9-4b78-8040-011866c5a7eb','柳源觀瀑戲明仲','劉子翬','宋','宋诗','song-poetry','','[]','山橫曉色中，綫路窮崎嶇。',144,'全唐诗/poet.song.111000.json','["山橫曉色中，綫路窮崎嶇。", "何年貫日虹，飄然墮秋虛。", "晴暉發燦爛，陰飆助傾輸。", "淙深粉雪沸，注險龍蛇趨。", "平生浩蕩胸，對此聊一舒。", "蒼蒼古澄潭，彷彿幽靈居。", "奇觀付豪逸，餘潤分膏腴。", "來遊今七賢，賤跡欣與俱。", "扶筇却軒輊，坐石安氍毹。", "壁陰生小寒，賞澹樂有餘。", "詩魔久已降，幽事復起予。", "爲言玉堂人，五字不可無。"]'),
('cfa5aaa8-7c9c-4784-a6fc-87fa36ec7b01','次韵明仲遊將軍巖','劉子翬','宋','宋诗','song-poetry','','[]','樂哉今日遊，結友盡英秀。',240,'全唐诗/poet.song.111000.json','["樂哉今日遊，結友盡英秀。", "山靈欣客來，閣雨開雲岫。", "步屣出烟嵐，聲呼答巖竇。", "輕生快險奇，一墜那復捄。", "崇林蓊地幽，長湍瀉天漏。", "精廬記舊經，密徑迷新簉。", "將軍隠高寒，古井餘荒甃。", "當年百戰疲，蟣蝨生戎胄。", "心存巢許間，功豈韓彭後。", "慨然望中原，毒手方交鬭。", "曷不生斯辰，天驕過難宥。", "妖氛六合昏，長夜何時晝。", "尊周感獲麟，懷楚歌啼狖。", "世變莽難知，如瞽窺篆籀。", "置之勿重論，大白引醇酎。", "幽禽靜一聞，寒芳晚三嗅。", "方虛接勝懷，日轂轉何驟。", "山南山北奇，脚力倦尋究。", "良遊易蹉跎，澹境難宿留。", "詩囊歸倒懸，瓊琚羨君富。"]'),
('a508ff33-e2fa-4625-8682-445beaf4c3f7','寄彭子靜','劉子翬','宋','宋诗','song-poetry','','[]','凍岫立高白，曉寒生太虛。',108,'全唐诗/poet.song.111000.json','["凍岫立高白，曉寒生太虛。", "閉門翻巾幐，偶見良友書。", "書中有長句，別懷陳鬰紆。", "吐鳳詞既絕，續貂理難如。", "起望新鄉雲，一讀三卷舒。", "繁思攪中扃，頼此豁欲無。", "鵠鷄有潛化，蓬麻豈資扶。", "吾人交義深，不恨相見疏。", "但恐德不修，心期愧非初。"]'),
('a81fd847-7c17-4ff7-a302-a0739938f836','必源以古風見投詞意甚遠因爲賦風吹原上苗勉其殖學待時也','劉子翬','宋','宋诗','song-poetry','','[]','風吹原上苗，青青入無邊。',108,'全唐诗/poet.song.111000.json','["風吹原上苗，青青入無邊。", "發生頼陽和，秀潤滋澄漣。", "遊車走道旁，忽之如浮烟。", "那知丁黄愁，枵腹望果然。", "農功日夜急，地産東南偏。", "飛霜皓盈疇，豐穗垂連顛。", "盤盂薦新嘗，瓊糜失輝鮮。", "物生爲世用，豈較成後先。", "羣芳紅打圍，從渠爭春妍。"]'),
('a176e49e-173d-459a-a9ad-8da98d2c8759','少稷賦十二相屬詩戲贈一篇','劉子翬','宋','宋诗','song-poetry','','[]','不用爲鼠何數奇，飯牛南山聊自怡。',96,'全唐诗/poet.song.111000.json','["不用爲鼠何數奇，飯牛南山聊自怡。", "探穴取虎有奇禍，守株伺兔非全癡。", "文成雕龍盈卷軸，畫蛇失杯坐添足。", "走馬章臺憶舊遊，歲月纔驚羊胛熟。", "六窗要自息獼猴，黄雞無應心日休。", "白衣蒼狗變化易，世事何殊牧豬戲。"]'),
('3532938e-40b7-4d61-ba11-b76e1d0cfa70','夜行潭溪上念仲原致中喬年茂元伯達皆有入山期以詩趣之','劉子翬','宋','宋诗','song-poetry','','[]','長夏不見雨，袢暑故相病。',120,'全唐诗/poet.song.111000.json','["長夏不見雨，袢暑故相病。", "及茲顥氣回，一夕飛灑併。", "攬衣步新凉，宇宙涵清潤。", "月離南山高，水循雙澗靜。", "流觀外既洽，至樂中潛應。", "緬懷平生友，契闊時光運。", "石峰許尋盟，有約殊未定。", "事紛莽如塵，欲掃那得盡。", "年衰覺世浮，慮澹知心勝。", "良遊莫蹉跎，小暇即乘興。"]'),
('00fb9c0a-3790-46c6-8ac0-f90eb66637ee','再和六四叔所賦十二相屬詩','劉子翬','宋','宋诗','song-poetry','','[]','饑鼠緣條殘果墮，舍如蝸牛足高卧。',96,'全唐诗/poet.song.111000.json','["饑鼠緣條殘果墮，舍如蝸牛足高卧。", "無心虎殿逐羣英，尚想兔園傾一坐。", "同年我又衰龍鍾，夔蛇相憐寧有窮。", "馬革戰場空白骨，羊裘釣瀨餘清風。", "棘端造猴巧難學，且赴茅簷雞黍約。", "雲深杞狗夜可尋，已辦豬靴走磽确。"]'),
('c33c9902-1c05-4b99-b5d0-746c3738af1a','讀曾吉甫橫碧齋詩','劉子翬','宋','宋诗','song-poetry','','["\u8861\u5c71"]','携鉏引荒泉，偶步松崗北。',180,'全唐诗/poet.song.111000.json','["携鉏引荒泉，偶步松崗北。", "泠然毛骨清，楚尾見秋色。", "稻氣馥初凉，檉陰澹微日。", "緬懷小齋居，櫺檻增岑寂。", "曠度滅知聞，微吟數峰碧。", "若人端好修，珍駕動無跡。", "深窮伊水源，峻陟衡山極。", "終焉憩孔林，所樂惟自得。", "延和數酌醪，侑靜一編易。", "向來辱傾輸，洞見胸中白。", "思親道匪侔，既遠情不懌。", "矧余質冥頑，固未易刻畫。", "尊生有遐心，克己無全力。", "以茲畏所知，負負常夕惕。", "餘波儻時漸，玉汝天其或。"]'),
('98fab8ef-6c73-492e-a10e-6bcd99259283','次韵明仲遊棲雲閣','劉子翬','宋','宋诗','song-poetry','','[]','溪山步步開圖障，山影更隨溪蕩漾。',128,'全唐诗/poet.song.111000.json','["溪山步步開圖障，山影更隨溪蕩漾。", "回環兩縣烟雨奇，一目盡奄長橋上。", "乾楓枯柳澹不春，歡伯爲解愁城屯。", "書空咄咄亦良苦，抵掌嗚嗚聊任真。", "山房竹陰生晚寂，客醉忘歸主忘客。", "沉機已寄謝安棋，逸興何慚阮孚屐。", "道人棲雲樂其天，孰知爲仙孰爲禪。", "定應風蜩足枯槁，絕勝磨蟻爭回旋。"]'),
('7663aa60-6987-47cc-b6da-421a7631d57b','同汪正夫行夫望鄱江','劉子翬','宋','宋诗','song-poetry','','[]','夜夢鄱江清，曉踏鄱陽縣。',156,'全唐诗/poet.song.111000.json','["夜夢鄱江清，曉踏鄱陽縣。", "雲濤著眼新，還疑夢中見。", "寒聲彭蠡合，凍色廬峰現。", "時方冬氣深，水縮川原變。", "連沙突堆阜，派港分組練。", "蕭蕭蓬鬢風，瑟瑟葭叢霰。", "奇觀信幽絕，領略殊未遍。", "何當烟艇高，載我行鏡面。", "二難今勝流，愛客移清燕。", "飲酣生泰和，語妙融交戰。", "衰遲百不堪，一快天與便。", "回筇晚霽中，路壓滄浪轉。", "波光似留人，隨裾蕩華絢。"]'),
('8c9450b8-fd0e-4ad2-809c-e2b115143aff','呂居仁惠建昌紙被','劉子翬','宋','宋诗','song-poetry','','[]','寒聲晚移林，殘臘無幾日。',240,'全唐诗/poet.song.111000.json','["寒聲晚移林，殘臘無幾日。", "高人擁楮眠，臠卷意自適。", "素風含混沌，春煦回呼吸。", "餘溫偶見分，來自芝蘭室。", "乍舒魄流輝，忽捲潮無迹。", "未能澡余心，愧此一衾白。", "嘗聞旴江藤，蒼崖走虬屈。", "斬之霜露秋，漚以滄浪色。", "粉身從澼絖，蛻骨齊麗密。", "乃知瑩然姿，故自漸陶出。", "治物猶貴精，治心豈宜逸。", "平生感交遊，耳剽非無得。", "精神隨事分，內省殊未力。", "寸陰捐已多，老矣將何及。", "自從得此衾，夢覺常惕惕。", "清如夷齊鄰，粹若淵騫覿。", "獨警發鏗鍧，邪思戢毫忽。", "勿謂絕知聞，虛闈百靈集。", "鼎鬴或存戒，韋弦亦規失。", "則知君子所，惠以勵蒙塞。"]'),
('9be19709-b911-4e02-a859-e02115c852e9','任伯顯昨寄日柹不至續以膽瓶爲貺','劉子翬','宋','宋诗','song-poetry','','[]','石瀨分携常慘慘，尺書沓至中彌感。',64,'全唐诗/poet.song.111000.json','["石瀨分携常慘慘，尺書沓至中彌感。", "槁慥不呈嫫母面，圓壺俄落雄兒膽。", "南窗吾伊俱不勤，汲泉養花聊任真。", "枝頭造化豈耐久，我輩自有無窮春。"]'),
('8504a481-a0a3-4b7f-a6b8-62859a318b69','寄茶與汪正夫兼簡行夫','劉子翬','宋','宋诗','song-poetry','','[]','絳囊團窊社邊得，持歸廣文破枯寂。',64,'全唐诗/poet.song.111000.json','["絳囊團窊社邊得，持歸廣文破枯寂。", "三人舌本有雌黄，一引胸次還虛白。", "平生目成惟素書，邇英能事知有餘。", "欻然長嘯風裂石，黟山方卧小於菟。"]'),
('ecc6a987-0dec-4c2a-8d80-ca8ef3453970','雲巖竹源二禪俱與招客三月二十一日遂飯于竹源庵謀諸野則獲也劉奇仲有約不至吳周寶游德華劉致中暨公望劉才仲陳聖叔某會焉從容辯論懷抱甚適因賦詩以紀之','劉子翬','宋','宋诗','song-poetry','','[]','雲巖市聲中，竹源山色處。',240,'全唐诗/poet.song.111000.json','["雲巖市聲中，竹源山色處。", "平生幾兩屐，惟樂取意去。", "晨光霽老春，飛蓋雙溪路。", "沙平水漫流，雲散天全露。", "逶迤經淺坂，窈窕穿崇樹。", "綠登方怒舒，紅竟忽繁雨。", "斯焉得小休，境熟來已屢。", "徵君常主盟，呼吸名勝聚。", "子休心鐵石，太叔語韶頀。", "鼎鼎吳劉陳，俱有不凡度。", "余衰氣不華，清遨慚輒與。", "未渠推遠之，政以枵然故。", "九賓既雲集，一士乃鴻翥。", "毋多溷幽人，蔬茗煩草具。", "叢談雜莊謔，泛閲披黄素。", "豐鎸辨活筆，始畫窮真數。", "解衣半日許，萬古回胸膆。", "西窗引虛明，汛灑延晚步。", "懶身厭依隨，靜若超羈馭。", "博山真起予，浮烟一枝騖。"]'),
('25b28ab5-7cf2-44c9-b5af-f8216ea65c3f','寄茶與曾吉甫','劉子翬','宋','宋诗','song-poetry','','[]','兩焙春風一塍隔，玉尺銀槽分細色。',64,'全唐诗/poet.song.111000.json','["兩焙春風一塍隔，玉尺銀槽分細色。", "解苞難辨邑中黔，瀹盞方知天下白。", "岸巾小啜橫碧齋，真味從底傾輸來。", "曩歸畀余一語妙，三歲暗室驚轟雷。"]'),
('b073b8c5-ad87-48a6-a1b8-067f7f98e5f4','竹源之集奇仲不赴蕭屯以詩嘲之再用原韵','劉子翬','宋','宋诗','song-poetry','','[]','平生老子興，渾寄幽絕處。',240,'全唐诗/poet.song.111000.json','["平生老子興，渾寄幽絕處。", "寧嫌一坡遠，甘作十歇去。", "至今清夢狂，時走松陰路。", "心忻自吟哦，技癢輒披露。", "那知菅蒯微，辱報瑶瓊樹。", "胸中萬斛清，忽向毫端雨。", "援桴未敢再，破的已驚屢。", "病身得所便，一閲神氣聚。", "淇竹秋稜欒，洛花春布濩。", "真機不可藏，文亦肖風度。", "樂哉精廬遊，愧我不常與。", "陋鄉豈無奇，乏此追陪故。", "翻然卜鄰心，幾逐長風翥。", "但分茅半簷，不假牛十具。", "劉郎箇中人，幽期乃愆素。", "曾無負負言，直委茫茫數。", "移文太遽生，恐未明深膆。", "君看旋磨蟻，瑣屑安故步。", "何如驥突雲，軒豁隨長馭。", "集枯豈小歟，動者中不騖。"]'),
('c777901a-961b-446c-b849-11a96fe6a809','題大義泉','劉子翬','宋','宋诗','song-poetry','','[]','移筇山未深，切骨寒無那。',120,'全唐诗/poet.song.111000.json','["移筇山未深，切骨寒無那。", "蜿蜒瘦蒼虬，脚底飛騰過。", "幽亭護石池，庭事不敢涴。", "虛中涵月浄，冷面從雲呵。", "欲搥玄璧試，恐觸方諸破。", "平生泉石癡，屢此箕踞坐。", "重來照清癯，白髮添箇箇。", "凡心未痛浣，老氣日以惰。", "緬懷大義風，絕唱寧無和。", "悚然聽琮琤，耳觀爲之大。"]'),
('6da48467-6921-4886-ae5e-4bc23a8316c6','同范智聞五月十四日夜賞月','劉子翬','宋','宋诗','song-poetry','','[]','微風浄郊原，暮色含清夏。',120,'全唐诗/poet.song.111000.json','["微風浄郊原，暮色含清夏。", "層巔月欲上，烱烱木葉罅。", "豐姿一髮虧，爽氣千毫射。", "流光不著地，黄抹溪西舍。", "翩然釋嶠飛，雲浪鱗鱗化。", "常恐螺髻青，失此驪珠挂。", "奇觀天所吝，老眼得屢借。", "不嫌神太清，跣立高梧下。", "故人肯留連，一笑偶良夜。", "濁醪勿虛杯，庭縞醉可藉。"]'),
('d9489191-b29b-4110-9392-74ad139b56a1','向元伯寄爇香陶爐有心清聞妙之語','劉子翬','宋','宋诗','song-poetry','','[]','鄱江細壤如凝脂，陶成小爐圓浄姿。',64,'全唐诗/poet.song.111000.json','["鄱江細壤如凝脂，陶成小爐圓浄姿。", "色含三秋玉沆瀣，韵壓六尺金狻猊。", "明窗澹澹浮薰起，故人警余良有以。", "心清聞妙遊無方，萬石只在吾家傍。"]'),
('eedb59cf-673b-4c38-80f4-c538ca23700e','感白髮','劉子翬','宋','宋诗','song-poetry','','[]','兒時坐澗石，散髮如浮烟。',168,'全唐诗/poet.song.111000.json','["兒時坐澗石，散髮如浮烟。", "風驚綠鬅鬙，意欲凌飛仙。", "那知二毛見，倏忽到老邊。", "蒙紗猶鏟彩，獵鬢强呈鮮。", "星星儻未已，遂恐華吾顛。", "騎省歎遇合，郎潛感迍邅。", "萬古寄一轍，長歌悲昔賢。", "流光不假借，志抱何由宣。", "餘齡事可知，已矣寧非天。", "窮通各有待，憔悴孰使然。", "淒其槁梧畔，惕若明鏡前。", "靈膏詎能涅，薅拂事可憐。", "惟應幽室處，一猛放萬緣。", "嘗聞衛生要，心白髮自玄。"]'),
('a9c31e0c-d695-468c-bc87-15c579aef66a','同吳居安入開善四首 遊松菴','劉子翬','宋','宋诗','song-poetry','','[]','虛廊附山翔，泉聲小菴閉。',48,'全唐诗/poet.song.111000.json','["虛廊附山翔，泉聲小菴閉。", "齋餘恣行遨，剝啄忻屢至。", "午陰遇蘭芳，夕照坐松吹。", "徜徉無所爲，聊盡今日意。"]'),
('40878ae9-2486-4af3-bbc5-202080934271','同吳居安入開善四首 宿省軒','劉子翬','宋','宋诗','song-poetry','','[]','夜空合一寂，擾擾息萬勞。',48,'全唐诗/poet.song.111000.json','["夜空合一寂，擾擾息萬勞。", "幽懷耿不寐，孤燈側殘膏。", "稍知山雨來，聲在橫林高。", "淒然却成夢，夢泛秋江濤。"]'),
('af44a4ef-86b5-44b9-84d5-09a455b3cfc9','同吳居安入開善四首 過報德菴','劉子翬','宋','宋诗','song-poetry','','[]','循溪踏危矼，路入篔簹塢。',48,'全唐诗/poet.song.111000.json','["循溪踏危矼，路入篔簹塢。", "森森翠櫺間，一幹橫清雨。", "茶煙日月靜，石壁軒扉古。", "盡茲北山旁，小勝無遺取。"]'),
('28289480-f27d-44b9-af4d-2fbacebc2102','同吳居安入開善四首 出山','劉子翬','宋','宋诗','song-poetry','','[]','日日冬氣昏，霜風不鐮面。',48,'全唐诗/poet.song.111000.json','["日日冬氣昏，霜風不鐮面。", "回輿始見山，數點寒中現。", "我行得勝友，笑語生華絢。", "如何劍峰南，咫尺不常見。"]'),
('4ead4c9f-d2a8-4ab7-b011-3777d37c169e','次韵茂元獨速歌','劉子翬','宋','宋诗','song-poetry','','[]','大兒行文學蘇黄，暗潮無聲走茫茫。',198,'全唐诗/poet.song.111000.json','["大兒行文學蘇黄，暗潮無聲走茫茫。", "小兒分題擬甫白，手抉蟆頤取冰魄。", "自成機杼誰如君，悲歌乃有可憐色。", "曉來春歸薺葉新，青女摧之良不仁。", "那知妙齡氣如許，一睨辟易驚千人。", "我亦歸爲村衰翁，接花成條欹屋紅。", "跣行肯追蹀躞步，杯飲不羨琉璃鍾。", "相逢他事不發語，醉面徹日承谿風。", "君不見豐碑模糊立峴首，又不見繐帷虛斟百眉侑。", "何如吾儕見在身，有口猶堪著醇酎。", "陶陶兀兀未全非，赫赫炎炎豈長有。", "硯峰絕頂撫孤松，伊誰及此蒼髯壽。"]'),
('5f4322c9-37ea-4e2f-843d-a05a022134f3','張巨山賦蠟梅因成四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','取名慕橫枝，要自同風格。',24,'全唐诗/poet.song.111000.json','["取名慕橫枝，要自同風格。", "雖微調鼎味，宛有金鉉色。"]'),
('8c6751a1-6718-4bac-bead-8a59bc31b554','張巨山賦蠟梅因成四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','渾疑蠟作花，貌野中抱幽。',24,'全唐诗/poet.song.111000.json','["渾疑蠟作花，貌野中抱幽。", "冷香不盈階，意盡仍一流。"]'),
('efe03c7e-ed5d-44f8-9aa2-4c7a353e43bb','張巨山賦蠟梅因成四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','尖萼破微霜，明犀透清暾。',24,'全唐诗/poet.song.111000.json','["尖萼破微霜，明犀透清暾。", "不有朱紫繁，那知中色尊。"]'),
('a81e17da-96a0-4742-8dea-a621b9b9ecd0','張巨山賦蠟梅因成四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','今日尋此梅，危行石澗東。',24,'全唐诗/poet.song.111000.json','["今日尋此梅，危行石澗東。", "花神欲宣令，萬鐸懸春風。"]'),
('79fd06a7-34cf-43fb-a5b5-cf4ad35f1ec7','和李似之秉燭觀梅詩','劉子翬','宋','宋诗','song-poetry','','[]','凍色沈萬象，晴巔露皚皚。',120,'全唐诗/poet.song.111000.json','["凍色沈萬象，晴巔露皚皚。", "通宵月觀夢，夢破東風來。", "小立值芳氣，微尋見寒肧。", "我病亦呼客，沙邊久徘徊。", "恍然驚老眼，一枝印清杯。", "應知塵意盡，故向癯儒開。", "謫仙愛逃禪，茲心政難灰。", "覘新不待晨，燒燭寒巖隈。", "草木有含章，發揮要天才。", "頼公管領春，筆端起潛雷。"]'),
('014b6e43-4ba4-40d4-9508-eb3933db5410','行夫寄黄山榧子有詩因同來韵','劉子翬','宋','宋诗','song-poetry','','[]','老坡文中哮闞聲，凜凜常如對英峙。',192,'全唐诗/poet.song.111000.json','["老坡文中哮闞聲，凜凜常如對英峙。", "琅然諷詠興凌雲，瞠若追攀顙流泚。", "玉山妙唱久寂寥，可與言詩有之子。", "裁牋遠餉風露新，坐我千尺黄山底。", "初挼玄縠出冰霜，小嚼清香泛窗几。", "已輕魏帝昵蒲桃，肯許唐賢魁綠李。", "極知人口無正味，苦談甘酸各矜美。", "不經真識爲品題，此物初筵幾不齒。", "青菁有用拔蒿萊，白粲無酬腐糠粃。", "士懷瓌瑋勿自神，邂逅飛沈同一理。", "子才超矣會曄然，外澤中真期是以。", "味果固已驅煩邪，味道更須淪骨髓。"]'),
('48628015-22b9-49c4-84ef-37910370eab6','劉道祖江程萬丘順甫講易孟子拾其意爲二十韵','劉子翬','宋','宋诗','song-poetry','','[]','吾初讀七篇，未領躍如義。',240,'全唐诗/poet.song.111000.json','["吾初讀七篇，未領躍如義。", "晚而窺大易，稍解寂然意。", "乃知平放著，的的目前事。", "盡心則無餘，窮神忽超詣。", "以斯印羣書，拈出句句是。", "君臣父子間，運量周旋際。", "體之則光明，雜物了無累。", "偉哉此陳編，孔孟心所寄。", "有如撞洪鍾，合響入迢遞。", "言高聽者聵，不絕僅如綴。", "幸茲良友集，一發萬古祕。", "真長富辭原，百折無留勢。", "文通秉文均，裁度取中制。", "宛丘坐忘言，袖手豈深閉。", "鄙懷頓爲空，快若掃長篲。", "旁觀二三子，耳剽咸愕眙。", "誘之循循然，活處鱍鱍地。", "氣質雖有拘，學問欲如蛻。", "時乎不再來，過此恐少味。", "大書鑱坐隅，以起衰惰氣。"]'),
('e9c0a7dd-9f2a-4821-a6ee-e370881d2107','韓幹畫馬闕四足龍眠搨而全之','劉子翬','宋','宋诗','song-poetry','','[]','吾聞兩臂天下重，馬失四蹄將底用。',146,'全唐诗/poet.song.111000.json','["吾聞兩臂天下重，馬失四蹄將底用。", "平生想似萬里遊，對此惟心惻然動。", "得非曾落駑駘羣，踠脫泥塗良已勤。", "又疑逸氣厭拘係，絕蹯徑欲超浮雲。", "諦觀事乃不爾劇，破練丹青老無色。", "軒昂自有尊足存，顧眄一株陰山碧。", "韓生筆法妙此圖，龍眠搨出了不殊。", "斷鼇自昔徒聞說，續鳬雖工計已疏。", "何如染作滄江遠明滅，要看追風蹴微雲。"]'),
('cabf5385-33ee-4f9d-a519-25c107e9fea8','次明仲矼字韵詩','劉子翬','宋','宋诗','song-poetry','','[]','頖宮德厚仍信矼，北扉筆力談笑扛。',192,'全唐诗/poet.song.111000.json','["頖宮德厚仍信矼，北扉筆力談笑扛。", "重圭疊璧凜羣視，不使東甌成陋邦。", "日邊時見召仙李，林下那容棲老龐。", "故園此日成勝聚，歸夢不泛瀟湘江。", "萬畦流泉裹雲屋，一點遠岫低吟窗。", "客來有酒輒均醉，長嘯手拊高梧幢。", "挽蔬唯便玉本脆，碎鯉屢惜銀鋋雙。", "伊予於世真長物，掃迹自分逃崆𡵻。", "驟揄揚之則過矣，豈有骨相當奇厖。", "左提右挈儻聞道，一了快若船下瀧。", "極知魯衛兄弟國，邾小尚許趨風降。", "嶤嶤岌岌正壁立，濤瀨未敢輕舂撞。"]'),
('e8702d44-86a6-41a2-882a-94770adfc06f','寄致明兼簡余時升','劉子翬','宋','宋诗','song-poetry','','[]','篔簹有利材，要自爲本觀。',156,'全唐诗/poet.song.111000.json','["篔簹有利材，要自爲本觀。", "綠虬挾春怒，穴土氣已完。", "達士審所施，窮士審所安。", "癯劉燭人鏡，僞態了莫干。", "常吹噓二余，傳以摩雲翰。", "大余携書來，一見意已殫。", "似爲殊勝摇，胸中衮濤瀾。", "皴膚褫厚襲，枵腹拾衆殘。", "那知藝圃遊，宇宙自爾寬。", "黄間跳鏃易，省括眼要端。", "幸公調護之，無使困所難。", "鵝峰橫几上，晚翠深作寒。", "徜徉有真樂，未應悔儒冠。"]'),
('34b3eda2-820a-4fb9-91fe-c9be9735de13','次韵明仲畦字韵詩','劉子翬','宋','宋诗','song-poetry','','[]','祝融散仙在西溪，此老平生無町畦。',112,'全唐诗/poet.song.111000.json','["祝融散仙在西溪，此老平生無町畦。", "一日不見十日恨，綠稻渺渺吞幽思。", "細紅時澆壘塊胸，跣行笑逆泠然風。", "意消萬事如燎髮，小醉扶頭須半月。", "叩梧林谷爲呼號，隠几乾坤有超越。", "自憐頑鈍不可鞭，挽之欲置名流邊。", "長言爲我澡袢暑，灑目萬線琮琤懸。"]'),
('f027bb4d-7e4c-46be-b941-2a7cc5d10821','入白水懷士特溫其','劉子翬','宋','宋诗','song-poetry','','[]','曉山隨意開，夏氣含露澄。',204,'全唐诗/poet.song.111000.json','["曉山隨意開，夏氣含露澄。", "扶筇過巇嶮，飛仙亦凌兢。", "松濤浄可潄，嵐煙起如蒸。", "巨崿轉鼎鼎，危塍上層層。", "悠然瞻眺地，彷彿記昔曾。", "是鄉雖窮深，泥泥秀色凝。", "高扉靜相對，招邀足嘉朋。", "讌席覆大斗，吟窗燁華燈。", "於今安在哉，骨冷喚不應。", "軒軒鸞鳳遊，驚飆失飛騰。", "豈伊黄壤恨，興言鯁煩膺。", "含章不震輝，憔悴非所應。", "雖微三字顯，要許二豪稱。", "余衰怠好修，故態了不懲。", "倏爾念離索，終焉愧瓌能。", "噫嘻長風來，躊躕素蟾升。", "及時痛自策，迅彩不可憑。"]'),
('d414d988-947b-4e94-9adb-fc04ea16f1a4','胡明仲潭溪三日飲','劉子翬','宋','宋诗','song-poetry','','[]','潭溪梧竹堆，無地浮高蔭。',168,'全唐诗/poet.song.111000.json','["潭溪梧竹堆，無地浮高蔭。", "暑中猶未佳，袒膊俯清深。", "急雨翳幽芬，空山落啼鵀。", "村醪得舊燒，時果出寒沈。", "醺然三日醉，是鄉絕呵禁。", "巖風故吹醒，偷逸嫌太甚。", "人生唯一真，擾擾萬緣滲。", "斯遊不屢尋，老境恐遂寖。", "窺樽有餘波，捫腹猶可飲。", "澹蟾如曉色，渺渺長空浸。", "常憂景過清，浮雲忽飛譖。", "酣歌金石號，慷慨君獨任。", "俾予酬對之，祇作寒蟬噤。", "吾惟善咍臺，忘形卧相枕。"]'),
('869d13e0-32e1-4d94-8192-59a047bc5774','有懷','劉子翬','宋','宋诗','song-poetry','','[]','溪石磊磊出，溪光失溶溶。',168,'全唐诗/poet.song.111000.json','["溪石磊磊出，溪光失溶溶。", "呼童理新堰，小駐萬折東。", "素杙競駢立，蒼皮堆已重。", "誰裁一道天，忽墮顧視中。", "遠淥送鳬鶩，餘茲上杉松。", "微波且勿摇，照我澹有容。", "炎曦爲變色，爽氣排高空。", "懷哉所親愛，此適未遽同。", "徜徉孰爲伴，惟有溪頭風。", "時來翻素書，頗似驚我慵。", "騷騷復策策，涉獵味正濃。", "久而寂無聲，無乃意自融。", "却泛碧滄浪，鱗鱗散遺蹤。", "我亦隠几酣，那能辨雌雄。"]'),
('1deaf1d2-3666-4474-a300-68c197b1dabe','早飲','劉子翬','宋','宋诗','song-poetry','','[]','柴椽百枝蔭方塘，高梧老柳著兩行。',96,'全唐诗/poet.song.111000.json','["柴椽百枝蔭方塘，高梧老柳著兩行。", "輕烟曳組適寒碧，芙蕖釀出秋風香。", "宿酲縈胸殊未快，衝之欲引天潢派。", "戲投小餌向深淵，錦鱗忽見空中挂。", "篘清鱠雪更作豪，坐客狼狽已半逃。", "嗚嗚叢歌猶未徹，兀睡聽作蜩蟬號。"]'),
('0c294e30-85c9-4340-b5a7-3ffa4dcdec4c','次致明泉石軒詩韵','劉子翬','宋','宋诗','song-poetry','','[]','天懷迥與塵囂背，蓬萊屢踏金鼇背。',96,'全唐诗/poet.song.111000.json','["天懷迥與塵囂背，蓬萊屢踏金鼇背。", "閑披白袷過清湖，爽氣涵空渺無外。", "澹然愛此一泓奇，散髮逍遥潄華滋。", "尚嫌林影太凋薄，斜陽射破碧琉璃。", "遥知宣室虛前席，良裘固非一狐腋。", "他時歸夢想南飛，瓌詞已爲磨崖石。"]'),
('e90193e6-dc50-4937-9ca2-db2e4103fb7a','借致明玉槌事藥復以小者易去因而銘之','劉子翬','宋','宋诗','song-poetry','','[]','潤色瑳，癯身橢。',64,'全唐诗/poet.song.111000.json','["潤色瑳，癯身橢。", "飛石塵，供藥裹。", "以小代大無不可，汝雖眇乎寔磊砢。", "摩頂至踵輔衰我，彼方歸卧留莫果。", "魁梧之才用則左，㗲然長歎口侈哆。"]'),
('0702784c-7817-44b2-8827-c2b399b67c52','寄魏元履','劉子翬','宋','宋诗','song-poetry','','[]','世情事虛文，十幅了一書。',240,'全唐诗/poet.song.111000.json','["世情事虛文，十幅了一書。", "片言倒肺腑，子獨不佞予。", "班班眼中秀，學膽誰似渠。", "平生幾兩屩，踏破牛斗墟。", "小言謁侯門，大言叫天都。", "歸來闢存室，默坐追亡逋。", "床頭著韋編，盤礴萬古初。", "時拈紙上語，破的妙有餘。", "已甘酬對難，舌本噤不舒。", "矧予在半流，所見方模糊。", "蝸涎不自潤，詎敢相霑濡。", "人生强多知，於己固已疏。", "睫邊遺太極，意上町六虛。", "獰猿縶尚跳，况乃拊檻呼。", "是神非吾神，滓穢政可奴。", "嘗聞不遠復，佩作三字符。", "煌煌杏壇春，一枝明清湖。", "蜂蝶未全知，佳處自不孤。", "惟予先著眼，時來採芳腴。", "何當共叩微，歸性有順塗。"]'),
('c3327769-e7cf-4f73-90bc-72e496f28d3b','新凉','劉子翬','宋','宋诗','song-poetry','','[]','新凉爲招客，勝集非預圖。',168,'全唐诗/poet.song.111000.json','["新凉爲招客，勝集非預圖。", "前峰雨未散，泠風繞吾廬。", "披襟沐清駛，合席隨霑濡。", "定知喧譊中，欲此一快無。", "興來擴以酒，草具來須臾。", "田翁偶過我，添杯坐其偶。", "爲言秋暑劇，稻畦日凋疏。", "寧辭抱甕勞，僅給園中蔬。", "喜茲甘澍足，普潤無遺墟。", "遥山莽難分，綠浪摇虛徐。", "我病不任耕，歲收仰微租。", "蒙成每自愧，一飽便有餘。", "連觴使之釂，醉語雜叫呼。", "野人無他腸，我輩恐不如。"]'),
('f0eb26a3-8ada-456e-be1c-cd9066566855','吳傳朋遊絲帖歌','劉子翬','宋','宋诗','song-poetry','','[]','園清無瑕二三月，時見遊絲轉空闊。',192,'全唐诗/poet.song.111000.json','["園清無瑕二三月，時見遊絲轉空闊。", "誰人寫此一段奇，著紙春風吹不脫。", "紛紜糾結疑非書，安得龍蛇如許癯。", "神縱政喜縈不斷，老眼只愁看若無。", "定知苗裔出飛白，古人妙處君潛得。", "勿輕漠漠一縷浮，力道可採千鈞石。", "睠予弟兄情不忘，軸之遠寄悠然堂。", "謝公遺髯凜若活，衛后落鬒摇人光。", "翻思長安夜飛蓋，醉哦聲落南山外。", "亂離契闊三十秋，筆意與人俱老大。", "政成著脚明河津，外家風流今絕倫。", "文章固自有機杼，戲事豈足勞心神。"]'),
('d7723374-f7a8-4952-9234-b69b17885c53','次友石臺詩韵','劉子翬','宋','宋诗','song-poetry','','[]','清湖嵇玉山，縹緲飛雙屐。',216,'全唐诗/poet.song.111000.json','["清湖嵇玉山，縹緲飛雙屐。", "泠風隨處流，三伏無赫赫。", "未成玄圃遊，聊醉端州宅。", "憶昨陪初筵，杯摇劍峰脊。", "杉篁漏疏櫺，雲氣縈長帟。", "主人意彌厚，不吝園蔬摘。", "我亦洞幽懷，涸此一泓碧。", "至歡召融融，叢慮消剌剌。", "聽君誦九流，浩若崑崙擘。", "摩天俊鳶飛，響澗驚魚擲。", "分携今幾時，浮埃翳瑶席。", "有如爛柯翁，萬古逢一奕。", "醉鄉梯磴坐，坐覺乾坤窄。", "茲行不果從，兀兀恨滋劇。", "未應柳源近，終作桃源隔。", "留詩友石臺，光動嶙峋石。", "正令謫仙來，著語無以易。", "强吟意悠哉，追風了無迹。"]'),
('36322561-45eb-45f0-bf05-b2d980b7d3dc','胡明仲羅養蒙爲悠然集追用前四疊之韵','劉子翬','宋','宋诗','song-poetry','','[]','筠州喜陪笑語新，鑾坡自來清湖濱。',128,'全唐诗/poet.song.111000.json','["筠州喜陪笑語新，鑾坡自來清湖濱。", "更招明月作三客，此外正復難其人。", "瑶觴十飛才小醉，追逐牢愁出肝肺。", "吾儕邂逅非作豪，常恐真歡來不繼。", "更闌已番四疊歌，却喚輕舟浮綺羅。", "一聲橫笛不知處，荷氣苒苒風頭多。", "玉山未倒誰之耻，霜露霑衣聊且已。", "維舟落月界平潭，翠亂紅披扶不起。"]'),
('f2700464-9958-408c-92c6-6c4755f4891b','十七日集清湖','劉子翬','宋','宋诗','song-poetry','','[]','石堤蟠素虬，捍此百尺灣。',144,'全唐诗/poet.song.111000.json','["石堤蟠素虬，捍此百尺灣。", "臨灣喚客飲，四座摇潺湲。", "殘歊紅蕩析，凜若超塵寰。", "却愁凉吹多，奪我酣醉顔。", "時方雨聲斷，草木淒餘潸。", "潤氣騰晚水，浮嵐撲秋山。", "領略得妙趣，心遊勝躋攀。", "那知百年憂，共樂此日閑。", "篝燈夜分歸，危塍轉彎環。", "芊芊稻苗風，綠亂不可刪。", "不礙一月流，冰丸走其間。", "慇懃傍扶輿，宛若送我還。"]'),
('5b948023-54f3-4bd0-bed7-33e5b9a53155','曉起聞明仲謁家叔嘗過門追已無及繼讀觀霧長句因次原韵','劉子翬','宋','宋诗','song-poetry','','[]','公才凜若干將鑄，膽落詩流失輕倨。',320,'全唐诗/poet.song.111000.json','["公才凜若干將鑄，膽落詩流失輕倨。", "弄毫邂逅即揮奇，造化玄機悉披露。", "凌晨訪客忽飛筇，雙澗徐穿碧交互。", "笑聲只在竹林東，夢破急追無復處。", "是時秋霧正涵空，潤氣一解驕陽怒。", "霏霏半掩景賢峰，翳翳全沒屯中樹。", "初疑爭先摩玉壘，驚塵漠漠桑乾渡。", "又如懷渴望梅林，細雨濛濛江左路。", "煩公一吐胸中豪，與此氤氳角馳騖。", "可憐南山玄豹姿，終以班班作身誤。", "何如霧隠長暗然，豈用毛采誇夭嫮。", "霑濡稻壟更潸珠，聯絡松崗尚橫素。", "南箕忽哆遂雄吞，顧視怳若南柯寤。", "向來昧昧六合間，日月山河但如故。", "世緣所遇孰非虛，不具真眼那能覷。", "醯雞甕裏有全癡，陷虎機中惟一悟。", "我雖不獲從斯遊，兀坐深觀亦同趣。", "况知陶令有名酒，未覺許詢無勝具。", "便思追逐胡公墩，恐激長言又生怖。", "願低筆力許我陪，韓孟才懸亦聯句。"]'),
('24359c61-6851-47e9-a3a5-1c33248cbd4d','觀胡文定公手墨因求別本','劉子翬','宋','宋诗','song-poetry','','[]','溫溫文定公，至道夙所欽。',192,'全唐诗/poet.song.111000.json','["溫溫文定公，至道夙所欽。", "神超雖緬邈，餘英壯儒林。", "正容閲真翰，默默流至音。", "不事八法奇，天成寫幽襟。", "有如瀚海鴻，隨波自浮沉。", "又如太虛雲，舒卷杳莫尋。", "乃知晉魏還，筆端有哇淫。", "棄藁競韜藏，非將玩球琳。", "庶幾字畫間，可以求其心。", "清伊一派流，匯作萬丈深。", "溝渠有暴盈，淟涊時見侵。", "投膠了不難，公以獨力任。", "我慚步趨晚，悠然寄孤吟。", "流風在目前，著鞭要駸駸。", "願分墨本餘，刻之蒼崖陰。", "大塊有動摇，斯文無古今。"]'),
('bda359bb-752b-497d-ab2b-ff1c97c3b990','寒中偶書','劉子翬','宋','宋诗','song-poetry','','[]','寒從何處來，凜色照閩楚。',48,'全唐诗/poet.song.111000.json','["寒從何處來，凜色照閩楚。", "挹之霜松下，清澹不成雨。", "豪生小病之，一笑窺寰宇。", "天轉隠江湖，吾心正如許。"]'),
('50bc8be1-66a3-4e9b-9966-f984e49bc3cc','病中追賦遊武夷','劉子翬','宋','宋诗','song-poetry','','[]','建水日夜淺，清灘自迢迢。',108,'全唐诗/poet.song.111000.json','["建水日夜淺，清灘自迢迢。", "漁舠愕已無，忽點浄練遥。", "老身寄其上，兀若棲危苕。", "松風知我狂，隨舷助傾摇。", "探幽神益新，得快意自消。", "長林翠洞口，微雲粉山腰。", "那知碧虛遠，一葦卧可超。", "不須換吾骸，吾慵登岧嶢。", "病中追餘觀，所得絕富饒。"]'),
('845eff07-7826-4876-a97c-9a74081b2a8f','病中賞梅贈元晦老友','劉子翬','宋','宋诗','song-poetry','','[]','梅邊無與談，頼有之子至。',48,'全唐诗/poet.song.111000.json','["梅邊無與談，頼有之子至。", "荒寒一點香，足以酬天地。", "天地亦無心，受之自人意。", "韜白任新和，風味要如此。"]'),
('a7b9d2b1-2423-4eba-b32a-46d4a4ea4be7','次韵致明聽琴','劉子翬','宋','宋诗','song-poetry','','[]','病翁不咄咄，琅然寄枯琴。',48,'全唐诗/poet.song.111000.json','["病翁不咄咄，琅然寄枯琴。", "倘無枯琴寄，孰表吾之心。", "形忘豈知病，道在寧復今。", "龍蟠老樟下，觱發摇長音。"]'),
('4b4c793b-0a10-4640-8e67-f78351f75cd1','過鄴中','劉子翬','宋','宋诗','song-poetry','','[]','逐鹿營營一夢驚，事隨流水去無聲。',64,'全唐诗/poet.song.111000.json','["逐鹿營營一夢驚，事隨流水去無聲。", "黄沙日傍荒臺落，綠樹人穿廢苑行。", "遺恨分香憐晚節，勝遊飛蓋想高情。", "我來不暇論興廢，一點西山入眼明。"]'),
('a0214327-2d75-4b51-a0bd-76a8b93df7ea','金陵懷古','劉子翬','宋','宋诗','song-poetry','','[]','荒城莽莽蔽荆榛，虎踞龍蟠迹已陳。',64,'全唐诗/poet.song.111000.json','["荒城莽莽蔽荆榛，虎踞龍蟠迹已陳。", "赤壁戰爭江照晚，青樓歌舞鳥鳴春。", "十年王氣雄圖盡，一疊寒笳客恨新。", "折屐風流猶可想，只今高卧豈無人。"]'),
('371dcc71-c425-4b6d-998b-8007633aba5e','會兵','劉子翬','宋','宋诗','song-poetry','','[]','羽檄西來趣會兵，秋風胡虜更縱橫。',64,'全唐诗/poet.song.111000.json','["羽檄西來趣會兵，秋風胡虜更縱橫。", "烽明石嶺塞垣迥，馬渡分河波浪生。", "使者謾傳蘇武節，君王頻幸亞夫營。", "百年信誓明如日，何事紛紛起戰爭。"]'),
('8528665e-be83-4e7c-b46d-f719057b7105','別安子允','劉子翬','宋','宋诗','song-poetry','','[]','得酒猶堪慰倦遊，長亭直爲故人留。',64,'全唐诗/poet.song.111000.json','["得酒猶堪慰倦遊，長亭直爲故人留。", "煙塵幾處兵猶鬭，風雨一年春又休。", "尚記虎頭初擲筆，終憐猿臂未封侯。", "離歌唱落榆關月，可是君心耐得愁。"]'),
('3316a080-31ea-4a38-aa43-59615e939c47','望楚','劉子翬','宋','宋诗','song-poetry','','[]','客浦舟凝滯，憑高識楚鄉。',48,'全唐诗/poet.song.111000.json','["客浦舟凝滯，憑高識楚鄉。", "有愁關眺覽，何地不淒涼。", "草木詞人怨，江山霸主亡。", "悠然獨搔首，暮靄一星光。"]'),
('ca4e1686-8423-4f1e-85f0-1e9c0ea6d890','井泉','劉子翬','宋','宋诗','song-poetry','','[]','石井水濺濺，寒莎映碧蘚。',48,'全唐诗/poet.song.111000.json','["石井水濺濺，寒莎映碧蘚。", "雨聲添溜急，天影入波圓。", "曉汲連山寺，春耕潤野田。", "杖藜三嚥罷，毛髮更蕭然。"]'),
('e8ed72e2-3f3d-4dc8-a380-37fda57a43ba','巖桂','劉子翬','宋','宋诗','song-poetry','','[]','凉颸振遠村，寂寞度清芬。',48,'全唐诗/poet.song.111000.json','["凉颸振遠村，寂寞度清芬。", "山路不知處，月窗時夜聞。", "孤根寒抱石，落子半飄雲。", "袖手空延佇，無才可賦君。"]'),
('47a5548c-c830-425c-af09-7d62736a0937','園蔬十詠 茭白','劉子翬','宋','宋诗','song-poetry','','[]','秋風吹折碧，削玉如芳根。',24,'全唐诗/poet.song.111000.json','["秋風吹折碧，削玉如芳根。", "應傍鵝池發，中懷灑墨痕。"]'),
('e6587551-c3e3-4800-9495-21baed8360c0','園蔬十詠 芋','劉子翬','宋','宋诗','song-poetry','','[]','分得蹲鴟種，連根占地腴。',24,'全唐诗/poet.song.111000.json','["分得蹲鴟種，連根占地腴。", "曉吹黏玉糝，深碗啖模糊。"]'),
('c488c4eb-b3cb-437c-bfad-77ec494be795','園蔬十詠 韮','劉子翬','宋','宋诗','song-poetry','','[]','肉食嘲三九，終憐氣韵清。',24,'全唐诗/poet.song.111000.json','["肉食嘲三九，終憐氣韵清。", "一畦春雨足，翠髮翦還生。"]'),
('d3a1a6dd-61f6-4a4c-b50b-046d93e22c2b','園蔬十詠 瓠','劉子翬','宋','宋诗','song-poetry','','[]','溉釜熟輪囷，香清味仍美。',24,'全唐诗/poet.song.111000.json','["溉釜熟輪囷，香清味仍美。", "一線解瓊瑶，中有家人齒。"]'),
('906956da-d774-46d9-b85d-a6cf3c9cf0ce','園蔬十詠 芥','劉子翬','宋','宋诗','song-poetry','','[]','葉實抱芳辛，氣烈消煩滯。',24,'全唐诗/poet.song.111000.json','["葉實抱芳辛，氣烈消煩滯。", "登俎效微勞，乍食驚頻嚏。"]'),
('99fd7f13-497d-4a9c-a29b-30238fb85dcc','園蔬十詠 菘','劉子翬','宋','宋诗','song-poetry','','[]','周郎愛晚菘，對客蒙稱賞。',24,'全唐诗/poet.song.111000.json','["周郎愛晚菘，對客蒙稱賞。", "今晨喜薦新，小嚼冰霜響。"]'),
('81b6e8a3-4a79-4132-9836-5018fb359855','園蔬十詠 波薐','劉子翬','宋','宋诗','song-poetry','','[]','金鏃因形製，臨畦發永歎。',24,'全唐诗/poet.song.111000.json','["金鏃因形製，臨畦發永歎。", "時危思擷佩，楚客莫紉蘭。"]'),
('14746fda-94d3-41eb-91a9-f9223ae55d8e','園蔬十詠 子薑','劉子翬','宋','宋诗','song-poetry','','[]','新芽肌理膩，映日浄如空。',24,'全唐诗/poet.song.111000.json','["新芽肌理膩，映日浄如空。", "恰似勻妝指，柔尖带淺紅。"]'),
('00a74e45-c006-4033-8e5c-35c43811acbb','園蔬十詠 蘿蔔','劉子翬','宋','宋诗','song-poetry','','[]','密壤深根蒂，風霜已飽經。',24,'全唐诗/poet.song.111000.json','["密壤深根蒂，風霜已飽經。", "如何純白質，近蒂染微青。"]'),
('264cc7f9-8c66-47a3-9f79-e5580803fa0d','園蔬十詠 苦益','劉子翬','宋','宋诗','song-poetry','','[]','雖無適口味，暖益功稀比。',24,'全唐诗/poet.song.111000.json','["雖無適口味，暖益功稀比。", "菜苦不登盤，言中多逆耳。"]'),
('d390d604-f8a2-4b82-943f-ac2ccaa7336a','次韵盧贊元喜雪','劉子翬','宋','宋诗','song-poetry','','[]','六花初逐曉風繁，五袴那憂歲晚寒。',64,'全唐诗/poet.song.111000.json','["六花初逐曉風繁，五袴那憂歲晚寒。", "杖屨客迷村徑遠，笙歌人在小樓看。", "也知近郭梅將動，只恐行春路未乾。", "授簡梁園休惜醉，銀臺列燭妓圍寬。"]'),
('896a7035-b96e-49c2-8298-abb24fea8739','府會次士特韵','劉子翬','宋','宋诗','song-poetry','','[]','夜宴芙蓉苑，華榱燭影光。',48,'全唐诗/poet.song.111000.json','["夜宴芙蓉苑，華榱燭影光。", "史君頻會客，侍女慣新妝。", "劇飲不勝醉，論詩非所長。", "倚欄霄漢近，宮殿鬰相望。"]'),
('c4f1c930-98d9-4491-af26-a5aa3c47fbc5','次韵士特贈別','劉子翬','宋','宋诗','song-poetry','','[]','客舍愁分袂，梅花小雪前。',48,'全唐诗/poet.song.111000.json','["客舍愁分袂，梅花小雪前。", "夜看牛渚月，春別剡溪船。", "麗句光行色，悲歌慘別筵。", "後期相約處，雙闕五雲天。"]'),
('7a615fca-b808-407f-8e63-e09499ea93a3','訪士特舉和六四叔詩因次韵','劉子翬','宋','宋诗','song-poetry','','[]','聞道歸舟泊淺沙，籃輿出郭日初斜。',64,'全唐诗/poet.song.111000.json','["聞道歸舟泊淺沙，籃輿出郭日初斜。", "新傳賦詠來梁苑，舊識芝蘭向謝家。", "遣興只憑樽有酒，感時愁見樹飛花。", "相逢未款還相別，回首長亭鬢欲華。"]'),
('630ecb91-c601-44ac-96a1-36ead8dfaa96','分韵賦古松得青字','劉子翬','宋','宋诗','song-poetry','','[]','風韵颼飀遠更清，蒼髯瘦甲聳亭亭。',64,'全唐诗/poet.song.111000.json','["風韵颼飀遠更清，蒼髯瘦甲聳亭亭。", "連根欲鬭巖巒力，一蓋常涵雨露青。", "曾映月明留鶴宿，近經雷霹带龍腥。", "衰殘愧我無仙骨，願採流膏慰暮齡。"]'),
('ddd6942d-3f3d-406e-bfaf-76d18a4ea49b','六言二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','鼎食鼎烹謀拙，山南山北興長。',28,'全唐诗/poet.song.111000.json','["鼎食鼎烹謀拙，山南山北興長。", "片夢彭殤壽夭，一枰漢楚興亡。"]'),
('56e6f9e3-adb8-47d4-86d8-982bf1e0380c','六言二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','黄卷篋中昆友，白醪杯裏聖賢。',28,'全唐诗/poet.song.111000.json','["黄卷篋中昆友，白醪杯裏聖賢。", "我願長閑足矣，人憐獨處蕭然。"]'),
('3f2cdbe7-f4fd-45e6-aa36-a7fd04049377','池蓮四詠分韵 葉','劉子翬','宋','宋诗','song-poetry','','[]','鬰烈香浮雨，團欒綠蔭波。',24,'全唐诗/poet.song.111000.json','["鬰烈香浮雨，團欒綠蔭波。", "近堤千葉亂，知有畫船過。"]'),
('e78e39dd-0ac3-4efc-9778-cd4cc5274267','池蓮四詠分韵 花','劉子翬','宋','宋诗','song-poetry','','[]','孤紅低映岸，併艷遠連汀。',24,'全唐诗/poet.song.111000.json','["孤紅低映岸，併艷遠連汀。", "露浥層層展，風披葉葉零。"]'),
('bb534135-bd53-424c-a91d-6ea81ac63841','池蓮四詠分韵 藕','劉子翬','宋','宋诗','song-poetry','','[]','密藴羅文細，明含玉色清。',24,'全唐诗/poet.song.111000.json','["密藴羅文細，明含玉色清。", "冰盤時薦美，刀惹斷絲輕。"]'),
('d54cca19-e6b4-4ab8-92d7-9b348651d280','池蓮四詠分韵 子','劉子翬','宋','宋诗','song-poetry','','[]','分房圓戢戢，弄色翠娟娟。',24,'全唐诗/poet.song.111000.json','["分房圓戢戢，弄色翠娟娟。", "摘實憐空菂，方知雨露偏。"]'),
('83b2d0a7-a7ed-4146-bfdf-2a592feef9af','雨歇','劉子翬','宋','宋诗','song-poetry','','[]','雨歇長虹淡欲收，疏疏寒靄暮依樓。',32,'全唐诗/poet.song.111000.json','["雨歇長虹淡欲收，疏疏寒靄暮依樓。", "西風滿院催摇落，已覺梧桐不耐秋。"]'),
('2b47ad1f-2132-434f-a9ad-cdf7eea2b9c4','新灣','劉子翬','宋','宋诗','song-poetry','','[]','苒苒寒生水面煙，吳歌唱罷月微偏。',32,'全唐诗/poet.song.111000.json','["苒苒寒生水面煙，吳歌唱罷月微偏。", "停橈又向灣前宿，一夜西風浪打船。"]'),
('a38476c7-2219-488f-a793-3070a26c2b04','汴堤','劉子翬','宋','宋诗','song-poetry','','[]','參差歌吹動離舟，宮女張帆信浪流。',32,'全唐诗/poet.song.111000.json','["參差歌吹動離舟，宮女張帆信浪流。", "轉盡柳堤三百曲，夜橋燈火看揚州。"]'),
('c4285062-fae9-438f-a57e-e54d04097eba','天迥','劉子翬','宋','宋诗','song-poetry','','[]','天迥孤帆隠約歸，茫茫殘照欲沉西。',32,'全唐诗/poet.song.111000.json','["天迥孤帆隠約歸，茫茫殘照欲沉西。", "寒鴉散亂知多少，飛向江頭一樹棲。"]'),
('6fc186e3-64e8-4ed3-a75e-836d969c7353','葉集之舉士特唱和因次韵','劉子翬','宋','宋诗','song-poetry','','[]','漂泊分携後，囏難會面時。',48,'全唐诗/poet.song.111000.json','["漂泊分携後，囏難會面時。", "夜燈初獻酒，春草舊題詩。", "遊宦君雖厭，才名衆所期。", "不應如倦翼，寂寞戀南枝。"]'),
('3dbbea68-3356-423f-aeb2-88516f5a68bb','銅爵','劉子翬','宋','宋诗','song-poetry','','[]','金碧銷磨瓦面星，亂山依舊繞宮城。',32,'全唐诗/poet.song.111000.json','["金碧銷磨瓦面星，亂山依舊繞宮城。", "路人休唱高臺曲，臺上而今春草生。"]'),
('a0eda641-788a-48b3-84b9-aa8ed67d8f2b','中渡','劉子翬','宋','宋诗','song-poetry','','[]','渡南渡北是長亭，沙上行人立馬情。',32,'全唐诗/poet.song.111000.json','["渡南渡北是長亭，沙上行人立馬情。", "回首若無煙樹隔，只應猶望見高城。"]'),
('8c42cec9-9c5c-4548-9f3b-d0cfeee2762f','江上','劉子翬','宋','宋诗','song-poetry','','[]','江上潮來浪薄天，隔江寒樹晚生煙。',32,'全唐诗/poet.song.111000.json','["江上潮來浪薄天，隔江寒樹晚生煙。", "北風三日無人渡，寂寞沙頭一簇船。"]'),
('1e4333f1-ef50-47fa-b310-64a57f4f552d','送曾彥思減罷赴闕','劉子翬','宋','宋诗','song-poetry','','[]','馬首成南渡，西風木葉疏。',48,'全唐诗/poet.song.111000.json','["馬首成南渡，西風木葉疏。", "去程煙雨外，孤館別離初。", "未試平戎策，空懷逐客書。", "漢皇方問賦，誰復薦相如。"]'),
('0db01094-52df-4869-8c05-b12289730713','過楚懷王廟','劉子翬','宋','宋诗','song-poetry','','[]','割據銷殘運，并吞息戰塵。',240,'全唐诗/poet.song.111000.json','["割據銷殘運，并吞息戰塵。", "遺民猶憫楚，三戶欲亡秦。", "念昔懷王立，潛圖霸業新。", "降顔欣接士，薄伐屢窺鄰。", "慷慨心何壯，囏難勢未伸。", "干戈憐暴骨，玉帛更和親。", "末路人多詐，輕謀禍及身。", "單車行凜慄，伏甲變逡巡。", "鹿走章臺下，龍沉渭水濱。", "素棺歸慘淡，故老恨酸辛。", "歲月今何在，興亡迹已陳。", "愁陰生古廟，翠蔓鎖重闉。", "有客投清酹，臨江憶放臣。", "聽讒雖主惑，多難亦時屯。", "憤氣摩星斗，哀詞動鬼神。", "飄零瓊玉佩，寂寞蕙蘭春。", "毀譽千年定，窮通一死均。", "招魂嗟已矣，抱石想漂淪。", "戀戀空回首，行行欲問津。", "潸然憂國淚，今古獨醒人。"]'),
('78642181-23f0-476e-8c33-bfeec7ab9f26','雙廟','劉子翬','宋','宋诗','song-poetry','','[]','無復連雲戰鼓悲，英風凜凜在雙祠。',64,'全唐诗/poet.song.111000.json','["無復連雲戰鼓悲，英風凜凜在雙祠。", "氣吞驕虜方張日，恨滿孤城欲破時。", "幽鳥自啼簷際樹，夕陽空照路傍碑。", "平生不作脂韋意，倚棹哀吟兩鬢絲。"]'),
('1fc4c91a-6ba4-434a-bf8f-1b4e074336b2','一樹','劉子翬','宋','宋诗','song-poetry','','[]','一樹梅開早，清香襲客衣。',24,'全唐诗/poet.song.111000.json','["一樹梅開早，清香襲客衣。", "夕陽簫鼓散，半是折殘枝。"]'),
('b7898042-ca50-43ef-af52-9bb61666e99d','偶步','劉子翬','宋','宋诗','song-poetry','','[]','偶步忘歸遠，心閑逸興增。',24,'全唐诗/poet.song.111000.json','["偶步忘歸遠，心閑逸興增。", "山深知有寺，路盡不逢僧。"]'),
('51561661-1041-4727-9475-13672126febb','離居','劉子翬','宋','宋诗','song-poetry','','[]','馬嘶何隴暮，有意念離居。',48,'全唐诗/poet.song.111000.json','["馬嘶何隴暮，有意念離居。", "去路經秋雨，行裝一擔書。", "窮知身計拙，病覺世緣疏。", "曉枕殘歸夢，翻然憶舊廬。"]'),
('00fa8bd1-cf13-4eed-85b2-19214b4d486a','有感','劉子翬','宋','宋诗','song-poetry','','[]','抱石親征澤潞時，艱難猶想舊開基。',32,'全唐诗/poet.song.111000.json','["抱石親征澤潞時，艱難猶想舊開基。", "官軍不守河陽渡，回首橋山淚欲垂。"]'),
('4fadf3f7-1612-42bc-80a4-be00b4e5ab3d','程嬰墓','劉子翬','宋','宋诗','song-poetry','','[]','停車莽蒼認孤墳，烈烈英標尚想存。',64,'全唐诗/poet.song.111000.json','["停車莽蒼認孤墳，烈烈英標尚想存。", "已脫遺孤安趙氏，更輕一死報公孫。", "荒林雀噪風常急，古道人稀日自昏。", "惆悵九原如可作，欲憑楚些爲招魂。"]'),
('bb5d19bc-e06b-4a19-a397-a4bd82b1ae60','晚宿','劉子翬','宋','宋诗','song-poetry','','[]','石瀨分流小，霜林間樹紅。',24,'全唐诗/poet.song.111000.json','["石瀨分流小，霜林間樹紅。", "暮橋橫隠約，寒鍛響丁東。"]'),
('017bfc1c-8a6c-4a89-9760-c7a611c37ce2','畫船','劉子翬','宋','宋诗','song-poetry','','[]','隠約菱歌斷，斜陽水面移。',24,'全唐诗/poet.song.111000.json','["隠約菱歌斷，斜陽水面移。", "美人貪照影，不覺畫船欹。"]'),
('fe6cd5b2-f940-450a-b07d-5bb8212f7208','宮亭湖','劉子翬','宋','宋诗','song-poetry','','[]','近湖黯黯氣常寒，指點宮亭渺莽間。',64,'全唐诗/poet.song.111000.json','["近湖黯黯氣常寒，指點宮亭渺莽間。", "素色夜浮全楚月，綠光春浸十州山。", "醉思天末騎鯨去，老怯風頭聽雁還。", "柔櫓聲中知禹烈，愧無椽筆畫孱顔。"]'),
('76cb1ceb-95a8-452d-9b59-da2454edc9b2','安仁道中','劉子翬','宋','宋诗','song-poetry','','[]','汩汩復汩汩，著鞭雞一號。',48,'全唐诗/poet.song.111000.json','["汩汩復汩汩，著鞭雞一號。", "老身緣底急，長路只徒勞。", "石亂春谿惡，山深曉月高。", "村沽得微醉，猶足張餘豪。"]'),
('81d30c30-0660-400b-9348-f3f89ba886c6','酴醿','劉子翬','宋','宋诗','song-poetry','','[]','顛風急雨退花晨，翠葉銀苞照眼新。',64,'全唐诗/poet.song.111000.json','["顛風急雨退花晨，翠葉銀苞照眼新。", "高架攀緣雖得地，長條盤屈總由人。", "橫釵素朵開猶小，撲酒餘香韵絕倫。", "唯有金沙顔色好，年年相伴殿殘春。"]'),
('1421fb34-b52e-4cae-8584-c5d9d03def63','夜坐','劉子翬','宋','宋诗','song-poetry','','[]','客裏驚秋晚，慵眠但曲肱。',48,'全唐诗/poet.song.111000.json','["客裏驚秋晚，慵眠但曲肱。", "夜闌深院雨，人過隔牆燈。", "遠思千端惡，寒威一倍增。", "夢孤渾易破，哀柝故登登。"]'),
('2eae9e59-99eb-4019-95c7-3e01e1d54249','靖康改元四十韵','劉子翬','宋','宋诗','song-poetry','','[]','肉食開邊釁，天驕負漢恩。',288,'全唐诗/poet.song.111000.json','["肉食開邊釁，天驕負漢恩。", "陰謀招叛將，喋血犯中原。", "飲馬江河竭，鳴笳宇宙喧。", "氛埃纏帝座，猰貐吠宮垣。", "鼓銳梯飛壁，彎强矢及門。", "黔黎驚瓦解，冠蓋盡星奔。", "走轍秦城地，浮航楚峽村。", "畫堂空鎖鑰，樂府散嬋媛。", "夜詔聞傳璽，春王記改元。", "三辰光盡匿，四海浪橫翻。", "伏閣惟羣彥，興邦在一言。", "雉城期必守，虎旅更增屯。", "龍困雖憂蟻，牛羸尚覆豚。", "謀成擒頡利，義可絕烏孫。", "堅壁師彌老，窮兵火自燔。", "鈎魚猶假息，幕燕暫游魂。", "懇款情先露，誅鉏黨實繁。", "橫磨非嗜殺，下策且和番。", "割地煩專使，要盟脅至尊。", "賜弓垂拱殿，留宴玉津園。", "回騎桑乾北，游軍廣武原。", "驅馳無立草，剖斲露空墳。", "太子悲秦粟，明妃泣漢軒。", "敵情終未測，鄰好久宜敦。"]'),
('7f21f330-c876-43ca-bab9-e7638b423291','春雨','劉子翬','宋','宋诗','song-poetry','','[]','暝色春朝雨，滋榮喜及時。',48,'全唐诗/poet.song.111000.json','["暝色春朝雨，滋榮喜及時。", "雲昏遥莫辨，地渴久方知。", "柳岸遊車歇，濤江釣舸移。", "拒寒須把酒，病骨况支離。"]'),
('330d5318-ed0c-46d1-a42d-b5b7b7cf2d83','瀑布','劉子翬','宋','宋诗','song-poetry','','[]','路窮巖瀑挂，爽氣浄塵紛。',48,'全唐诗/poet.song.111000.json','["路窮巖瀑挂，爽氣浄塵紛。", "溜險時依壁，源高半隔雲。", "入池驚練盡，觸石聽雷分。", "接勝多幽侶，筇聲破蘚紋。"]'),
('3ac99695-09d4-4b98-aadb-44f44543341b','海棠花','劉子翬','宋','宋诗','song-poetry','','[]','幽姿淑態弄春晴，梅借風流柳借輕。',64,'全唐诗/poet.song.111000.json','["幽姿淑態弄春晴，梅借風流柳借輕。", "初種直教圍野水，半開長是近清明。", "幾經夜雨香猶在，染盡烟脂畫不成。", "詩老無心爲題拂，至今惆悵似含情。"]'),
('639ba7ae-aaa3-440f-b997-f14f7258ac32','策杖','劉子翬','宋','宋诗','song-poetry','','[]','策杖農家去，蕭條絕四鄰。',48,'全唐诗/poet.song.111000.json','["策杖農家去，蕭條絕四鄰。", "空田依壠峻，斷藁布窠勻。", "地薄惟供稅，年豐尚苦貧。", "平生飽官粟，愧爾力耕人。"]'),
('8c98e93a-98ff-46ad-8262-6ee42b72b80d','送杜季習四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','結廬空谷抱沉憂，底事軒車肯爲留。',32,'全唐诗/poet.song.111000.json','["結廬空谷抱沉憂，底事軒車肯爲留。", "千里問塗良獨苦，似君須向古人求。"]'),
('5c8979d7-63f3-4e84-8bcd-fea25312c55e','送杜季習四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','聞道華亭已解圍，親朋消息未全知。',32,'全唐诗/poet.song.111000.json','["聞道華亭已解圍，親朋消息未全知。", "君歸爲遣書來報，細說從初喪亂時。"]'),
('b4250331-d992-4657-bede-88876eb1a9c9','送杜季習四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','寂寂家園草覆階，亂兵飛箭入樓臺。',32,'全唐诗/poet.song.111000.json','["寂寂家園草覆階，亂兵飛箭入樓臺。", "丁寧莫斫湖邊柳，盡是劉郎手自栽。"]'),
('299c756d-8148-4364-821c-7981a735e4d9','送杜季習四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','摇落難堪更語離，曉風吹月上征衣。',32,'全唐诗/poet.song.111000.json','["摇落難堪更語離，曉風吹月上征衣。", "送君直到長亭去，隻影愁尋舊路歸。"]'),
('4d30e67b-841b-4d79-a5d3-dc62c278d429','劉處士墳山禮亭','劉子翬','宋','宋诗','song-poetry','','[]','風馬雲車悵莫尋，祠亭空鎖古原陰。',64,'全唐诗/poet.song.111000.json','["風馬雲車悵莫尋，祠亭空鎖古原陰。", "豆觴三獻禮經事，霜露四時人子心。", "世盡浮雲同渺渺，名高拱木共森森。", "平生積善身徒老，頼有家兒敵萬金。"]'),
('8cc8086e-b3ca-4a8a-b012-eab6cc54d3f4','喜誅大將','劉子翬','宋','宋诗','song-poetry','','[]','自提烏合衆，南北久跳梁。',48,'全唐诗/poet.song.111000.json','["自提烏合衆，南北久跳梁。", "避事幾危國，專權擬僭王。", "然臍誅未快，擢髮罪難詳。", "膏血汙砧斧，何曾灑戰場。"]'),
('8f9552f1-3e6c-4e5a-91b9-c22733c6e4ce','疊嶂','劉子翬','宋','宋诗','song-poetry','','[]','益遣歸心快，愁霖喜乍晴。',48,'全唐诗/poet.song.111000.json','["益遣歸心快，愁霖喜乍晴。", "樹陰迎馬合，波影照人清。", "不見雲山路，時聞樵斧聲。", "暮雲偏有意，相伴隔溪行。"]'),
('a640667b-6a36-492d-815b-1820930ef618','梅花','劉子翬','宋','宋诗','song-poetry','','[]','玉骨綃裳韵太孤，天教飛雪伴清癯。',64,'全唐诗/poet.song.111000.json','["玉骨綃裳韵太孤，天教飛雪伴清癯。", "林寒疏蕊半開落，野迥暗香疑有無。", "庾嶺風光仍似舊，漢宮鉛粉莫相汙。", "驚心不必臨空樹，一白流空春便徂。"]'),
('db36b707-3613-4b4c-b2f1-4c813ce33743','和李巽伯','劉子翬','宋','宋诗','song-poetry','','[]','浦樹冥茫茫，雲山淺淡中。',48,'全唐诗/poet.song.111000.json','["浦樹冥茫茫，雲山淺淡中。", "客愁生遠望，春意入晴空。", "酒憶相如病，途憐阮籍窮。", "慇懃桃葉句，欲和愧難工。"]'),
('7f79e599-5aba-4143-9d62-bf9776bbcf9e','野步','劉子翬','宋','宋诗','song-poetry','','[]','野步忘歸遠，春心不自休。',48,'全唐诗/poet.song.111000.json','["野步忘歸遠，春心不自休。", "管弦非老伴，風雨定花讎。", "柳暗深深路，溪寒小小樓。", "謝娘歌白紵，此意可忘憂。"]'),
('4bc0abd6-8ba7-43e0-b6fb-73672ca9bf73','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 王猛捫蝨','劉子翬','宋','宋诗','song-poetry','','[]','劇談世事灞河濱，奇骨瓌姿兩絕倫。',32,'全唐诗/poet.song.111000.json','["劇談世事灞河濱，奇骨瓌姿兩絕倫。", "却訝秦無豪傑至，坐中捫蝨定何人。"]'),
('7cf9290e-1bb6-4946-bdda-b09bc2155447','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 高陽長揖','劉子翬','宋','宋诗','song-poetry','','[]','胡床二女執巾裾，長揖高陽舊酒徒。',32,'全唐诗/poet.song.111000.json','["胡床二女執巾裾，長揖高陽舊酒徒。", "不是蒼皇能輟洗，溺冠何異昔坑儒。"]'),
('72f14d46-b0b5-47e2-ba41-d717f77c258a','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 霍光取璽','劉子翬','宋','宋诗','song-poetry','','[]','此郎守節固堪論，漢璽飄飄亦僅存。',32,'全唐诗/poet.song.111000.json','["此郎守節固堪論，漢璽飄飄亦僅存。", "周勃取將迎代邸，霍光持去授皇孫。"]'),
('f6123048-7711-44ae-953c-e9d2ae26c430','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 馮媛當熊','劉子翬','宋','宋诗','song-poetry','','[]','婕妤下輦辭榮日，馮媛當熊效死時。',32,'全唐诗/poet.song.111000.json','["婕妤下輦辭榮日，馮媛當熊效死時。", "带礪稱忠惟一傳，宮闈著節有雙姬。"]'),
('590e21e3-4b0d-4368-b6e7-abc879c55c47','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 李密迓太宗','劉子翬','宋','宋诗','song-poetry','','[]','海內羣雄逐鹿時，虬髯一見識英姿。',32,'全唐诗/poet.song.111000.json','["海內羣雄逐鹿時，虬髯一見識英姿。", "牖窺已歎尚書婦，野拜仍驚柱國兒。"]'),
('f31b7aa6-9859-4078-bf66-0efa097dee45','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 明妃出塞','劉子翬','宋','宋诗','song-poetry','','[]','羞貌丹青鬭麗顔，爲君一笑靜天山。',32,'全唐诗/poet.song.111000.json','["羞貌丹青鬭麗顔，爲君一笑靜天山。", "西京自有麒麟閣，畫向功臣衛霍間。"]'),
('6d6276ec-3ba2-4194-8e11-9ae3415bf69a','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 張釋之諫文帝','劉子翬','宋','宋诗','song-poetry','','[]','擾擾椎埋遍九原，因山獨有霍陵存。',32,'全唐诗/poet.song.111000.json','["擾擾椎埋遍九原，因山獨有霍陵存。", "孝文儉德雖天縱，亦頼忠臣效一言。"]'),
('6e7ebfd8-9b5c-416a-97af-85752f716ba9','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 醉山簡','劉子翬','宋','宋诗','song-poetry','','[]','倒載山公豈酒狂，羣兒拍手峴山旁。',32,'全唐诗/poet.song.111000.json','["倒載山公豈酒狂，羣兒拍手峴山旁。", "汗青等是虛填耳，不把雲臺喚酒鄉。"]'),
('bfa6c4a1-6879-4645-bbc9-fb08cd218643','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 武帝問日磾','劉子翬','宋','宋诗','song-poetry','','[]','漢朝人物盡英奇，武帝招延盛一時。',32,'全唐诗/poet.song.111000.json','["漢朝人物盡英奇，武帝招延盛一時。", "拒諫不能容汲直，託孤何至用胡兒。"]'),
('d17a3190-29c1-4519-9fc2-a95a5acf4f18','李伯時畫十古圖鄭尚明作詩詩辭多振絕因爲同賦 明皇覽鏡妃子翦鬟','劉子翬','宋','宋诗','song-poetry','','[]','不復青銅照瘁顔，耄荒從諫若移山。',32,'全唐诗/poet.song.111000.json','["不復青銅照瘁顔，耄荒從諫若移山。", "只將女子論賢否，陶母當時亦翦鬟。"]'),
('c1577424-224b-43d3-9190-890c3684b365','送原仲之荆南','劉子翬','宋','宋诗','song-poetry','','[]','風急塵埃滿漢關，送君行處路漫漫。',64,'全唐诗/poet.song.111000.json','["風急塵埃滿漢關，送君行處路漫漫。", "不知爭戰幾時定，常恐別離相見難。", "三徑舊遊松竹老，五湖新隠水雲寬。", "交朋日覺知音少，綠綺從今莫浪彈。"]'),
('70681145-d828-4ded-9963-af20b458b9fe','和士特南浦詩','劉子翬','宋','宋诗','song-poetry','','[]','羽檄分兵控上流，時傳烽火過鄰州。',64,'全唐诗/poet.song.111000.json','["羽檄分兵控上流，時傳烽火過鄰州。", "樓船半渡旌旗曉，胡馬欲來江漢秋。", "淝水投鞭真浪語，幄中借箸有奇謀。", "吾儒雅有康時意，不把詩輕萬戶侯。"]'),
('84e52ade-6f87-4717-90d4-ce68d977e74c','景陽鐘二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','景陽鐘動曉寒清，度柳穿花隠隠聲。',32,'全唐诗/poet.song.111000.json','["景陽鐘動曉寒清，度柳穿花隠隠聲。", "三十六宮梳洗罷，却吹殘燭待天明。"]'),
('fd24e005-df96-4920-a117-51854bfcccfd','景陽鐘二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','一刀殘月淡觚稜，遥望林梢曉色升。',32,'全唐诗/poet.song.111000.json','["一刀殘月淡觚稜，遥望林梢曉色升。", "寂寞小簾風露冷，玉盆脂水已生冰。"]'),
('0b89bf75-8136-4386-9dbc-a188def0efaf','春夜二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','葉葉風鳴幕，梢梢雨打窗。',24,'全唐诗/poet.song.111000.json','["葉葉風鳴幕，梢梢雨打窗。", "烟銷寒寶鴨，膏淺側銀缸。"]'),
('48963ef9-70ce-481c-ba55-2805a1084f65','春夜二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','樓迥星河轉，宵殘鼓角催。',24,'全唐诗/poet.song.111000.json','["樓迥星河轉，宵殘鼓角催。", "重門和月鎖，寒夢繞花回。"]'),
('7a9c92db-e192-4e09-9e95-563a175ff789','賦雙溪閣用蔡君謨詩聲字韵','劉子翬','宋','宋诗','song-poetry','','[]','雄觀今古快幽情，突兀層樓出市甍。',64,'全唐诗/poet.song.111000.json','["雄觀今古快幽情，突兀層樓出市甍。", "二水交流何處盡，孤舟不見亂山橫。", "丹爐寂寞仙遊遠，劍氣蕭條客恨盈。", "向晚移樽話流落，可堪時聽鼓鼙聲。"]'),
('19890dcb-adc1-4413-a3b8-fb6ad82ffa6c','泊舟','劉子翬','宋','宋诗','song-poetry','','[]','莽莽荒茨岸，回回亂石灘。',48,'全唐诗/poet.song.111000.json','["莽莽荒茨岸，回回亂石灘。", "雨寒收市早，風急泊舟難。", "㝢縣兵猶鬭，乾坤網正寬。", "慇懃囑龍劍，莫久卧波瀾。"]'),
('82506f61-609e-4549-8e5d-d892c1c1503f','劍潭贈李似表','劉子翬','宋','宋诗','song-poetry','','[]','夜窗把酒對鵝峰，分手悠悠各轉蓬。',64,'全唐诗/poet.song.111000.json','["夜窗把酒對鵝峰，分手悠悠各轉蓬。", "艤棹相逢烟浪際，有家皆在亂離中。", "胡兒久占清河地，壯士誰收赤壁功。", "它日著鞭先後耳，飄零不用歎途窮。"]'),
('f979e510-f6e6-4ead-8696-16e21a2e6453','舟中寄似表','劉子翬','宋','宋诗','song-poetry','','[]','溪流元自急，積雨更兼旬。',48,'全唐诗/poet.song.111000.json','["溪流元自急，積雨更兼旬。", "曲渚方移棹，高城忽背人。", "艱難爭避地，去住不由身。", "客食憐詩李，相期一問津。"]'),
('6f985ba8-017e-407e-88b4-0b6aa6bdf5d9','次韵張守同往華嚴','劉子翬','宋','宋诗','song-poetry','','[]','淺水荷花開傍橋，晚鐘樓殿碧山椒。',64,'全唐诗/poet.song.111000.json','["淺水荷花開傍橋，晚鐘樓殿碧山椒。", "林松繞路行不徹，野鳥避人飛更遥。", "喜有高情共丘壑，應須長嘯混漁樵。", "老僧好事能延客，未覺山房苦寂寥。"]'),
('7aceb6c2-cac7-4585-99ee-40524a929698','出郭詩呈張守','劉子翬','宋','宋诗','song-poetry','','[]','出郭籃輿載酒隨，林邊蕭寺趁幽期。',64,'全唐诗/poet.song.111000.json','["出郭籃輿載酒隨，林邊蕭寺趁幽期。", "雲依石度遥看久，路繞田分欲去疑。", "落日悲風滄海外，黄化翠竹晚秋時。", "憑詩一寫登臨勝，爲報壺山太守知。"]'),
('0b4694dd-8cc6-4f2d-bbac-05f4dcf67274','次韵張守壺山詩','劉子翬','宋','宋诗','song-poetry','','[]','松根繫馬望巑岏，乘興攀躋不作難。',64,'全唐诗/poet.song.111000.json','["松根繫馬望巑岏，乘興攀躋不作難。", "日出漸看林霧散，潮來先覺海風寒。", "遥連釣石多紅樹，半出僧垣盡綠竿。", "不見雙旌來視稼，憶君對酒豈能歡。"]'),
('d606d42e-ea28-4121-b132-37616d15c7ad','次韵方學士萬卷樓','劉子翬','宋','宋诗','song-poetry','','[]','淵然推量德爲循，酷愛收書定可人。',64,'全唐诗/poet.song.111000.json','["淵然推量德爲循，酷愛收書定可人。", "劉向討論稱好古，退之學問美藏身。", "箕裘有子能傳業，俎豆於今歎不辰。", "我亦平生譏傳癖，可憐朱墨費精神。"]'),
('c48c1f72-8698-429e-b24a-3e77bd457b1f','次韵吳教授題子應山齋','劉子翬','宋','宋诗','song-poetry','','[]','芒鞋竹杖日隨身，所向逍遥樂任真。',64,'全唐诗/poet.song.111000.json','["芒鞋竹杖日隨身，所向逍遥樂任真。", "强健挂冠非矯俗，榮華得路轉迷人。", "愛山兀兀常心醉，與世悠悠只貌親。", "最晚論交欣得子，一樽猶足慰漂淪。"]'),
('e276d2bc-60ba-4507-8ab0-6dbb70752f9f','張守唱和紅字韵詩八首  其一','劉子翬','宋','宋诗','song-poetry','','[]','午枕回清夢，疎林逗遠風。',48,'全唐诗/poet.song.111000.json','["午枕回清夢，疎林逗遠風。", "茶甌烹葉白，果飣剝方紅。", "小壘常稀訟，鄰邦近息戎。", "民謠知善政，佽助亦何功。"]'),
('8025d4c5-99c8-4ad0-be88-181a0bf16085','張守唱和紅字韵詩八首  其二','劉子翬','宋','宋诗','song-poetry','','[]','一巵那惜醉，引劍坐生風。',48,'全唐诗/poet.song.111000.json','["一巵那惜醉，引劍坐生風。", "怒髮冠衝綠，憂顔鏡損紅。", "莫輕秦黷武，舊耻漢和戎。", "慷慨今賢守，燕然擬勒功。"]'),
('774e3a69-8a1d-4b84-b932-332df49b7908','張守唱和紅字韵詩八首  其三','劉子翬','宋','宋诗','song-poetry','','[]','漂流今海角，胡騎忽秋風。',48,'全唐诗/poet.song.111000.json','["漂流今海角，胡騎忽秋風。", "舊隠懷空翠，征途厭軟紅。", "時平猶倦仕，力小况從戎。", "欲遣愁城破，須論酒子功。"]'),
('04ff04ff-b03d-45f5-bbd3-b23d9102db52','張守唱和紅字韵詩八首  其四','劉子翬','宋','宋诗','song-poetry','','[]','燦爛燕公筆，飄然邁祖風。',48,'全唐诗/poet.song.111000.json','["燦爛燕公筆，飄然邁祖風。", "高吟時舉白，戲語或題紅。", "訝敏文翻水，誇嚴律比戎。", "詩壇如第將，蘇李謝前功。"]'),
('5f9fb336-0de8-437f-bad3-8daf5671de34','張守唱和紅字韵詩八首  其五','劉子翬','宋','宋诗','song-poetry','','[]','海市從蕭索，杯盤樂土風。',48,'全唐诗/poet.song.111000.json','["海市從蕭索，杯盤樂土風。", "郡樓山向背，村塢樹青紅。", "玉麈嗤夷甫，牙籌陋阿戎。", "王侯真夢耳，穴蟻更論功。"]'),
('7183beea-1e64-4e4a-9adf-3889733a354e','張守唱和紅字韵詩八首  其六','劉子翬','宋','宋诗','song-poetry','','[]','微吟時擁鼻，瀟灑晉人風。',48,'全唐诗/poet.song.111000.json','["微吟時擁鼻，瀟灑晉人風。", "客至添樽綠，官閑省印紅。", "易徂嗟歲月，迭盛歎華戎。", "願草浯溪頌，中興旦暮功。"]'),
('074c3e8c-9a5c-498b-b333-9c62dac00f0d','張守唱和紅字韵詩八首  其七','劉子翬','宋','宋诗','song-poetry','','[]','斷虹明晚井，烟靄半隨風。',48,'全唐诗/poet.song.111000.json','["斷虹明晚井，烟靄半隨風。", "岸柳霜收綠，庭榴日貸紅。", "酒酣腸有海，棋戰手興戎。", "賡唱逢勍敵，方知比興功。"]'),
('b4a3bec0-d686-4c82-86f7-e238d2450543','張守唱和紅字韵詩八首  其八','劉子翬','宋','宋诗','song-poetry','','[]','濟難資長策，常懷國士風。',48,'全唐诗/poet.song.111000.json','["濟難資長策，常懷國士風。", "秦强因將白，魯弱更蒐紅。", "歎己懷孤憤，憂時詠小戎。", "儒冠須勿溺，邂逅亦成功。"]'),
('bbeb511a-ef14-4762-8d96-21d1aaa1cc7a','次韵張守述懷','劉子翬','宋','宋诗','song-poetry','','[]','避地漂流更海隅，一身難料豈知餘。',64,'全唐诗/poet.song.111000.json','["避地漂流更海隅，一身難料豈知餘。", "晚樓獨上非吾里，幾日西來絕羽書。", "虜未息兵由運數，力難康世昧孤虛。", "郡侯愷悌憂民切，魯史無因諷失魚。"]'),
('a59021b4-08d3-4ee3-8e68-3d9f644cf44d','同張守謁蔡子强觀硯論琴偶書','劉子翬','宋','宋诗','song-poetry','','[]','共造中郎室，明窗玩好奇。',48,'全唐诗/poet.song.111000.json','["共造中郎室，明窗玩好奇。", "硯珍鎸子石，琴古斲孫枝。", "篆鼎飄香遠，茶甌轉味遲。", "自慚塵土累，清話得移時。"]'),
('13170425-526c-4168-8ccf-babe4d89e8ae','次韵林吉甫遊天宮','劉子翬','宋','宋诗','song-poetry','','[]','聞說星郎隠翠峰，鵷鸞回首大明宮。',64,'全唐诗/poet.song.111000.json','["聞說星郎隠翠峰，鵷鸞回首大明宮。", "倦遊壯歲拋朝紱，歸夢清江憶釣筒。", "賢聖相期黄卷裏，是非都付濁醪中。", "更聞蓮社多幽侶，我欲時來問苦空。"]'),
('d2485a0f-c767-456f-8702-7e21127e2934','莫田','劉子翬','宋','宋诗','song-poetry','','[]','打麥蓬蓬響莫田，兒童拾穟笑爭先。',32,'全唐诗/poet.song.111000.json','["打麥蓬蓬響莫田，兒童拾穟笑爭先。", "市頭米價新來減，一醉瓷甌五六錢。"]'),
('7f44fc28-660a-4165-96da-ffa5c67ccbd6','石磨','劉子翬','宋','宋诗','song-poetry','','[]','盤石輪囷隠澗幽，煙籠月照幾經秋。',32,'全唐诗/poet.song.111000.json','["盤石輪囷隠澗幽，煙籠月照幾經秋。", "可憐琢作團團磨，終日隨人轉不休。"]'),
('299ec1cf-ce81-49f5-b33c-d98325d01794','寒澗','劉子翬','宋','宋诗','song-poetry','','[]','林間幽鳥啄枯槎，落盡寒潮一澗沙。',32,'全唐诗/poet.song.111000.json','["林間幽鳥啄枯槎，落盡寒潮一澗沙。", "獨木橋西遊子宿，酒旗斜日兩三家。"]'),
('a5fc9e24-dd81-4d57-b4bb-d9443aed30da','秋望','劉子翬','宋','宋诗','song-poetry','','[]','輝輝江日已沉西，隠約餘紅泛渺瀰。',32,'全唐诗/poet.song.111000.json','["輝輝江日已沉西，隠約餘紅泛渺瀰。", "却上松岡望秋色，偶逢僧話立多時。"]'),
('7b98fd75-4b05-4155-b0b2-038febc78638','兩山','劉子翬','宋','宋诗','song-poetry','','[]','渡南渡北兩山遥，隔岸行人手可招。',32,'全唐诗/poet.song.111000.json','["渡南渡北兩山遥，隔岸行人手可招。", "日暮海門煙雨黑，一川舟檝趁歸潮。"]'),
('5ed652bd-79c0-44a4-87be-0c5e2fcdb01e','游鯈','劉子翬','宋','宋诗','song-poetry','','[]','禹鑿天門浪渺茫，游鯈也解化龍翔。',32,'全唐诗/poet.song.111000.json','["禹鑿天門浪渺茫，游鯈也解化龍翔。", "風雲得路誇頭角，歲旱爭尋窟穴藏。"]'),
('4e7ee98e-bf3e-412a-a751-a8471ab79527','和徐從道韵二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','高軒遥肯顧，掃室慣逢迎。',48,'全唐诗/poet.song.111000.json','["高軒遥肯顧，掃室慣逢迎。", "酒喜頻中聖，官慚四至卿。", "憂時論曲突，感物詠長檠。", "古道難開口，微君孰與明。"]'),
('d9f8cb09-f450-4eda-961d-33765b2641d9','和徐從道韵二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','拂袖歸來日，柴門稚子迎。',48,'全唐诗/poet.song.111000.json','["拂袖歸來日，柴門稚子迎。", "貧甘守藜藿，名不愧公卿。", "寶劍空藏匣，良弨惜解檠。", "中興誰草詔，君盍在承明。"]'),
('89e4bd6b-f2bf-48bc-817f-edd23c9e272d','蔡子强挽章','劉子翬','宋','宋诗','song-poetry','','[]','擢秀詞林少也奇，星軺榮耀更分麾。',64,'全唐诗/poet.song.111000.json','["擢秀詞林少也奇，星軺榮耀更分麾。", "世傳清德名方盛，生不長年理可疑。", "蘇晉逃禪心淡泊，孔融好客酒淋漓。", "眼看玉樹埋塵土，零落交遊我獨悲。"]'),
('c1352d7a-c85e-43e5-a2d7-30444101e19b','聞笛','劉子翬','宋','宋诗','song-poetry','','[]','倚樓何處笛，飛響徹雲霄。',48,'全唐诗/poet.song.111000.json','["倚樓何處笛，飛響徹雲霄。", "曲怨吹難盡，風回聽忽遥。", "戍兵臨絕漠，閨婦起寒宵。", "一弄梅飛雪，華年鬢亦凋。"]'),
('401bb790-6056-4ea9-9d2f-d72121e00c42','投壺','劉子翬','宋','宋诗','song-poetry','','[]','暇日賓朋集，投壺雅戲同。',48,'全唐诗/poet.song.111000.json','["暇日賓朋集，投壺雅戲同。", "傍觀驚妙手，一失廢前功。", "禮盛周垂憲，詞誇晉起戎。", "區區論勝負，轉眼事還空。"]'),
('6706a8f1-9df8-420a-ad79-c2c5efc0a8ac','思賢堂懷薛令','劉子翬','宋','宋诗','song-poetry','','[]','創始人何在，空堂草棘侵。',48,'全唐诗/poet.song.111000.json','["創始人何在，空堂草棘侵。", "衝門狐竄急，穴柱蠹藏深。", "羽化王喬舄，塵昏子賤琴。", "獨嗟民困甚，誰繼昔賢心。"]'),
('c22cabb0-fa90-4d1c-95f6-e8ff5224ae31','燒','劉子翬','宋','宋诗','song-poetry','','[]','惹草熒熒熖，隨風烈烈聲。',48,'全唐诗/poet.song.111000.json','["惹草熒熒熖，隨風烈烈聲。", "欲臨橫澗斷，忽上晚風明。", "踸踔無潛迹，蒙茸有怒生。", "尚餘飛燼煖，培耔及春耕。"]'),
('2d073c9f-4340-415b-9590-37320e34c1f0','潮','劉子翬','宋','宋诗','song-poetry','','[]','江晚潮風應，蕭蕭百里秋。',48,'全唐诗/poet.song.111000.json','["江晚潮風應，蕭蕭百里秋。", "寒聲初戰峽，怒力暗移洲。", "卷岸舟航盡，涵空日月浮。", "吳兒輕逐利，亡命雪山頭。"]'),
('2a47b0fd-b69e-40d3-ba5f-551d6d544319','洛陽橋','劉子翬','宋','宋诗','song-poetry','','[]','跨海飛梁疊石成，曉風十里度瑶瓊。',64,'全唐诗/poet.song.111000.json','["跨海飛梁疊石成，曉風十里度瑶瓊。", "雄如建業虎城峙，勢若常山蛇陳橫。", "脚底波濤時洶湧，望中煙嶼晚分明。", "往來利涉歌遺愛，誰復題橋繼長卿。"]'),
('8d6a897e-becb-4349-87aa-515d5809b234','途中','劉子翬','宋','宋诗','song-poetry','','[]','小市猶依海，橫橋欲跨汀。',48,'全唐诗/poet.song.111000.json','["小市猶依海，橫橋欲跨汀。", "雨餘榕徑冷，春晚苧田青。", "薄宦低豪氣，浮生惜壯齡。", "急流歸亦好，憂患飽曾經。"]'),
('f8881686-7aa4-4fcd-996b-c546985acc58','次張守韵四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','久分閩郡竹，屢賜漢庭金。',48,'全唐诗/poet.song.111000.json','["久分閩郡竹，屢賜漢庭金。", "才刃硎新發，恩波海並深。", "寇銷乘間禍，民有不欺心。", "祇恐鋒車起，雲霄路莫尋。"]'),
('e18324d4-33c4-400f-948c-6bb2f7d1d220','次張守韵四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','促席山堂夜，寒燈吐碎金。',48,'全唐诗/poet.song.111000.json','["促席山堂夜，寒燈吐碎金。", "酒分鄰甕美，栗爆地爐深。", "疏懶難堪事，紛華易壞心。", "自憐貪寸祿，雙鬢老侵尋。"]'),
('9d066146-5b46-478a-bd45-727b261f9c3c','次張守韵四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','瓦白霜封縞，波清月漾金。',48,'全唐诗/poet.song.111000.json','["瓦白霜封縞，波清月漾金。", "柝沈秋壘靜，人語夜堂深。", "故國歸何日，寒衾事滿心。", "庭松憐手植，擢幹已彌尋。"]'),
('44b2adb7-5bae-419c-8654-292bce4a9eed','次張守韵四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','泣懷三獻玉，廉拒四知金。',48,'全唐诗/poet.song.111000.json','["泣懷三獻玉，廉拒四知金。", "勢利焚和猛，詩書汲古深。", "貴無長得意，閑有自由心。", "岣嶁丹砂在，盟寒儻可尋。"]'),
('ab90e954-19af-4f6d-b276-c73c5e392914','同李漢老登高齋','劉子翬','宋','宋诗','song-poetry','','[]','飛梯百級轉層巒，政喜登臨著眼寬。',64,'全唐诗/poet.song.111000.json','["飛梯百級轉層巒，政喜登臨著眼寬。", "海上波濤連閬苑，日邊塵土暗長安。", "亂來世事終無定，春盡羈愁豈一端。", "頼有謫仙能喜客，時陪杖屨得雄觀。"]'),
('7a321424-8e61-4d1e-8b55-7689ddcd8962','過丹峰菴','劉子翬','宋','宋诗','song-poetry','','[]','杖策到丹峰，開軒對綠叢。',48,'全唐诗/poet.song.111000.json','["杖策到丹峰，開軒對綠叢。", "禪心清似水，客鬢亂如蓬。", "鼓角譙門日，鶑花上巳風。", "逢人相借問，何地隠龐翁。"]'),
('747f2a2e-ed23-4eca-93bf-9de1c79cbdcc','悼李奉','劉子翬','宋','宋诗','song-poetry','','[]','選拔由親衛，時危遠出征。',48,'全唐诗/poet.song.111000.json','["選拔由親衛，時危遠出征。", "氣驍嘗忽敵，身歿始知名。", "故妾辭空帳，殘兵隸別營。", "傷心豺虎窟，冒險爾何輕。"]'),
('5550ea99-f22c-44e1-afca-fab88b40ccc4','聞韓侯至','劉子翬','宋','宋诗','song-poetry','','[]','今代淮陰將，宣威瘴海東。',48,'全唐诗/poet.song.111000.json','["今代淮陰將，宣威瘴海東。", "夜營兵氣黑，寒磧戰聲雄。", "有寇常親討，無官可賞功。", "屹然沈鷙貌，識汝未侯中。"]'),
('7b7d822e-cdee-48a4-aa03-e12ed1c0c818','次韵張守梅詩','劉子翬','宋','宋诗','song-poetry','','[]','破雪梅初動，南枝更北枝。',48,'全唐诗/poet.song.111000.json','["破雪梅初動，南枝更北枝。", "傍牆應折盡，背日較開遲。", "曉角驚殘夢，春愁占兩眉。", "狂風將落蕊，故入畫樓吹。"]'),
('2cea4181-624c-4591-8393-aff4f917dc62','次韵陳成季郡會','劉子翬','宋','宋诗','song-poetry','','[]','疾雨狂風恨若何，芳晨坐覺等閑過。',64,'全唐诗/poet.song.111000.json','["疾雨狂風恨若何，芳晨坐覺等閑過。", "惜花意欲春長在，對酒年來飲不多。", "雅會欣聞珠履集，新詞好付雪兒歌。", "風流閣老推前輩，喜客溫顔似醉酡。"]'),
('58808076-8e28-4abd-9bd4-399bdc98ad97','古松','劉子翬','宋','宋诗','song-poetry','','[]','手植知何代，樅樅萬蓋齊。',48,'全唐诗/poet.song.111000.json','["手植知何代，樅樅萬蓋齊。", "韵清琴易寫，幹直鳥難栖。", "慘淡連雲塢，鬅鬙蔭石谿。", "刳明雖小用，曾照路人迷。"]'),
('fe5f0bca-0a08-4767-acca-6df2205c9243','出郊','劉子翬','宋','宋诗','song-poetry','','[]','路轉囊山北，扶輿憶舊過。',48,'全唐诗/poet.song.111000.json','["路轉囊山北，扶輿憶舊過。", "乾坤征戰久，遊宦別離多。", "瘴樹餘紅葉，春江又綠波。", "平生豪橫氣，未老半消磨。"]'),
('046da1fd-92b1-499d-8660-541d20dd12c5','偶書','劉子翬','宋','宋诗','song-poetry','','[]','風急胡塵暗九州，岸巾長嘯一登樓。',64,'全唐诗/poet.song.111000.json','["風急胡塵暗九州，岸巾長嘯一登樓。", "故園却憶桐孫在，薄宦端爲荔子留。", "湖海以南兵尚鬭，犬戎不死禍難休。", "似聞推轂皆飛將，盍有清談謝傅流。"]'),
('73f8814f-e7b1-4ffd-93ca-dfdf8361b16b','送惠州史君范智聞','劉子翬','宋','宋诗','song-poetry','','[]','喜聽清談滿座傾，不堪行色動雙旌。',64,'全唐诗/poet.song.111000.json','["喜聽清談滿座傾，不堪行色動雙旌。", "長亭把酒分携易，暮角催人太瘦生。", "地遠守臣知妙選，時危壯士耻南征。", "羅浮說與潮陽近，盍擬離騷弔二英。"]'),
('66c1bdfd-8682-4408-b557-c4ff05146e90','柳','劉子翬','宋','宋诗','song-poetry','','[]','體爲常輕定復飄，間梅遮杏得春饒。',64,'全唐诗/poet.song.111000.json','["體爲常輕定復飄，間梅遮杏得春饒。", "別離處處添愁色，風雨年年換舊條。", "拂瓦半枯陶令宅，沿溪不斷灞陵橋。", "淒涼又見千門綠，野老當時恨未銷。"]'),
('2f948231-6af9-4dcd-a277-82a45ec604c1','鹿鳴燕詩送諸進士','劉子翬','宋','宋诗','song-poetry','','[]','講藝欣聞暫息兵，槐花秋晚詔羣英。',64,'全唐诗/poet.song.111000.json','["講藝欣聞暫息兵，槐花秋晚詔羣英。", "胡塵不隔蟾宮路，鏡水初題雁塔名。", "禮盛邦侯開宴豆，道隆鄉老萃簪纓。", "更期妙手皆穿的，薦士吳僚亦與榮。"]'),
('01920cd7-9fe6-44e9-9833-060099ae8713','至日','劉子翬','宋','宋诗','song-poetry','','[]','客中雙鬢老塵埃，海角仍逢至日來。',64,'全唐诗/poet.song.111000.json','["客中雙鬢老塵埃，海角仍逢至日來。", "近臘風光初染荔，新陽氣力僅浮灰。", "豆糜厭勝憐荆俗，雲物書祥憶魯臺。", "搔首故園心欲斷，少陵頼有掌中杯。"]'),
('057bba23-2465-4a3a-9a7b-8e0e4768a080','曲倚','劉子翬','宋','宋诗','song-poetry','','[]','器成因揉木，偃月勢相侔。',48,'全唐诗/poet.song.111000.json','["器成因揉木，偃月勢相侔。", "適用形雖巧，論材性本柔。", "倦憑觀秘籙，趺坐接禪流。", "莫效愚溪戮，時多曲似鈎。"]'),
('9f329d39-f35f-4313-a787-db9a0e6a1bc7','宵長','劉子翬','宋','宋诗','song-poetry','','[]','宵長慵早寐，念念客愁新。',48,'全唐诗/poet.song.111000.json','["宵長慵早寐，念念客愁新。", "燈影明高屋，蛩聲動四鄰。", "滿懷平日事，雙鬢倦遊身。", "避地從漂轉，西風羽檄頻。"]'),
('04a6c86e-4da0-4755-8b33-d53fabe93c4b','試弓','劉子翬','宋','宋诗','song-poetry','','[]','結束擬從戎，秋堂試寶弓。',48,'全唐诗/poet.song.111000.json','["結束擬從戎，秋堂試寶弓。", "角寒開拒手，弦勁響流空。", "巧習穿楊技，神誇飲羽功。", "挽强吾有待，狐兔莫爭雄。"]'),
('42194658-76d9-462f-b44b-5e43f43b05c3','次韵張守梅詩','劉子翬','宋','宋诗','song-poetry','','[]','草棘蕭蕭野岸隈，暗香消息已傳梅。',64,'全唐诗/poet.song.111000.json','["草棘蕭蕭野岸隈，暗香消息已傳梅。", "雪欺籬落遥難認，暖入枝條併欲開。", "愁向天涯今度見，老隨春色暗中來。", "似聞詩社多何遜，盍試招邀共一杯。"]'),
('d8ccb5fa-7dfb-4525-8903-7984c9697e42','次韵張守立春','劉子翬','宋','宋诗','song-poetry','','[]','把酒酬佳節，遨頭樂未央。',48,'全唐诗/poet.song.111000.json','["把酒酬佳節，遨頭樂未央。", "池冰猶澀舫，岸柳已籠牆。", "曉院簾幃卷，春盤餠餌香。", "慇懃分彩勝，爲掩鬢邊霜。"]'),
('430a7161-71e4-4739-9352-c840a14e191c','九日登北山','劉子翬','宋','宋诗','song-poetry','','[]','戲馬英雄安在哉，閒因九日上崔嵬。',64,'全唐诗/poet.song.111000.json','["戲馬英雄安在哉，閒因九日上崔嵬。", "步窮巖壑身忘倦，望盡乾坤意始開。", "已向晚風伴落帽，可無新菊共浮杯。", "佳時及早須行樂，老境侵人咄咄來。"]'),
('a7eb0c56-4165-4213-834c-85a69a362cba','荔子','劉子翬','宋','宋诗','song-poetry','','[]','挺秀窮荒歎未遭，昔賢吟賞著風騷。',64,'全唐诗/poet.song.111000.json','["挺秀窮荒歎未遭，昔賢吟賞著風騷。", "縱班盧橘材非偶，不近長安價愈高。", "烟雨萬株遥若畫，塵埃一騎笑徒勞。", "琱盤此日無遺選，品格妍媸敢自逃。"]'),
('f3e346e8-b4dd-4ed3-b0ab-839c3322318b','龍眼','劉子翬','宋','宋诗','song-poetry','','[]','幽株旁挺綠婆娑，啄咂雖微奈美何。',64,'全唐诗/poet.song.111000.json','["幽株旁挺綠婆娑，啄咂雖微奈美何。", "香剖蜜脾知韵勝，價輕魚目爲生多。", "左思賦詠名初出，玉局揄揚論豈頗。", "地極海南秋更暑，登盤猶足洗沈痾。"]'),
('734ea1a2-7d15-41b9-bd2d-b923fab1a487','次韵張守酴醿二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','榮華休羨黑頭公，且對芳辰賞麗叢。',64,'全唐诗/poet.song.111000.json','["榮華休羨黑頭公，且對芳辰賞麗叢。", "十萬青條寒掛雨，三千粉面笑臨風。", "莫將擬雪才情賦，盍與觀梅興味同。", "只恐春歸有遺恨，典刑猶在濁醪中。"]'),
('c519588a-9b89-43ab-8922-649ca3a73acf','次韵張守酴醿二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','退食黄堂喜自公，不妨幽興囑芳叢。',64,'全唐诗/poet.song.111000.json','["退食黄堂喜自公，不妨幽興囑芳叢。", "雙旌不出閒春晝，大筆微吟綴祖風。", "老矣交朋今日少，飄然遊宦異鄉同。", "杖藜約我過南浦，賢聖時時爲一中。"]'),
('8d97273b-b593-4cfd-b6d5-2acc36dfa770','荔子','劉子翬','宋','宋诗','song-poetry','','[]','炎蒸午枕夢滄浪，落落星苞喜乍嘗。',64,'全唐诗/poet.song.111000.json','["炎蒸午枕夢滄浪，落落星苞喜乍嘗。", "筆下丹青千品色，釵頭風露一枝香。", "鷄冠借諭何輕許，馬乳爭名固不量。", "直待當時妃子笑，驪山千古事淒涼。"]'),
('003e4b87-07ad-4c01-acf1-0f594de3a8b9','次施子韵','劉子翬','宋','宋诗','song-poetry','','[]','之子才非碌碌流，一官將母海濱遊。',64,'全唐诗/poet.song.111000.json','["之子才非碌碌流，一官將母海濱遊。", "妙齡意氣看長劍，久客風霜歎敝裘。", "完璧有懷空慕藺，著鞭它日定先劉。", "岫窗故隠今何在，草棘連雲淮楚秋。"]'),
('e4f61844-5bd9-44d8-880a-a526d9666189','次韵張守秋懷四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','杖藜乘興出，佳處每關情。',48,'全唐诗/poet.song.111000.json','["杖藜乘興出，佳處每關情。", "白石溪流淺，黄花籬落清。", "林烟經雨薄，野日傍山明。", "頼有杯中物，愁懷得暫平。"]'),
('21939ba4-ceae-4722-a5e7-941081af998c','次韵張守秋懷四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','徙倚山堂晚，悲秋萬古情。',48,'全唐诗/poet.song.111000.json','["徙倚山堂晚，悲秋萬古情。", "雨蔬猶擢秀，風沼自揚清。", "野迥歸牛小，沙寒白鳥明。", "淒淒楓柳樹，汝意亦難平。"]'),
('682058f5-77b3-4289-a49f-3b39c332c30c','次韵張守秋懷四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','失計縈塵網，栖栖厭不情。',48,'全唐诗/poet.song.111000.json','["失計縈塵網，栖栖厭不情。", "興隨鳬舄遠，官比綺曹清。", "大案韋編古，深房紙瓦明。", "聖賢聊晤對，事業只平平。"]'),
('2a38ccc3-267c-4c62-ba54-955cbef5ba59','次韵張守秋懷四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','歲事何倉卒，微吟寄客情。',48,'全唐诗/poet.song.111000.json','["歲事何倉卒，微吟寄客情。", "野耕方刈熟，鄰釀已沽清。", "歸雁年年急，寒烽處處明。", "予衰倦流轉，夢想玉階平。"]'),
('1f78600c-a382-4fa6-8691-c0ed00ef2e11','次韵蔡學士巖桂','劉子翬','宋','宋诗','song-poetry','','[]','才應摛藻大明宮，戲詠巖花屬意工。',64,'全唐诗/poet.song.111000.json','["才應摛藻大明宮，戲詠巖花屬意工。", "酷愛清香凌鼻觀，更欣佳句愈頭風。", "移來已覺池臺勝，賞處何當杖屨同。", "不解小山招隠意，巖幽歸夢繞青叢。"]'),
('619f9625-5faa-40d0-8723-9ef9badc4d4e','得沖佑命','劉子翬','宋','宋诗','song-poetry','','[]','幾年歸夢水雲間，猿鶴重尋已厚顔。',32,'全唐诗/poet.song.111000.json','["幾年歸夢水雲間，猿鶴重尋已厚顔。", "慚愧君恩猶竊祿，官銜新带武夷山。"]'),
('f1fb9b96-be95-4b76-ad53-951626b1c18d','與溫其對榻','劉子翬','宋','宋诗','song-poetry','','[]','細雨南窗夜，青燈對榻眠。',48,'全唐诗/poet.song.111000.json','["細雨南窗夜，青燈對榻眠。", "升沈嗟薄宦，聚散忽流年。", "失路誰推轂，他時看著鞭。", "竹林須款集，君亦暫留連。"]'),
('1eca0b1e-5c6c-4385-bfd8-121f6ebce7bf','和士特栽果十首 桃','劉子翬','宋','宋诗','song-poetry','','[]','手種桃花滿北山，花紅艷艷照春灣。',32,'全唐诗/poet.song.111000.json','["手種桃花滿北山，花紅艷艷照春灣。", "不知何代兒孫老，却見漁舟乍往還。"]'),
('a0182e32-56ad-41ec-99ab-86b3bdaaa16a','和士特栽果十首 李','劉子翬','宋','宋诗','song-poetry','','[]','仙枝移傍小巖幽，答遝名推第一流。',32,'全唐诗/poet.song.111000.json','["仙枝移傍小巖幽，答遝名推第一流。", "曾向清波沈寒碧，甘瓜五色但輕浮。"]'),
('f02302f5-8d83-41c6-84e1-8723bfd0d33a','和士特栽果十首 梅','劉子翬','宋','宋诗','song-poetry','','[]','園林漸見綠陰濃，漠漠輕烟細雨中。',32,'全唐诗/poet.song.111000.json','["園林漸見綠陰濃，漠漠輕烟細雨中。", "底事望梅能止渴，惟應萬想先來空。"]'),
('feb02491-a4f4-474d-b857-fc4eef2e8014','和士特栽果十首 橘','劉子翬','宋','宋诗','song-poetry','','[]','南北由來地氣偏，凌寒松柏但蒼然。',32,'全唐诗/poet.song.111000.json','["南北由來地氣偏，凌寒松柏但蒼然。", "逾淮種橘今爲枳，豈比中人性易遷。"]'),
('9f9d5240-05ba-4511-9b6f-c46c0a5d82b7','和士特栽果十首 櫻桃','劉子翬','宋','宋诗','song-poetry','','[]','一樹含桃火爍空，而今春獻隔離宮。',32,'全唐诗/poet.song.111000.json','["一樹含桃火爍空，而今春獻隔離宮。", "只應壯士憂時淚，灑向枝頭點點紅。"]'),
('5e1f9af2-97ad-4b2d-aea1-1c1e7568ccd8','和士特栽果十首 石榴','劉子翬','宋','宋诗','song-poetry','','[]','庭榴結實墊芳叢，一夜飛霜染茜容。',32,'全唐诗/poet.song.111000.json','["庭榴結實墊芳叢，一夜飛霜染茜容。", "萬子同胞無異質，金房玉隔謾重重。"]'),
('f91e87a9-4d8c-4c7b-93e9-258bbd5bd958','和士特栽果十首 棖','劉子翬','宋','宋诗','song-poetry','','[]','棖橘甘酸各效能，南苞錫貢不同升。',32,'全唐诗/poet.song.111000.json','["棖橘甘酸各效能，南苞錫貢不同升。", "果中亦抱遺才歎，有客攀條氣拂膺。"]'),
('923c973e-6c34-47ef-8ece-59dd307273b3','和士特栽果十首 枇杷','劉子翬','宋','宋诗','song-poetry','','[]','萬斛金凡綴樹稠，遺根漢苑識風流。',32,'全唐诗/poet.song.111000.json','["萬斛金凡綴樹稠，遺根漢苑識風流。", "也知不作清時瑞，朽腐那關故主憂。"]'),
('62106e53-32aa-472d-a473-5093fffa0259','和士特栽果十首 來禽','劉子翬','宋','宋诗','song-poetry','','[]','粲粲來禽味獨香，孤根誰徙向天涯。',32,'全唐诗/poet.song.111000.json','["粲粲來禽味獨香，孤根誰徙向天涯。", "好尋青李相遮映，風味應同逸少家。"]'),
('8fb126ae-b9b2-4773-b86c-af34d68cd8f1','和士特栽果十首 椑柿','劉子翬','宋','宋诗','song-poetry','','[]','秋林黄葉晚霜嚴，熟蔕甘香味獨兼。',32,'全唐诗/poet.song.111000.json','["秋林黄葉晚霜嚴，熟蔕甘香味獨兼。", "火傘頳虬浪褒拂，風標那似邑中黔。"]'),
('c82fde4c-8c01-48de-9046-96dd2ddb5df2','與原仲至交溪橋','劉子翬','宋','宋诗','song-poetry','','[]','倦憩春橋午，回環翠碧重。',48,'全唐诗/poet.song.111000.json','["倦憩春橋午，回環翠碧重。", "亂溪流背海，新柳色欺松。", "厭市常思野，爲官不及農。", "喜逢湖上客，談話得從容。"]'),
('2231e712-52cc-440f-8e1f-d399e26ea8a6','山源','劉子翬','宋','宋诗','song-poetry','','[]','汩汩山源水，分流去若馳。',48,'全唐诗/poet.song.111000.json','["汩汩山源水，分流去若馳。", "有聲知尚淺，得勢轉徂卑。", "葦棘連荒浦，魚蝦聚小泜。", "起予湖海興，惆悵念前期。"]'),
('a1ee540b-2e99-46b3-970d-3fe004643b14','春望','劉子翬','宋','宋诗','song-poetry','','[]','杳杳盡寒色，乘高望更迷。',48,'全唐诗/poet.song.111000.json','["杳杳盡寒色，乘高望更迷。", "曉晴山氣上，春漲野橋低。", "幽鳥啼無伴，閒花發欲齊。", "幾多沈寂景，醉筆爲提撕。"]'),
('6c022a19-6794-4fa5-8e9e-d8573689c7f9','書齋十詠 筆架','劉子翬','宋','宋诗','song-poetry','','[]','刻畫峰巒勢，尸功翰墨餘。',24,'全唐诗/poet.song.111000.json','["刻畫峰巒勢，尸功翰墨餘。", "鎖窗閒晝永，高卧數中書。"]'),
('ac51c630-2785-41eb-98db-c865eca8d6ab','書齋十詠 剪刀','劉子翬','宋','宋诗','song-poetry','','[]','錯落雙刀合，晶熒百鍊光。',24,'全唐诗/poet.song.111000.json','["錯落雙刀合，晶熒百鍊光。", "剪裁皆在手，終不露鋒鋩。"]'),
('5315ed51-97dd-4f04-9d09-3d69b52897c7','書齋十詠 喚鐵','劉子翬','宋','宋诗','song-poetry','','[]','號令行惟信，人誰不我承。',24,'全唐诗/poet.song.111000.json','["號令行惟信，人誰不我承。", "舉烽諸國叛，敲鐵小童譍。"]'),
('437fd91c-6ed5-4258-89ef-2c2f40314b31','書齋十詠 紙拂','劉子翬','宋','宋诗','song-poetry','','[]','拂兒雖草創，日用最相親。',24,'全唐诗/poet.song.111000.json','["拂兒雖草創，日用最相親。", "莫遣維摩室，潛生庾亮塵。"]'),
('ca58c714-3d51-47b3-9a3d-79c23f65c64f','書齋十詠 圖書','劉子翬','宋','宋诗','song-poetry','','[]','慚非蘇子佩，聊置簡書間。',24,'全唐诗/poet.song.111000.json','["慚非蘇子佩，聊置簡書間。", "尺牘予慵理，何勞汝汗顔。"]'),
('063c3665-458d-49f6-8868-ec4cd7d314f7','書齋十詠 壓紙獅子','劉子翬','宋','宋诗','song-poetry','','[]','鎮浮須假重，刻石作狻猊。',24,'全唐诗/poet.song.111000.json','["鎮浮須假重，刻石作狻猊。", "偶以形模好，兒童競見知。"]'),
('684ae471-2348-4f69-b749-ed6093e1de09','書齋十詠 界方','劉子翬','宋','宋诗','song-poetry','','[]','抄書防縱逸，界墨作遮闌。',24,'全唐诗/poet.song.111000.json','["抄書防縱逸，界墨作遮闌。", "妙用誰能識，心端筆自端。"]'),
('6a279e24-287d-4ce4-a346-b369fe5a4e1c','書齋十詠 硯瓶','劉子翬','宋','宋诗','song-poetry','','[]','小瓶防硯渴，埏埴自良工。',24,'全唐诗/poet.song.111000.json','["小瓶防硯渴，埏埴自良工。", "懷抱清誰見，聊憑一滴通。"]'),
('f4b258f2-fc50-470c-ae47-b1e41d3fcc6e','書齋十詠 燈檠','劉子翬','宋','宋诗','song-poetry','','[]','代木收奇幹，安燈創小檠。',24,'全唐诗/poet.song.111000.json','["代木收奇幹，安燈創小檠。", "勿誇能自照，得助益高明。"]'),
('5537658e-024c-49ad-ab57-81d5b5795110','書齋十詠 榰案木','劉子翬','宋','宋诗','song-poetry','','[]','匠餘留片木，榰案定欹傾。',24,'全唐诗/poet.song.111000.json','["匠餘留片木，榰案定欹傾。", "不是乖繩墨，人間地少平。"]'),
('8e755ea7-004c-4049-affb-5bcd1ca3ff1b','有酒','劉子翬','宋','宋诗','song-poetry','','[]','誰家好事許相過，有酒何妨醉面酡。',64,'全唐诗/poet.song.111000.json','["誰家好事許相過，有酒何妨醉面酡。", "兄弟偶同詞館逸，林泉偏傍故園多。", "晨鍾屢趁伊蒲飯，晚艇時聽欵乃歌。", "莫遣是非來到耳，只應憨睡奈閒何。"]'),
('1402eca6-3309-4d88-81f6-ad6c2d0ad760','過東陽','劉子翬','宋','宋诗','song-poetry','','[]','小箔鳴機幾萬家，時清猶想舊繁華。',64,'全唐诗/poet.song.111000.json','["小箔鳴機幾萬家，時清猶想舊繁華。", "樓臺夜映雙溪月，簫鼓春迷後坂花。", "回首十年真夢寐，停驂四顧但風沙。", "却過蕭寺無人語，獨對枯林數暝鴉。"]'),
('adf9bfdb-acd6-4ff2-96c0-66af02430c2d','題蓋竹廟','劉子翬','宋','宋诗','song-poetry','','[]','雙猿嘯月寒巖幽，陳侯故家官渡頭。',64,'全唐诗/poet.song.111000.json','["雙猿嘯月寒巖幽，陳侯故家官渡頭。", "陰陰老木旆旌暗，渺渺驚灘雲霧流。", "九旅已荷本朝渥，三雁更忻同日侯。", "我來瞻拜想遺直，歎息此道今悠悠。"]'),
('c1095e88-5892-43b2-a4fe-24e4d7424f4f','遊北巖','劉子翬','宋','宋诗','song-poetry','','[]','濺濺小水暗通池，熠熠高花亂出籬。',64,'全唐诗/poet.song.111000.json','["濺濺小水暗通池，熠熠高花亂出籬。", "知有精廬潛寂寞，更忻蠟屐共襟期。", "茗芽未辨三湯試，麥餠先嘗十字炊。", "幾許幽奇待知己，品題政在一篇詩。"]'),
('5969bf4f-d471-40cd-8844-402f15b1b1e3','訪原仲','劉子翬','宋','宋诗','song-poetry','','[]','布衣自昔有遺才，白首窮經隠澗隈。',64,'全唐诗/poet.song.111000.json','["布衣自昔有遺才，白首窮經隠澗隈。", "門掩青山朝暮色，客來濁酒兩三杯。", "鴻冥豈復驚塵網，鶚薦虛聞達帝臺。", "我亦放情依一壑，雲間杖屨喜相陪。"]'),
('ed9b6dbd-ebe3-4bea-b30a-6641bef7cf91','北風','劉子翬','宋','宋诗','song-poetry','','[]','雁起平沙晚角哀，北風回首恨難裁。',64,'全唐诗/poet.song.111000.json','["雁起平沙晚角哀，北風回首恨難裁。", "淮山已隔胡塵斷，汴水猶穿故苑來。", "紫色蛙聲真倔强，翠華龍衮暫徘徊。", "廟堂此日無遺策，可是憂時獨草萊。"]'),
('42c4cb47-bb32-4bff-9a5f-1d86deb9b4df','同原仲茂元致和入開善','劉子翬','宋','宋诗','song-poetry','','[]','寒聲蕭蕭霜葉秋，石路磽确穿林幽。',64,'全唐诗/poet.song.111000.json','["寒聲蕭蕭霜葉秋，石路磽确穿林幽。", "雲橫遠岫若平斷，風約小溪如倒流。", "偶經名藍亦終日，喜有勝士同茲遊。", "移床果茗咄嗟辦，曳杖欲歸仍更留。"]'),
('ba04a0e3-c302-4968-bf2e-728c31eaac40','原仲溫其彥藻彥符致明集敝廬','劉子翬','宋','宋诗','song-poetry','','[]','清樽勸客且留連，亂後相從亦偶然。',64,'全唐诗/poet.song.111000.json','["清樽勸客且留連，亂後相從亦偶然。", "三徑生涯鄉社裏，一秋心事菊花前。", "向來憂喜皆陳迹，老去光陰逐斷弦。", "懷抱故人今有幾，只因情話可忘年。"]'),
('e7afec6f-472d-418d-9db9-3642979267b1','過天竺寺','劉子翬','宋','宋诗','song-poetry','','[]','一徑聯鑣去，身疑在畫圖。',48,'全唐诗/poet.song.111000.json','["一徑聯鑣去，身疑在畫圖。", "林陰穿欲盡，山靄近還無。", "下榻聊盤礴，裁詩屢囁嚅。", "道人留客意，片月出雲孤。"]'),
('0cbe0128-db12-4281-9927-47a1a5571bb7','山館偶題','劉子翬','宋','宋诗','song-poetry','','[]','水繞山堂竹映橋，偶來塵意已潛消。',32,'全唐诗/poet.song.111000.json','["水繞山堂竹映橋，偶來塵意已潛消。", "最憐曉日浮波影，滿壁煌煌玉電摇。"]'),
('db160f68-403f-4fc2-b341-3c6212d90791','悠然堂和致明絕句','劉子翬','宋','宋诗','song-poetry','','[]','清霜一夜倒蒹葭，放出湖光徹遠沙。',32,'全唐诗/poet.song.111000.json','["清霜一夜倒蒹葭，放出湖光徹遠沙。", "漠漠浮煙收欲盡，晚風輕浪蹴銀花。"]'),
('e2c90970-0df4-4979-b3f7-d38b4ba91143','雜題四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','積雨生秋意，浮陰放晚晴。',24,'全唐诗/poet.song.111000.json','["積雨生秋意，浮陰放晚晴。", "鐘聲寒野迥，橋影小溪清。"]'),
('32e2fbeb-8c5f-4a92-af32-a19a2e938186','雜題四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','殘霞銷暝色，新月長圓輝。',24,'全唐诗/poet.song.111000.json','["殘霞銷暝色，新月長圓輝。", "黄落樹滋本，夜眠人息機。"]'),
('d7f15a01-d605-4aa7-aee9-f6ee5424bd8c','雜題四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','簷溜停清瀉，林聲息怒號。',24,'全唐诗/poet.song.111000.json','["簷溜停清瀉，林聲息怒號。", "水浮秋色遠，山带夕陽高。"]'),
('968f9735-30b6-4df8-a7dd-6df6f795f660','雜題四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','宿雁猶驚渚，昏鴉已著林。',24,'全唐诗/poet.song.111000.json','["宿雁猶驚渚，昏鴉已著林。", "野平雲散亂，江動月浮沈。"]'),
('f5ccd3ac-0227-496e-a7a7-bedd8401dfed','道中','劉子翬','宋','宋诗','song-poetry','','[]','微風收宿靄，細路繞平皋。',48,'全唐诗/poet.song.111000.json','["微風收宿靄，細路繞平皋。", "石亂春溪急，山寒曉月高。", "鳥聲時出樹，花氣欲侵袍。", "行役兼清賞，驅馳未覺勞。"]'),
('56fe91fe-e0da-42b7-a07d-1aa0027fe291','次彭資深韵','劉子翬','宋','宋诗','song-poetry','','[]','林下相從多勝友，誰如吾子妙才華。',64,'全唐诗/poet.song.111000.json','["林下相從多勝友，誰如吾子妙才華。", "曳裾所至成師席，射策由來有世家。", "意氣胸中千里駿，文詞筆下九光霞。", "郵亭一見傾懷抱，投分金蘭不足誇。"]'),
('f54a539d-420e-4471-8bc1-1e8033b98849','奉酬少稷道舊之什','劉子翬','宋','宋诗','song-poetry','','[]','少日胸懷輒自奇，與君談笑叩天扉。',64,'全唐诗/poet.song.111000.json','["少日胸懷輒自奇，與君談笑叩天扉。", "南宮試藝聯裾出，上苑尋芳結騎歸。", "亂後交遊今孰在，向來心事已多違。", "雙魚忽得平安信，回首家鄉夢欲飛。"]'),
('944501b6-30f3-4475-857d-d5752dbc92da','宿雲際偶題','劉子翬','宋','宋诗','song-poetry','','[]','穀雨都無十日間，落紅棲草已斑斑。',64,'全唐诗/poet.song.111000.json','["穀雨都無十日間，落紅棲草已斑斑。", "曉烟未放屋頭樹，春漲欲浮天際山。", "翠蓋縈風沉遠坂，漁舟驚浪落前灣。", "鍾聲認得林邊寺，歲歲籃輿獨往還。"]'),
('aad25121-e19a-4b74-8faa-6e27664b4fb0','贈詹朝倚','劉子翬','宋','宋诗','song-poetry','','[]','之子詞鋒孰敢爭，它時雲路定飛騰。',64,'全唐诗/poet.song.111000.json','["之子詞鋒孰敢爭，它時雲路定飛騰。", "客懷未免悲彈鋏，文社遥知喜得朋。", "舊隠生涯三徑菊，夜窗弦誦十年燈。", "長篇寄我情何厚，欲和陽春愧未曾。"]'),
('90eea3f9-65a4-42ff-b2e2-c5f9559e111a','雪','劉子翬','宋','宋诗','song-poetry','','[]','晚天冥漠霰初飛，皓皓山顔復水湄。',64,'全唐诗/poet.song.111000.json','["晚天冥漠霰初飛，皓皓山顔復水湄。", "莫遣瑶林生染汙，却憂雲路隠巇危。", "寒侵夜褐樽前覺，春入晴簷枕上知。", "憶得梁園探花早，十年淚眼看旌旗。"]'),
('c3bb920a-b86d-448c-8951-3e916597ce39','隆祐太后挽歌辭三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','三朝欽母訓，四海被仁風。',48,'全唐诗/poet.song.111000.json','["三朝欽母訓，四海被仁風。", "倉卒垂簾政，艱難取日功。", "仙遊暌懿範，孝慕慘皇衷。", "寢隧休華飾，靈輀必返嵩。"]'),
('c0e5b381-e9cd-4f0e-830d-3798cd20060f','隆祐太后挽歌辭三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','謚易徽名正，恩加戚屬優。',48,'全唐诗/poet.song.111000.json','["謚易徽名正，恩加戚屬優。", "素心潛道妙，盛化秉坤柔。", "握璽終存漢，爲梁實配周。", "願書班馬紀，萬古播芳猷。"]'),
('501e6a8c-a4a3-4027-950a-31658e7d4390','隆祐太后挽歌辭三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','儉約身爲率，憂勤壽豈延。',48,'全唐诗/poet.song.111000.json','["儉約身爲率，憂勤壽豈延。", "鐘殘長樂夜，日斷泰陵烟。", "歸馭應奔月，餘勳頼補天。", "傷心南渡日，一棹灨江船。"]'),
('124d0125-1827-4aad-9ca0-77dd33221f53','徐大著挽詩二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','韋經傳素業，漢策射巍科。',48,'全唐诗/poet.song.111000.json','["韋經傳素業，漢策射巍科。", "史擅三長譽，書讎九寫訛。", "甑塵終寂寞，雲路久蹉跎。", "迅景崦嵫迫，知君恨獨多。"]'),
('6e732db7-3e83-46be-afb3-c79767893819','徐大著挽詩二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','方同傾蓋樂，遽起絕弦悲。',48,'全唐诗/poet.song.111000.json','["方同傾蓋樂，遽起絕弦悲。", "道向清朝屈，心惟靜者知。", "阻修綿酒奠，誰序錦囊詩。", "宣室空思賈，淒涼又一時。"]'),
('cda3f4a0-9a1e-498c-9496-4d78934fe852','次韵劉憲詩二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','吾宗三鳳久心降，一見端如渴飲江。',64,'全唐诗/poet.song.111000.json','["吾宗三鳳久心降，一見端如渴飲江。", "好客襟懷直絕倒，封侯骨相自耆龐。", "知名夙昔慚驚座，袖手雍容笑斲窗。", "豈謂詩盟容我輩，啞鐘無韵若爲撞。"]'),
('fbcea0aa-fd22-4758-a3fb-cf631fe3d806','次韵劉憲詩二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','已築高城受虜降，盟言端的有如江。',64,'全唐诗/poet.song.111000.json','["已築高城受虜降，盟言端的有如江。", "翠華回蹕清馳道，繡指觀風絕犬龐。", "凱奏花卿初卷甲，詩成草聖屢題窗。", "還朝有策裨聰聽，納諫那憂以杖撞。"]'),
('3e12caa1-9fea-482f-af63-5c5554f0c9f1','次韵溫其雪','劉子翬','宋','宋诗','song-poetry','','[]','侵凌臘尾近春前，凍色冥冥不見天。',64,'全唐诗/poet.song.111000.json','["侵凌臘尾近春前，凍色冥冥不見天。", "一洗氛埃終自潔，暗催花柳爲誰妍。", "單衣窶巷無朝爨，垂箔高門有醉眠。", "聞道江頭消息好，玉旌瑶幟滿樓船。"]'),
('ae21f955-a7d1-4dba-b900-51d9f1730133','次韵原仲幽居','劉子翬','宋','宋诗','song-poetry','','[]','貴賤營營各有求，柴門晝掩靜幽幽。',64,'全唐诗/poet.song.111000.json','["貴賤營營各有求，柴門晝掩靜幽幽。", "讀書無效空千卷，學稼雖勤少一丘。", "感慨舊餘王粲賦，棲遲今倦長卿遊。", "幔亭莫失春風約，我亦身如不繫舟。"]'),
('198d6471-f852-440f-8dcc-fa214f84b07b','次韵原仲竹','劉子翬','宋','宋诗','song-poetry','','[]','夕烟浮野圃，春竹過鄰牆。',48,'全唐诗/poet.song.111000.json','["夕烟浮野圃，春竹過鄰牆。", "石澗深深影，風軒遠遠凉。", "禪心敲有韵，翠袖倚生香。", "不有冰霜勁，蒿萊到汝長。"]'),
('4de420ff-f5cb-4b2c-846d-2ef3834db04a','書事','劉子翬','宋','宋诗','song-poetry','','[]','三年玉帛走稽山，萬騎凌江稍北還。',64,'全唐诗/poet.song.111000.json','["三年玉帛走稽山，萬騎凌江稍北還。", "絕塞風烟連魏闕，千官戎服立朝班。", "皇圖鳳歷謳歌裏，紫色蛙聲倔强間。", "露布更傳原上捷，王師早晚下潼關。"]'),
('58ff470f-3c94-4ccd-abaa-f8bef6e5ebff','客路','劉子翬','宋','宋诗','song-poetry','','[]','客路經春雨，淹留未得歸。',48,'全唐诗/poet.song.111000.json','["客路經春雨，淹留未得歸。", "徑泥黄染屨，林霧白侵衣。", "直氣何由吐，愁心只欲飛。", "東風如解事，吹夢落漁磯。"]'),
('39cfbd13-dead-481e-8431-d98314729433','哭呂倅','劉子翬','宋','宋诗','song-poetry','','[]','瞑目荒山裏，携家萬里來。',48,'全唐诗/poet.song.111000.json','["瞑目荒山裏，携家萬里來。", "旅塋猶借地，兒哭不勝哀。", "裂甑妖難測，藏舟事可猜。", "大賢應有後，天道信悠哉。"]'),
('76078a42-bb76-45b7-99a6-52a600aeedc0','贈詹道人','劉子翬','宋','宋诗','song-poetry','','[]','道人山北住，鄉曲舊知名。',48,'全唐诗/poet.song.111000.json','["道人山北住，鄉曲舊知名。", "語妙初疑簡，神藏久益清。", "夜衾寒楮白，歸舄兩鳬輕。", "心靜皆仙境，何勞款玉京。"]'),
('63fbc25d-69dd-405f-a280-c59fd8e6e264','燕子','劉子翬','宋','宋诗','song-poetry','','[]','燕子何光彩，飛飛引衆雛。',48,'全唐诗/poet.song.111000.json','["燕子何光彩，飛飛引衆雛。", "營巢終老草，解語只含胡。", "賀厦恩非淺，焚宮禍亦殊。", "寥寥鴻鵠志，嗟汝豈能俱。"]'),
('4c9f1f93-e4c1-4d21-a708-1939755f0dde','秋意','劉子翬','宋','宋诗','song-poetry','','[]','又見庭梧一葉飛，物華心事兩差池。',64,'全唐诗/poet.song.111000.json','["又見庭梧一葉飛，物華心事兩差池。", "百年未半老相逼，四序平分秋獨悲。", "過岸山川雲漠漠，殘燈院落雨絲絲。", "客懷料理須杯酒，哭向窮途定自癡。"]'),
('bb4ee4d3-7877-46f6-9ec2-f0df7bf5ad68','屏跡','劉子翬','宋','宋诗','song-poetry','','[]','屏跡山樊避世喧，晚風落日靜柴門。',64,'全唐诗/poet.song.111000.json','["屏跡山樊避世喧，晚風落日靜柴門。", "寒泉繞竹通幽圃，小徑穿田入別村。", "散策微吟霜葉脫，鈎簾宴坐碧雲翻。", "閒中興味知何晚，絕口名途不更言。"]'),
('908e5801-ee5f-48cd-8f21-1f8668a89123','哭士特二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','自古才難得，斯人又早亡。',48,'全唐诗/poet.song.111000.json','["自古才難得，斯人又早亡。", "青蠅頻去國，白首歎爲郎。", "不覩遺書奏，徒懷挂劍傷。", "楚魂招不得，南斗夜無光。"]'),
('392a97d3-4ded-460b-aa3e-c949b6676dc4','哭士特二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','世緒風流遠，鄉評譽望清。',48,'全唐诗/poet.song.111000.json','["世緒風流遠，鄉評譽望清。", "苦心幾傳癖，老筆擅詩名。", "已訝祥占鵩，終憐夢泣瓊。", "五峯雲外碧，一慟見交情。"]'),
('cc655820-b80f-4e1b-93c1-bac6ee0888a3','讀士特詩集','劉子翬','宋','宋诗','song-poetry','','[]','誰將家集到書帷，故喜風騷擅一時。',64,'全唐诗/poet.song.111000.json','["誰將家集到書帷，故喜風騷擅一時。", "快讀祇愁雌霓誤，流傳不但落楓奇。", "唱酬濫許聯東野，敘引仍欣得牧之。", "生死窮途天不恤，虛名安用日星垂。"]'),
('cc172416-e0e5-4468-9351-27c9c3a8130e','燕子','劉子翬','宋','宋诗','song-poetry','','[]','燕子營巢得所依，銜泥辛苦傍人飛。',32,'全唐诗/poet.song.111000.json','["燕子營巢得所依，銜泥辛苦傍人飛。", "秋風一夜驚桐葉，不戀雕梁萬里歸。"]'),
('603987b5-b45a-4c66-9233-7942e6b3abd0','下灘','劉子翬','宋','宋诗','song-poetry','','[]','亂石槎牙瀉怒濤，滿船性命等鴻毛。',32,'全唐诗/poet.song.111000.json','["亂石槎牙瀉怒濤，滿船性命等鴻毛。", "莫誇好手翻成誤，寄語舟人穩著篙。"]'),
('9e5c95f2-2f9e-464a-84cb-1785c6e4522d','致明惠蓮栽','劉子翬','宋','宋诗','song-poetry','','[]','玉井初浮翠出，禪風漸扇紅開。',28,'全唐诗/poet.song.111000.json','["玉井初浮翠出，禪風漸扇紅開。", "長梯顧我安得，浄社如君盍來。"]'),
('fc832924-68a1-405a-964b-a5a9fce0af17','絕句五首  其一','劉子翬','宋','宋诗','song-poetry','','[]','目送孤鴻獨倚樓，晚風吹淚更橫流。',32,'全唐诗/poet.song.111000.json','["目送孤鴻獨倚樓，晚風吹淚更橫流。", "蕉花落處蠻烟碧，六十三程是白州。"]'),
('93e4039a-3fe8-4f20-92e7-e0150272acde','絕句五首  其二','劉子翬','宋','宋诗','song-poetry','','[]','雙魚來自瘴江濱，一讀家書一愴神。',32,'全唐诗/poet.song.111000.json','["雙魚來自瘴江濱，一讀家書一愴神。", "見說炎荒風土惡，可無神物護忠臣。"]'),
('1b0a1675-aaea-4c59-b6a5-5d757e74f4d4','絕句五首  其三','劉子翬','宋','宋诗','song-poetry','','[]','干戈擾擾恨何窮，南北東西任轉蓬。',32,'全唐诗/poet.song.111000.json','["干戈擾擾恨何窮，南北東西任轉蓬。", "世事不堪長齟齬，胸中頼有氣如虹。"]'),
('8d4dfb5a-6322-44b1-9057-77833966c523','絕句五首  其四','劉子翬','宋','宋诗','song-poetry','','[]','喜聞歸騎已揚鑣，載酒相迎不憚遥。',32,'全唐诗/poet.song.111000.json','["喜聞歸騎已揚鑣，載酒相迎不憚遥。", "我是武夷東道主，便同蠟屐上岧嶢。"]'),
('35aff73c-6afa-4af9-8705-a57b6ea4bd5c','絕句五首  其五','劉子翬','宋','宋诗','song-poetry','','[]','竹繞茅簷水繞階，東風漸欲放春回。',32,'全唐诗/poet.song.111000.json','["竹繞茅簷水繞階，東風漸欲放春回。", "丁寧紅紫休爭發，待取山南刺史來。"]'),
('97c0add8-5561-4b94-a5c5-05f5c87d2684','寄蜀二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','盜隔枝江遠，人來蜀道稀。',48,'全唐诗/poet.song.111000.json','["盜隔枝江遠，人來蜀道稀。", "亂離非復昔，富貴不如歸。", "戎馬心何壯，家山願莫違。", "阿圓從小慧，解歎白雲飛。"]'),
('fa89e6aa-2797-4af5-854f-84ea625bb041','寄蜀二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','有客傳歸信，愁懷得暫寬。',48,'全唐诗/poet.song.111000.json','["有客傳歸信，愁懷得暫寬。", "兒童占鵲喜，鄰里借書看。", "離蜀秋方半，浮湘歲欲闌。", "柴門頻灑掃，夢想見征鞍。"]'),
('fdc7adfb-5fd7-40d1-8626-54da2dc4b626','野墅','劉子翬','宋','宋诗','song-poetry','','[]','野墅驚秋晚，殘年匆匆過。',48,'全唐诗/poet.song.111000.json','["野墅驚秋晚，殘年匆匆過。", "海潮通井淺，林日到窗多。", "酒盡鄰翁餉，詩成稚子哦。", "人生行樂耳，軒冕奈余何。"]'),
('331aa7bc-9752-42cc-ad2d-47cec40412f2','秋宵','劉子翬','宋','宋诗','song-poetry','','[]','秋宵如許永，兀坐思悠哉。',48,'全唐诗/poet.song.111000.json','["秋宵如許永，兀坐思悠哉。", "手誤挑燈滅，情長鼓瑟哀。", "清號生竅穴，皓色轉崔嵬。", "醉覺雄心在，流光且莫催。"]'),
('4833f029-e4b9-4c83-a0d0-5bff8f6817da','春圃六言三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','候騎不侵南海，好山多近吾廬。',28,'全唐诗/poet.song.111000.json','["候騎不侵南海，好山多近吾廬。", "醒歌醉眠任我，朝奏暮召從渠。"]'),
('71da620f-2af4-458f-853e-388bc153a4dc','春圃六言三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','南堂面山已勝，北檻俯澗仍幽。',28,'全唐诗/poet.song.111000.json','["南堂面山已勝，北檻俯澗仍幽。", "千巖莫非石友，萬壑總是清流。"]'),
('7f62f67e-eba9-4def-9d41-6dbbe316342c','春圃六言三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','小凍猶殘柳雪，新□□□□□。',28,'全唐诗/poet.song.111000.json','["小凍猶殘柳雪，新□□□□□。", "□□□□□□，□酒時須一中。"]'),
('ff7b1549-e594-4a3d-a7eb-03a502c686f8','汴京紀事二十首  其一','劉子翬','宋','宋诗','song-poetry','','[]','帝城王氣雜妖氛，胡虜何知屢易君。',32,'全唐诗/poet.song.111000.json','["帝城王氣雜妖氛，胡虜何知屢易君。", "猶有太平遺老在，時時灑淚向南雲。"]'),
('90406608-ce8c-4f19-8097-2119cf032700','汴京紀事二十首  其二','劉子翬','宋','宋诗','song-poetry','','[]','玉璽相傳舜紹堯，壺春堂上獨逍遥。',32,'全唐诗/poet.song.111000.json','["玉璽相傳舜紹堯，壺春堂上獨逍遥。", "唐虞盛事今寥落，盡卷清風入聖朝。"]'),
('f3d96e01-a14f-4f15-b37e-af8c10e9b136','汴京紀事二十首  其三','劉子翬','宋','宋诗','song-poetry','','[]','聖君嘗膽憤艱難，雙蹕無因日問安。',32,'全唐诗/poet.song.111000.json','["聖君嘗膽憤艱難，雙蹕無因日問安。", "漢節凋零胡地闊，北州何處是通汗。"]'),
('2d8f49fd-4f65-44f6-809f-5792128e9550','汴京紀事二十首  其四','劉子翬','宋','宋诗','song-poetry','','[]','朝廷植黨互相挻，政事紛更屬紀年。',32,'全唐诗/poet.song.111000.json','["朝廷植黨互相挻，政事紛更屬紀年。", "曾讀上皇哀痛詔，責躬猶是禹湯賢。"]'),
('783d1ae9-16c5-47c5-b3a4-7513ec0b7c67','汴京紀事二十首  其五','劉子翬','宋','宋诗','song-poetry','','[]','聯翩漕舸入神州，梁主經營授宋休。',32,'全唐诗/poet.song.111000.json','["聯翩漕舸入神州，梁主經營授宋休。", "一自胡兒來飲馬，春波惟見斷冰流。"]'),
('76ae767f-a6e2-4f79-85de-f99f121eabd9','汴京紀事二十首  其六','劉子翬','宋','宋诗','song-poetry','','[]','內苑珍林蔚絳霄，圍城不復禁芻蕘。',32,'全唐诗/poet.song.111000.json','["內苑珍林蔚絳霄，圍城不復禁芻蕘。", "舳艫歲歲銜清汴，纔足都人幾炬燒。"]'),
('f9d15298-6713-44b3-8749-9cf517ff4141','汴京紀事二十首  其七','劉子翬','宋','宋诗','song-poetry','','[]','空嗟覆鼎誤前朝，骨朽人間駡未銷。',32,'全唐诗/poet.song.111000.json','["空嗟覆鼎誤前朝，骨朽人間駡未銷。", "夜月池臺王傅宅，春風楊柳太師橋。"]'),
('8e91f9fa-212d-43bb-9351-b388a954efd8','汴京紀事二十首  其八','劉子翬','宋','宋诗','song-poetry','','[]','御路丹花映綠槐，曈曈日照五門開。',32,'全唐诗/poet.song.111000.json','["御路丹花映綠槐，曈曈日照五門開。", "五皇欲與民同樂，不惜千金築露臺。"]'),
('0dc49329-c54b-4802-94bb-b3721eaf4dd8','汴京紀事二十首  其九','劉子翬','宋','宋诗','song-poetry','','[]','神霄宮殿五雲間，羽服黄冠綴曉班。',32,'全唐诗/poet.song.111000.json','["神霄宮殿五雲間，羽服黄冠綴曉班。", "詔許羣臣親受籙，步虛聲裏認龍顔。"]'),
('2e1e75df-5f31-4b2d-bf7b-d9ff8e7ac5f2','汴京紀事二十首  其一○','劉子翬','宋','宋诗','song-poetry','','[]','宮娃控馬紫茸袍，笑撚金丸彈翠毛。',32,'全唐诗/poet.song.111000.json','["宮娃控馬紫茸袍，笑撚金丸彈翠毛。", "鳳輦北遊今未返，蓬蓬艮嶽內中高。"]'),
('3a3fabcc-60af-4d58-bc31-c22beb8eead6','汴京紀事二十首  其一一','劉子翬','宋','宋诗','song-poetry','','[]','篤耨清香步障遮，並桃冠子玉簪斜。',32,'全唐诗/poet.song.111000.json','["篤耨清香步障遮，並桃冠子玉簪斜。", "一時風物堪魂斷，機女猶挑韵字紗。"]'),
('37e082d5-01c8-43cf-838a-53a71bcf427d','汴京紀事二十首  其一二','劉子翬','宋','宋诗','song-poetry','','[]','萬炬銀花錦繡圍，景龍門外軟紅飛。',32,'全唐诗/poet.song.111000.json','["萬炬銀花錦繡圍，景龍門外軟紅飛。", "淒涼但有雲頭月，曾照當時步輦歸。"]'),
('11519de6-a627-4826-84c7-11fb46afc2fe','汴京紀事二十首  其一三','劉子翬','宋','宋诗','song-poetry','','[]','雲芝九幹麥雙岐，盍有嘉生瑞聖時。',32,'全唐诗/poet.song.111000.json','["雲芝九幹麥雙岐，盍有嘉生瑞聖時。", "玉殿稱觴聞好語，時教張補撰宮詞。"]'),
('358fec9f-00b5-4841-93c9-313c9ca7765b','汴京紀事二十首  其一四','劉子翬','宋','宋诗','song-poetry','','[]','橋上遊人度鏡光，五花殿裹奏笙簧。',32,'全唐诗/poet.song.111000.json','["橋上遊人度鏡光，五花殿裹奏笙簧。", "日曛未放龍舟泊，中使傳宣趣鄆王。"]'),
('6f889362-f0a6-40b1-9b92-3ad4ea234ba4','汴京紀事二十首  其一五','劉子翬','宋','宋诗','song-poetry','','[]','天廄龍媒十萬蹄，春池蹴踏浪花飛。',32,'全唐诗/poet.song.111000.json','["天廄龍媒十萬蹄，春池蹴踏浪花飛。", "路人爭看蕭衙內，月下親調御馬歸。"]'),
('49b48819-db32-49c9-960b-26d10270e47e','汴京紀事二十首  其一六','劉子翬','宋','宋诗','song-poetry','','[]','盤石曾聞受國封，承恩不與倖臣同。',32,'全唐诗/poet.song.111000.json','["盤石曾聞受國封，承恩不與倖臣同。", "時危運作高城砲，猶解捐軀立戰功。"]'),
('7b92b27f-54c3-4eb5-9f6e-4681d8d4b859','汴京紀事二十首  其一七','劉子翬','宋','宋诗','song-poetry','','[]','梁園歌舞足風流，美酒如刀解斷愁。',32,'全唐诗/poet.song.111000.json','["梁園歌舞足風流，美酒如刀解斷愁。", "憶得少年多樂事，夜深燈火上樊樓。"]'),
('b157e010-ce35-4279-89bc-7156ac0fe1dc','汴京紀事二十首  其一八','劉子翬','宋','宋诗','song-poetry','','[]','倉黄禁陌夜飛戈，南去人稀北去多。',32,'全唐诗/poet.song.111000.json','["倉黄禁陌夜飛戈，南去人稀北去多。", "自古胡沙埋皓齒，不堪重唱蓬蓬歌。"]'),
('98b426c7-6ed1-4087-82fe-802af8f5edd2','汴京紀事二十首  其一九','劉子翬','宋','宋诗','song-poetry','','[]','河漢如雲掃泬寥，登東寒鐵響清宵。',32,'全唐诗/poet.song.111000.json','["河漢如雲掃泬寥，登東寒鐵響清宵。", "竹窗驚破高人夢，門外駸駸萬馬朝。"]'),
('0e7f9f21-7091-4848-9a91-443cc1cc29c7','汴京紀事二十首  其二○','劉子翬','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u548f\u53f2\u6000\u53e4", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143"]','輦轂繁華事可傷，師師垂老過湖湘。',32,'全唐诗/poet.song.111000.json','["輦轂繁華事可傷，師師垂老過湖湘。", "縷衣檀板無顔色，一曲當時動帝王。"]'),
('3fc88cc3-761f-4e90-b623-1a0ec783adc2','長句寄尚明學士','劉子翬','宋','宋诗','song-poetry','','[]','短褐沉潛不近名，只今長樂鄭康成。',64,'全唐诗/poet.song.111000.json','["短褐沉潛不近名，只今長樂鄭康成。", "酒中賢聖無多酌，琴裏宮商一再行。", "翰墨放懷新水石，烽烟回首舊蓬瀛。", "四愁不爲思君作，懷抱何因得暫平。"]'),
('5b3632b2-997f-4657-a7f9-eb55f5d1b0e4','讀韓子蒼呂居仁近詩','劉子翬','宋','宋诗','song-poetry','','[]','詩人零落歎才難，二妙風流壓建安。',64,'全唐诗/poet.song.111000.json','["詩人零落歎才難，二妙風流壓建安。", "已見詞鋒推晉楚，定應臭味等芝蘭。", "鴻軒意氣慚交呂，鳳躍聲華敢望韓。", "咫尺烟塵不相見，它時惆悵隔金鑾。"]'),
('c9d1a3bb-6f6c-4a04-97b9-ef10e87f71f0','題將軍巖','劉子翬','宋','宋诗','song-poetry','','[]','昔年棲險人何在，彷彿樓臺杳靄間。',64,'全唐诗/poet.song.111000.json','["昔年棲險人何在，彷彿樓臺杳靄間。", "事去長空飛鳥沒，時清宴坐一僧閒。", "霜秋石壁黄金樹，月夜雲濤碧玉灣。", "杖策時來訪奇絕，漁樵幽興自相關。"]'),
('ef98ba34-591e-438f-95b6-921f3a30316d','遊武夷山','劉子翬','宋','宋诗','song-poetry','','[]','回薄湍流漾翠岑，夷猶一舸縱幽尋。',64,'全唐诗/poet.song.111000.json','["回薄湍流漾翠岑，夷猶一舸縱幽尋。", "幔亭落日笙簫遠，毛竹連雲洞府深。", "似有碧雞翔木杪，誰將丹鶴寫巖陰。", "神仙可學非身外，多少遊人浪苦心。"]'),
('38411e19-266d-4b7e-8f59-a026f399bdd8','致中惠瓜','劉子翬','宋','宋诗','song-poetry','','[]','瓜疇暑雨亂花飛，美實蠲煩喜及時。',64,'全唐诗/poet.song.111000.json','["瓜疇暑雨亂花飛，美實蠲煩喜及時。", "蘇并筠籠香發越，金刀玉手翠離披。", "侯家昔見連阡盛，賈肆徒誇厚貌奇。", "珍重故人分少意，臨風宛若對冰姿。"]'),
('e1ace130-afc5-423f-9397-ae8b2112f4f5','得天台命二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','奉祠得請向天台，清夢先尋紫翠堆。',32,'全唐诗/poet.song.111000.json','["奉祠得請向天台，清夢先尋紫翠堆。", "借問劉晨今在否，雲間應見耳孫來。"]'),
('ef6d801a-c79f-4cca-b003-a1b238387e3d','得天台命二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','暖風環佩滿芳洲，貝闕珠宮憶舊遊。',32,'全唐诗/poet.song.111000.json','["暖風環佩滿芳洲，貝闕珠宮憶舊遊。", "此日劉郎心似水，桃花空繞暮溪流。"]'),
('fad07b04-290e-4fab-9d60-8af9d1dc80b0','遊密菴三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','半參樵徑繞危岑，彷彿精廬若可尋。',32,'全唐诗/poet.song.111000.json','["半參樵徑繞危岑，彷彿精廬若可尋。", "怪底扶筇筋力健，暖風晴日送登臨。"]'),
('1add5c3f-ef59-4d06-bbb3-17ee01620db7','遊密菴三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','病身偏與靜相宜，著意悠悠定自癡。',32,'全唐诗/poet.song.111000.json','["病身偏與靜相宜，著意悠悠定自癡。", "兀坐南窗了無語，篆花縈處一星移。"]'),
('295572bb-9324-4f5c-82da-e912f34c077e','遊密菴三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','幽興無邊未遽窮，泉聲隨屐下寒空。',32,'全唐诗/poet.song.111000.json','["幽興無邊未遽窮，泉聲隨屐下寒空。", "一秋夢桂仙洲碧，盤礴才能半日中。"]'),
('3c2e7ee5-0be7-40a4-bf43-4fd5d160b9a7','訪原仲山居','劉子翬','宋','宋诗','song-poetry','','[]','寂寂臨湖屋，湖風爲掩門。',48,'全唐诗/poet.song.111000.json','["寂寂臨湖屋，湖風爲掩門。", "鳥聲幽谷樹，山影夕陽村。", "好事長留客，雖貧亦置樽。", "平生枯淡意，去此欲誰論。"]'),
('d68a8578-16a1-435d-aa1a-4905d690639a','與致明對榻','劉子翬','宋','宋诗','song-poetry','','[]','勝會嘗連榻，還欣與子同。',48,'全唐诗/poet.song.111000.json','["勝會嘗連榻，還欣與子同。", "一燈寒夜永，殘夢雨聲中。", "道舊驚身老，談玄了性空。", "卜鄰今有約，泉石興何窮。"]'),
('38eff776-6d14-4e9d-8343-f5932801aec0','登原仲茅亭','劉子翬','宋','宋诗','song-poetry','','[]','茅簷聊徙倚，落日見樵蘇。',48,'全唐诗/poet.song.111000.json','["茅簷聊徙倚，落日見樵蘇。", "過雁飛何急，寒山遠欲無。", "劇談容謾叟，逸興慕潛夫。", "寸祿甘華髮，人生底事愚。"]'),
('d3b5a37b-d081-4bd9-94c1-a2ac2de81585','送瓜與胡原仲','劉子翬','宋','宋诗','song-poetry','','[]','呼兒急走送筠籃，敵暑惟應此物堪。',64,'全唐诗/poet.song.111000.json','["呼兒急走送筠籃，敵暑惟應此物堪。", "一握青瑶含秀潤，滿襟寒雪沍清甘。", "搔園底用修鄰怨，剪棘聊應益盜慚。", "它日儻收遺瓣種，離離虎掌遍山南。"]'),
('f52e6c6d-7d94-437e-abab-7a1cedd74158','菊','劉子翬','宋','宋诗','song-poetry','','[]','青叢馥鬰早抽芽，金蕊斕斑晚著花。',64,'全唐诗/poet.song.111000.json','["青叢馥鬰早抽芽，金蕊斕斑晚著花。", "秋意祇應宜淡泊，化工可是惜鉛華。", "輕烟細雨重陽節，曲檻疏籬五柳家。", "暮醉朝吟供採摘，更憐寒蝶共生涯。"]'),
('48328a10-2d1c-42ec-bcc2-9a9d95a80c60','黄彥達之衡山有詩留別因次其韵','劉子翬','宋','宋诗','song-poetry','','["\u8861\u5c71"]','窮臘冰霜千里客，此行何事更間關。',64,'全唐诗/poet.song.111000.json','["窮臘冰霜千里客，此行何事更間關。", "永懷契闊徒酸鼻，無力吹噓祇厚顔。", "鉛槧一囊身計拙，烽烟匝地世途艱。", "曳裾端向龍門去，清夢猶應憶故山。"]'),
('1e4386bd-7934-426c-b6f4-4ed44eb4a81f','懷遠','劉子翬','宋','宋诗','song-poetry','','[]','樓北樓南烟岫遮，水光秋色澹無涯。',64,'全唐诗/poet.song.111000.json','["樓北樓南烟岫遮，水光秋色澹無涯。", "風驚枯葦連汀雨，霜著寒楓滿樹花。", "故人悠悠絕雙鯉，別恨耿耿聞悲笳。", "索居懷抱向誰寫，古調一吟青鬢華。"]'),
('078ce06f-8060-4b50-b29e-786dfd80f6fa','梨','劉子翬','宋','宋诗','song-poetry','','[]','尚想飛花照綺疏，離離秋實點烟蕪。',64,'全唐诗/poet.song.111000.json','["尚想飛花照綺疏，離離秋實點烟蕪。", "丹腮曉露香猶薄，玉齒寒冰嚼欲無。", "舊有佳名留大谷，誰分靈種下仙都。", "蔗漿不用傳金椀，猶得相如病少蘇。"]'),
('9cefa74a-6e89-4df4-a07d-4613e341a698','築室','劉子翬','宋','宋诗','song-poetry','','[]','旋剪荆榛出舊蹊，架巖鑿壁啟幽棲。',64,'全唐诗/poet.song.111000.json','["旋剪荆榛出舊蹊，架巖鑿壁啟幽棲。", "已通鄰圃盡栽竹，更搭飛橋南過溪。", "蓮社昔誇廬阜勝，漁舟空向武陵迷。", "宦遊若勝歸田樂，肯把軒裳換一犁。"]'),
('1e5c63fd-7fdb-46c7-a12b-b1449ac7e010','絕句送巨山二首  其一','劉子翬','宋','宋诗','song-poetry','','["\u670b\u53cb", "\u79bb\u522b"]','二年寄跡閩山寺，一笑翻然向浙江。',32,'全唐诗/poet.song.111000.json','["二年寄跡閩山寺，一笑翻然向浙江。", "明月不知君已去，夜深還照讀書窗。"]'),
('b5f7ed54-71ff-41f9-aebb-fc573acc06b3','絕句送巨山二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','江邊胡虜年年盛，借筯應須爲掃除。',32,'全唐诗/poet.song.111000.json','["江邊胡虜年年盛，借筯應須爲掃除。", "聞道漢皇方仄席，不因詞賦召相如。"]'),
('7e968167-d954-4e99-b433-812c7c95640b','送元仲','劉子翬','宋','宋诗','song-poetry','','[]','惆悵回車不可攀，故廬猶得及春還。',32,'全唐诗/poet.song.111000.json','["惆悵回車不可攀，故廬猶得及春還。", "遥知去路風烟好，看盡閩山看越山。"]'),
('cc969930-b3f7-4432-b797-7ec4ea50184e','致中惠瓜因成二絕句  其一','劉子翬','宋','宋诗','song-poetry','','[]','故人夙有瓜畦約，走送筠籃百里間。',32,'全唐诗/poet.song.111000.json','["故人夙有瓜畦約，走送筠籃百里間。", "翠甒瓊罌纔一握，極知風味勝黄斑。"]'),
('0c48b155-44a0-4b8a-a11a-1258538cf3a2','致中惠瓜因成二絕句  其二','劉子翬','宋','宋诗','song-poetry','','[]','蔗漿溜溜香浮玉，蘇水沉沉色弄金。',32,'全唐诗/poet.song.111000.json','["蔗漿溜溜香浮玉，蘇水沉沉色弄金。", "那似甘瓜能破渴，一盤霜雪沍清襟。"]'),
('28749761-9e84-4034-98f2-2dee9e78ffe5','勸六四叔卜居','劉子翬','宋','宋诗','song-poetry','','[]','便合誅茅隠舊陂，亂來吾里獨熙熙。',64,'全唐诗/poet.song.111000.json','["便合誅茅隠舊陂，亂來吾里獨熙熙。", "年豐禾黍侵山上，地僻杉松傍澗欹。", "涉世有求俱甕算，歸田得計莫狐疑。", "竹林杖屨從茲始，二阮風流儻可追。"]'),
('8d60fe2a-202f-4372-afb2-c390eb803a38','贈王周士','劉子翬','宋','宋诗','song-poetry','','[]','逐客初從瘴海歸，平生未識想英奇。',64,'全唐诗/poet.song.111000.json','["逐客初從瘴海歸，平生未識想英奇。", "致身不負管城子，報國聊將雕面兒。", "舌在壯懷猶未已，途窮俗眼少相知。", "虎頭合是封侯相，笑挽天河會有時。"]'),
('7163fff0-9a64-41cd-914a-ed43014a19e7','杖藜','劉子翬','宋','宋诗','song-poetry','','[]','亂後惟憂死，無心問歲華。',48,'全唐诗/poet.song.111000.json','["亂後惟憂死，無心問歲華。", "故園依草莽，今日見梅花。", "閩俗嘗三飯，僧房但一茶。", "海瀕猶未穩，更擬訪仙槎。"]'),
('1de69446-4ddf-44bd-ac44-ab8163d336d6','有懷十首  其一','劉子翬','宋','宋诗','song-poetry','','[]','滿空寒雨雜飛烟，湖上先生擁褐眠。',32,'全唐诗/poet.song.111000.json','["滿空寒雨雜飛烟，湖上先生擁褐眠。", "借問茅齋容客否，夜燈相伴讀韋編。"]'),
('93c760ca-0c01-443d-b192-d95ddb84a6a3','有懷十首  其二','劉子翬','宋','宋诗','song-poetry','','[]','結茅同隠水雲間，何日柴車不往還。',32,'全唐诗/poet.song.111000.json','["結茅同隠水雲間，何日柴車不往還。", "憶得松林長嘯罷，歸時明月遍秋山。"]'),
('e1f0b81c-5e96-4772-a27b-1d057b974354','有懷十首  其三','劉子翬','宋','宋诗','song-poetry','','[]','山空墜石咽寒溪，雨濕浮雲晚更低。',32,'全唐诗/poet.song.111000.json','["山空墜石咽寒溪，雨濕浮雲晚更低。", "不見蕭屯劉處士，年年清夢繞瓜畦。"]'),
('c4a674ec-ed7c-45a1-928f-eb0d58940823','有懷十首  其四','劉子翬','宋','宋诗','song-poetry','','[]','當年冊府仰才華，一跌青雲萬里賒。',32,'全唐诗/poet.song.111000.json','["當年冊府仰才華，一跌青雲萬里賒。", "白首却來蓮社裏，幅巾緇褐誦楞伽。"]'),
('555fe062-973d-4057-9513-a51096485af5','有懷十首  其五','劉子翬','宋','宋诗','song-poetry','','[]','風驚枯葦白花浮，欲下橫橋晚更留。',32,'全唐诗/poet.song.111000.json','["風驚枯葦白花浮，欲下橫橋晚更留。", "惆悵不逢吳季子，一溪寒水带烟流。"]'),
('63354470-4704-48f4-bfec-da3892e48333','有懷十首  其六','劉子翬','宋','宋诗','song-poetry','','[]','青錢學士妙文章，便合含毫侍帝傍。',32,'全唐诗/poet.song.111000.json','["青錢學士妙文章，便合含毫侍帝傍。", "寂寂閩山餘舊隠，憶君時到讀書堂。"]'),
('22c4012e-ca3d-4a26-aede-e34717b607bb','有懷十首  其七','劉子翬','宋','宋诗','song-poetry','','[]','松底柴門盡日關，主人西去幾時還。',32,'全唐诗/poet.song.111000.json','["松底柴門盡日關，主人西去幾時還。", "長鑱委地黄精老，時有寒猿嘯硯山。"]'),
('aad10434-a476-49a4-b889-aa21e2c209ce','有懷十首  其八','劉子翬','宋','宋诗','song-poetry','','[]','馬蹴浮埃去路長，相逢端欲問行藏。',32,'全唐诗/poet.song.111000.json','["馬蹴浮埃去路長，相逢端欲問行藏。", "未饒赤壁風流在，且向何家醉碧香。"]'),
('6cf970b5-8e1b-4e8d-86a9-e64b38b25658','有懷十首  其九','劉子翬','宋','宋诗','song-poetry','','[]','翁侯滿腹是精神，三謁金門計未成。',32,'全唐诗/poet.song.111000.json','["翁侯滿腹是精神，三謁金門計未成。", "却跨蹇馿遊霅上，秋風雄劍匣中鳴。"]'),
('a7fb27a3-583e-4540-b5bc-e6ac5c041560','有懷十首  其一○','劉子翬','宋','宋诗','song-poetry','','[]','曾訪高人上翠峯，至今清興逐松風。',32,'全唐诗/poet.song.111000.json','["曾訪高人上翠峯，至今清興逐松風。", "籃輿夢想行山處，白葛花開細雨中。"]'),
('2e5739a8-e38a-488e-b084-1098cbbb07ad','山寺見牡丹','劉子翬','宋','宋诗','song-poetry','','[]','倦遊曾向洛陽城，幾見芳菲照眼新。',64,'全唐诗/poet.song.111000.json','["倦遊曾向洛陽城，幾見芳菲照眼新。", "載酒屢穿卿相圃，傍花時值綺羅人。", "十年客路驚華髮，回首中原隔戰塵。", "今日尋芳意蕭索，山房數朵弄殘春。"]'),
('86a7fec3-5a64-45df-98a8-d6b3c31897a9','送六四叔之茶陵','劉子翬','宋','宋诗','song-poetry','','[]','底用匆匆便據鞍，離觴縱滿不能歡。',64,'全唐诗/poet.song.111000.json','["底用匆匆便據鞍，離觴縱滿不能歡。", "瀟湘萬里客愁遠，鶗鴂一聲春事闌。", "此去宦遊當益顯，時來功業自非難。", "似聞幕府資奇畫，好借雄風弄羽翰。"]'),
('3b8f975a-2dd0-4b54-8803-028c253c52ba','蕭屯訪致中','劉子翬','宋','宋诗','song-poetry','','[]','曉色陰晴久未分，亂山何處是蕭屯。',64,'全唐诗/poet.song.111000.json','["曉色陰晴久未分，亂山何處是蕭屯。", "荒荒日轉漁樵路，靄靄烟生桑柘村。", "勝地逢春聊駐馬，主人好客爲開樽。", "平生夢想歸田樂，正喜吾儕得踐言。"]'),
('df741258-4ae3-4975-bb18-ee3da0ac4780','李似表見訪','劉子翬','宋','宋诗','song-poetry','','[]','石磴荆藩隠薜蘿，豈知迢遞枉鳴珂。',64,'全唐诗/poet.song.111000.json','["石磴荆藩隠薜蘿，豈知迢遞枉鳴珂。", "交遊奈久如君少，邂逅成歡此夕多。", "千斛敢求身後傳，一樽聊和飲中歌。", "雲鵬欲舉那留得，南浦傷心又綠波。"]'),
('817571fd-90e6-4353-93c3-ffa248f8bf26','致明携酒來雲際','劉子翬','宋','宋诗','song-poetry','','[]','有客携家釀，敲門訪病翁。',48,'全唐诗/poet.song.111000.json','["有客携家釀，敲門訪病翁。", "一春寒食過，幽寺晚晴中。", "嫩竹扶簷綠，殘花蓋地紅。", "牢愁頼君破，歸意莫匆匆。"]'),
('859565e6-fa75-470c-be7b-343a78200f75','次韵六四叔蘭詩','劉子翬','宋','宋诗','song-poetry','','[]','疏疏綠髮覆清潯，漠漠微香起夕陰。',64,'全唐诗/poet.song.111000.json','["疏疏綠髮覆清潯，漠漠微香起夕陰。", "無復風流追九畹，空餘烟雨暗深林。", "誰分秀色來幽室，獨寫遺聲入素琴。", "還似高人遠塵俗，爭輝玉樹亦何心。"]'),
('ca2a8ce3-d24d-4b2a-a077-5407c8ba2617','讀李忠愍文集','劉子翬','宋','宋诗','song-poetry','','[]','英姿直節想堂堂，不忍偷生向擾攘。',64,'全唐诗/poet.song.111000.json','["英姿直節想堂堂，不忍偷生向擾攘。", "二帝蒙塵方幸虜，六臣奉璽更朝梁。", "身輕欲抗豺狼怒，名在終同日月光。", "曾與先君共褒錄，拊編交感淚浪浪。"]'),
('960884c7-23e6-42f0-866c-178aa475ece8','同詹明誠傅茂元遊晞真館有詩因次其韵','劉子翬','宋','宋诗','song-poetry','','[]','橘柚垂紅古觀秋，歸途邂逅得尋幽。',64,'全唐诗/poet.song.111000.json','["橘柚垂紅古觀秋，歸途邂逅得尋幽。", "晴沙散策隨山遠，夜月回船信水流。", "勝處無詩端可恨，它時有酒更來遊。", "相陪二妙平生友，老矣襟期共一丘。"]'),
('bec14579-0adc-4870-894f-66c9b574a9a0','入白水次韵劉溫其詩','劉子翬','宋','宋诗','song-poetry','','[]','南山北山舊經行，諸劉相看如弟兄。',64,'全唐诗/poet.song.111000.json','["南山北山舊經行，諸劉相看如弟兄。", "一枰圍棋果敵國，五字琢句真長城。", "濁醪粗飯有餘樂，小几疏簾何太清。", "我來徑醉未歸得，卧對屋角巖泉傾。"]'),
('8525e74f-b921-4b1a-bfbf-da6260c4cc2d','宿士特山堂懷似表','劉子翬','宋','宋诗','song-poetry','','[]','襆被重來宿，山堂故宛然。',48,'全唐诗/poet.song.111000.json','["襆被重來宿，山堂故宛然。", "池清秋過月，林靜晚生烟。", "仙李朝雙闕，詩翁閟九泉。", "無因訪存歿，搔首暮山前。"]'),
('4942b0b2-20c6-496a-8442-e40a292b1898','過致思新齋','劉子翬','宋','宋诗','song-poetry','','[]','酷愛鵝溪水，潺潺傍馬流。',48,'全唐诗/poet.song.111000.json','["酷愛鵝溪水，潺潺傍馬流。", "落梅寒崦靜，啼鳥暮村幽。", "我病今朝已，君家有酒不。", "新齋最奇絕，猶得少淹留。"]'),
('1cc22750-bbcf-4a39-aac5-9b67195cada7','約致明入開善不至二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','喬松翠竹鎖禪關，乘興時來興盡還。',32,'全唐诗/poet.song.111000.json','["喬松翠竹鎖禪關，乘興時來興盡還。", "懊恨劉郎招不得，瘦筇獨自入寒山。"]'),
('01102d51-c2b4-4aff-967b-03558411532e','約致明入開善不至二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','偶臨沙岸立多時，淡淡烟村日向低。',32,'全唐诗/poet.song.111000.json','["偶臨沙岸立多時，淡淡烟村日向低。", "幽事挽人歸不得，一枝梅影浸澄溪。"]'),
('d2106bbd-6483-4f26-94e5-d0e0d46962e9','宿回向寺','劉子翬','宋','宋诗','song-poetry','','[]','清秋聊命駕，細雨獨行山。',48,'全唐诗/poet.song.111000.json','["清秋聊命駕，細雨獨行山。", "淺淡烟雲裏，回還紫翠間。", "病多新覺老，心懶舊能閒。", "宿遍山南寺，何曾興盡還。"]'),
('76215cbe-7a8f-4f3c-a96c-94e30e412b07','次韵趙清獻陰字詩','劉子翬','宋','宋诗','song-poetry','','[]','石磴雲房隠澗陰，昔年清獻此清吟。',64,'全唐诗/poet.song.111000.json','["石磴雲房隠澗陰，昔年清獻此清吟。", "鳳池人物終難繼，花縣風流直到今。", "三尺翠碑遺墨在，一林寒竹暮烟深。", "平生景仰高名久，敢負它時直愛心。"]'),
('e64a68c9-adf0-411c-a9f6-0d716c1ea9da','次韵溫其種竹詩','劉子翬','宋','宋诗','song-poetry','','[]','種竹應須我輩人，茅簷對此可忘貧。',64,'全唐诗/poet.song.111000.json','["種竹應須我輩人，茅簷對此可忘貧。", "欹風带雨看無厭，淡夜寒綃畫不真。", "青女侵凌餘瘦節，籜龍盤屈更分身。", "會裁一管招鳴鳳，千畝何須羨渭濱。"]'),
('fafd6524-1945-4804-a5be-a6161b8b0024','次韵溫其見寄長句','劉子翬','宋','宋诗','song-poetry','','[]','拂衣歸去隠巖扃，世事悠悠亦飽經。',64,'全唐诗/poet.song.111000.json','["拂衣歸去隠巖扃，世事悠悠亦飽經。", "午夢溪聲摇戶牖，夜吟花影轉廂營。", "已甘衰病安堯壤，豈有聲名動漢廷。", "好事髯翁每相過，幅巾藜杖喜逢迎。"]'),
('deaa543d-fb61-49a3-956f-17e22bddb854','周元仲將出山有愁別園林後夜春之句因作此詩留之','劉子翬','宋','宋诗','song-poetry','','[]','山館春來特地幽，岸巾何日不同遊。',64,'全唐诗/poet.song.111000.json','["山館春來特地幽，岸巾何日不同遊。", "花隨石壁高低發，水繞茅簷左右流。", "叵我三杯真性適，咍臺一枕萬緣休。", "山中樂事端如許，爲底周郎不肯留。"]'),
('021e4a84-8b55-4d0f-ba12-83177a45ca90','伯勝文本袖詩見訪輒成長句奉酬盛意','劉子翬','宋','宋诗','song-poetry','','[]','懶逐交遊戶晝扃，客來曳履亦逢迎。',64,'全唐诗/poet.song.111000.json','["懶逐交遊戶晝扃，客來曳履亦逢迎。", "舊知吾里多豪雋，親識君家好弟兄。", "瓜芋滿畦聊卒歲，琴書一榻寄平生。", "驊騮歷塊終千里，俗眼悠悠未可輕。"]'),
('0d3fa77a-4b0c-4343-8994-44ed4277955d','呂尚書挽詩二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','昔在賢關日，雄飛接俊髦。',48,'全唐诗/poet.song.111000.json','["昔在賢關日，雄飛接俊髦。", "家因登第起，名爲諫君高。", "荷橐論思舊，牙旗出入勞。", "傷心淝水變，遺恨激秋濤。"]'),
('9271e1e9-7f11-4db9-9456-eb968aa63fd8','呂尚書挽詩二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','國步多艱棘，忠誠誓翼扶。',48,'全唐诗/poet.song.111000.json','["國步多艱棘，忠誠誓翼扶。", "據鞍方矍鑠，駡賊已含糊。", "義在光惇史，人亡失壯圖。", "因公感家世，憤氣欲吞胡。"]'),
('809043cc-5711-4d87-8a73-c959fd6df0e4','和丘斯行牧牛頌','劉子翬','宋','宋诗','song-poetry','','[]','軟草豐苗任滿前，蒼然觳觫卧寒烟。',32,'全唐诗/poet.song.111000.json','["軟草豐苗任滿前，蒼然觳觫卧寒烟。", "直饒牧得渾純熟，痛處還應著一鞭。"]'),
('3885bf66-b541-4ea4-bb3c-f8960b4bfa66','夜凉','劉子翬','宋','宋诗','song-poetry','','[]','茅舍蕭蕭暑雨餘，夜凉清若在冰壺。',32,'全唐诗/poet.song.111000.json','["茅舍蕭蕭暑雨餘，夜凉清若在冰壺。", "一窗月上杉篁影，便是人間水墨圖。"]'),
('84e131c4-3e95-4fc6-b082-8ffaa62ef87a','寄題鄭尚明煮茶軒三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','過耳颼颼未歇，裝懷憒憒俄空。',28,'全唐诗/poet.song.111000.json','["過耳颼颼未歇，裝懷憒憒俄空。", "它日寧逃水厄，會須一訪髯翁。"]'),
('876ce28e-88bc-4672-ad88-6a89a1f473e5','寄題鄭尚明煮茶軒三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','黿鼎從渠染指，麯車絕念流涎。',28,'全唐诗/poet.song.111000.json','["黿鼎從渠染指，麯車絕念流涎。", "猶有清饞未已，茶甌日食萬錢。"]'),
('72d3d308-912a-4d5b-b4ce-ec356e0625a7','寄題鄭尚明煮茶軒三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','一點春回枯枿，萬家譟動寒墟。',28,'全唐诗/poet.song.111000.json','["一點春回枯枿，萬家譟動寒墟。", "鳳餠龍團玉食，傷心半入穹廬。"]'),
('cd74eaf7-2b6a-4b04-983c-edcfbd2e9632','寄題陳良臣頤軒四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','七事疑生何晏，三爻夢感虞翻。',28,'全唐诗/poet.song.111000.json','["七事疑生何晏，三爻夢感虞翻。", "獨養靈龜不昧，有人高卧頤軒。"]'),
('418f7bfc-5e00-434d-b32c-73eb17f3fc2f','寄題陳良臣頤軒四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','啼鵑底用流血，渴水猶貪飲河。',28,'全唐诗/poet.song.111000.json','["啼鵑底用流血，渴水猶貪飲河。", "勿謂山雷象淺，人生口禍常多。"]'),
('00131b97-caa2-49b8-b31a-b377b2d5d698','寄題陳良臣頤軒四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','奇峯一疊兩疊，亂澗清流濁流。',28,'全唐诗/poet.song.111000.json','["奇峯一疊兩疊，亂澗清流濁流。", "那識高人勝處，閴然心地能幽。"]'),
('06a0d864-d838-462f-b72e-4ae38a1d0187','寄題陳良臣頤軒四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','道醇泮宮識面，德潤梓里知名。',28,'全唐诗/poet.song.111000.json','["道醇泮宮識面，德潤梓里知名。", "相從固應未晚，畏君難弟難兄。"]'),
('b383500d-d4a1-4075-b8e0-d5e145a76e35','胡文定公挽詩三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','今代儒林伯，聲名舊藹如。',48,'全唐诗/poet.song.111000.json','["今代儒林伯，聲名舊藹如。", "不爲簪紱累，常樂燕閒居。", "悟主承三接，尊王著一書。", "天胡奪楊綰，素業未全攄。"]'),
('d0466cb7-187b-4187-838c-f438e5192810','胡文定公挽詩三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','有意扶名教，躬行語默中。',48,'全唐诗/poet.song.111000.json','["有意扶名教，躬行語默中。", "楷模陶士器，藥石補天聰。", "衡嶽鄰新卜，伊川道已東。", "傳經知有子，接武大明宮。"]'),
('46629b7f-451c-4ce4-a38b-a2d5360e5eaa','胡文定公挽詩三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','奕葉論深契，平生仰大儒。',48,'全唐诗/poet.song.111000.json','["奕葉論深契，平生仰大儒。", "淹留趨絳帳，寂寞奠生芻。", "忍見摧梁木，悲歌碎玉壺。", "尺書垂奬意，提耳愧朱愚。"]'),
('4fbcb0a7-79c5-4ade-946f-9c5707a18193','徑山寄生子作道服三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','旋裁山繭作山衣，更著芒鞋白接䍦。',32,'全唐诗/poet.song.111000.json','["旋裁山繭作山衣，更著芒鞋白接䍦。", "自笑支離風貌野，紆朱紆紫不相宜。"]'),
('29ba09ee-d93c-4c5b-8757-86f73563e09c','徑山寄生子作道服三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','遠信慇懃到草菴，却慚衰病豈能堪。',32,'全唐诗/poet.song.111000.json','["遠信慇懃到草菴，却慚衰病豈能堪。", "聊將佛日三端布，爲造青州一領衫。"]'),
('a28475f9-a59b-4832-b008-565fc19a8537','徑山寄生子作道服三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','粲粲休誇綺與紈，紉蘭製芰亦良難。',32,'全唐诗/poet.song.111000.json','["粲粲休誇綺與紈，紉蘭製芰亦良難。", "此袍遍滿三千界，要與寒兒共解顔。"]'),
('a5f793a4-c23c-4d03-a661-fb37e877c402','清泉亨老寄鼓枕二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','團團鼓枕樣新傳，竹簟繩床得飽眠。',32,'全唐诗/poet.song.111000.json','["團團鼓枕樣新傳，竹簟繩床得飽眠。", "耳界若聞聲外意，不須撾擊也鏗然。"]'),
('491ef6f6-fbf9-4b51-b7d3-96ccf7b4b3da','清泉亨老寄鼓枕二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','蘧蘧一覺直千金，雅贈徒知感激深。',32,'全唐诗/poet.song.111000.json','["蘧蘧一覺直千金，雅贈徒知感激深。", "莫道林間高卧穩，憂時亦有枕戈心。"]'),
('9e2b7ea4-c508-410d-b61e-aeacaf631716','贈總上人兼簡無求居士二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','雙徑山中一衲衣，曳筇遠遠叩巖扉。',32,'全唐诗/poet.song.111000.json','["雙徑山中一衲衣，曳筇遠遠叩巖扉。", "愧無白璧黄金贈，携取清風滿袖歸。"]'),
('1509f346-f320-4180-9395-985629917ba4','贈總上人兼簡無求居士二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','多謝徽州吳使君，新詩問勞意何勤。',32,'全唐诗/poet.song.111000.json','["多謝徽州吳使君，新詩問勞意何勤。", "無求已得心空樂，更作無心出岫雲。"]'),
('1e9594f7-1c0d-4836-adf1-08b05e936654','會蔡子思張叔獻二教授','劉子翬','宋','宋诗','song-poetry','','[]','膠庠夙昔記追隨，物變時移萬事非。',64,'全唐诗/poet.song.111000.json','["膠庠夙昔記追隨，物變時移萬事非。", "曉闕風烟胡騎滿，夜窗燈火故人稀。", "中郎秉德無瑕纇，平子談經有旨歸。", "獨我衰遲愧朋友，蹉跎已覺壯心違。"]'),
('30ac56cb-f2e2-4706-9356-b7fd8d106160','次韵挹山亭張子猷絕句','劉子翬','宋','宋诗','song-poetry','','[]','鶴駕騰空春復秋，淡烟寒日鎖林丘。',32,'全唐诗/poet.song.111000.json','["鶴駕騰空春復秋，淡烟寒日鎖林丘。", "夕郎自是金門客，莫更臨風思遠遊。"]'),
('facd3111-d50e-4b0e-b9dc-64fd55e3d973','邃老寄龍涎香二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','瘴海驪龍供素沫，蠻村花露挹清滋。',32,'全唐诗/poet.song.111000.json','["瘴海驪龍供素沫，蠻村花露挹清滋。", "微參鼻觀猶疑似，全在爐烟未發時。"]'),
('847f32f1-19c1-41d8-9d89-9824ebccce27','邃老寄龍涎香二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','知有名香出海隅，幽人得得寄吾廬。',32,'全唐诗/poet.song.111000.json','["知有名香出海隅，幽人得得寄吾廬。", "明窗小爇跏趺坐，更覺胸懷一事無。"]'),
('0ab3f1d5-491e-40f7-b6cc-6cd8be528713','次韵溫其元日詩','劉子翬','宋','宋诗','song-poetry','','[]','曉來飛雨挾風顛，洗出韶容換故年。',64,'全唐诗/poet.song.111000.json','["曉來飛雨挾風顛，洗出韶容換故年。", "花動一紅明屋角，山寒亂碧到樽前。", "病如夜鶴孤還警，老似春蠶飽即眠。", "頼有故人開寂寞，錦囊詩句許時傳。"]'),
('f75bf14c-1c04-41bf-b005-d1ac32a03f04','呂丞相挽詩二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','黄髮三朝老，勤勞險阻中。',48,'全唐诗/poet.song.111000.json','["黄髮三朝老，勤勞險阻中。", "十年流馬策，一日斷鼇功。", "汛掃乾坤靜，扶持廟社隆。", "璜溪今寂寞，彷彿見英風。"]'),
('caa55a59-f9a5-4e69-8f7f-a23904a0787a','呂丞相挽詩二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','慎□重調鼎，宣威屢幹方。',48,'全唐诗/poet.song.111000.json','["慎□重調鼎，宣威屢幹方。", "夷吾欣在晉，尚父果興唐。", "劍佩凌烟閣，笙歌逸老堂。", "猶聞病乘馹，遺恨隔清光。"]'),
('e613f988-4769-4dd0-9c9b-4112b807b8be','次韵明仲遊北巖','劉子翬','宋','宋诗','song-poetry','','[]','雲巖藏勝絕，何路不潛通。',48,'全唐诗/poet.song.111000.json','["雲巖藏勝絕，何路不潛通。", "信步迷時遠，冥心樂處同。", "亂松風索索，懸瀑雨濛濛。", "陶謝多清興，招邀有遠公。"]'),
('d3494c48-fd9a-4abb-9265-6423935bc111','李丞相挽詩三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','委質艱難際，精忠日月昭。',48,'全唐诗/poet.song.111000.json','["委質艱難際，精忠日月昭。", "引裾堯浸縮，斷鞅虜氛消。", "顧眄安諸夏，風聲動一朝。", "南遷誰辨謗，公論付芻蕘。"]'),
('030ad8bd-e724-4272-93fd-4ae00b42a0bd','李丞相挽詩三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','文武中興相，名高北斗南。',48,'全唐诗/poet.song.111000.json','["文武中興相，名高北斗南。", "茂弘恢遠量，安石暢玄談。", "六策陳丹扆，三休寄夢菴。", "人亡今孰頼，憂國意如惔。"]'),
('88966be3-5379-4c4f-9027-f1c3b2a53e63','李丞相挽詩三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','賓榻勤初設，詩筒辱屢傳。',48,'全唐诗/poet.song.111000.json','["賓榻勤初設，詩筒辱屢傳。", "一嗟雲霧隔，坐閲歲時遷。", "埋玉俄成恨，乘風想已仙。", "終當挽行紼，長慟繐帷前。"]'),
('6310910d-cdfb-4258-a8c2-39789ab46a48','無諸策題問顔亡絕好軻沒無傳','劉子翬','宋','宋诗','song-poetry','','[]','孔林黄玉化飛埃，一派淵源有自來。',64,'全唐诗/poet.song.111000.json','["孔林黄玉化飛埃，一派淵源有自來。", "具體好時心似谷，厲辭傳處口如雷。", "聞聲盡是緇帷客，見色無非古市槐。", "却訝文公迷聖戶，不知靈鑰有人開。"]'),
('7f78915a-2f34-4e44-84e7-e23a16c05f25','次韵黄宰一源亭二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','聞說催耕步澗幽，田家喜氣共春浮。',32,'全唐诗/poet.song.111000.json','["聞說催耕步澗幽，田家喜氣共春浮。", "仁聲似水潛潛物，不作驚人洶洶流。"]'),
('e7282ee6-3c85-42ad-b19b-a6be8f47e064','次韵黄宰一源亭二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','賓榻浮塵拂不開，胸中豐恨結崔嵬。',32,'全唐诗/poet.song.111000.json','["賓榻浮塵拂不開，胸中豐恨結崔嵬。", "幔亭雲散天全露，猶想雙鳬化舄來。"]'),
('426e299d-2f7c-49ad-9c45-163c60c2a091','翁仁山受恩歸以詩相訪因次其韵','劉子翬','宋','宋诗','song-poetry','','[]','寒階響葉終日靜，剝啄欣聞人叩關。',64,'全唐诗/poet.song.111000.json','["寒階響葉終日靜，剝啄欣聞人叩關。", "一聽清言風灑座，幾回幽夢月沈山。", "遺珠未許留滄海，老驥終聞在六閑。", "獻策明光豈無用，人心久矣厭多艱。"]'),
('62e9a03e-57e7-474f-ba2b-0ead45ea2ef1','題王巖起樂齋三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','數叢修竹擁齋居，興味翛然樂有餘。',32,'全唐诗/poet.song.111000.json','["數叢修竹擁齋居，興味翛然樂有餘。", "午枕睡酣窗寂寂，清風來去自翻書。"]'),
('b72351c4-7c9b-4e24-87d3-9bd7575e945a','題王巖起樂齋三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','怪底愁端生不已，勞心逐事事無窮。',32,'全唐诗/poet.song.111000.json','["怪底愁端生不已，勞心逐事事無窮。", "陶然一點沖融趣，只在清虛淡泊中。"]'),
('8f2df91b-fe2f-4f2d-b4cd-76423b22d712','題王巖起樂齋三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','我亦雲根結小房，年來與世畧相忘。',32,'全唐诗/poet.song.111000.json','["我亦雲根結小房，年來與世畧相忘。", "定知可蛻紛華事，不及弦歌氣味長。"]'),
('f9977c2a-ed4a-42fd-8fca-a18dba2683f6','寄巨山','劉子翬','宋','宋诗','song-poetry','','[]','分携六換禁城烟，夢也慵飛到日邊。',64,'全唐诗/poet.song.111000.json','["分携六換禁城烟，夢也慵飛到日邊。", "綵筆尚懷貂可續，冰銜時許雁遥傳。", "紫薇院靜君宵直，綠苧村深我晝眠。", "會向急流歸亦好，雙筇同訪幔亭仙。"]'),
('564c85a2-3ceb-4819-bc44-aa6588b4796d','寄題觀瀾亭二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','遥知壓水創新齋，百里寒聲席下來。',32,'全唐诗/poet.song.111000.json','["遥知壓水創新齋，百里寒聲席下來。", "準擬杖藜秋夜去，同看月湧爛銀堆。"]'),
('8d8456a1-32cc-4828-926f-5ad9175db14f','寄題觀瀾亭二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','未合滄溟勢不休，噴雲齧石幾經秋。',32,'全唐诗/poet.song.111000.json','["未合滄溟勢不休，噴雲齧石幾經秋。", "雄心戲欲相吞吐，一縱詞瀾筆下流。"]'),
('7abb256f-252f-4ff7-8120-d74bde38e481','遊密菴致明有喜雨詩次原韵','劉子翬','宋','宋诗','song-poetry','','[]','雨氣經巖上，僧窗暗復明。',48,'全唐诗/poet.song.111000.json','["雨氣經巖上，僧窗暗復明。", "溪流生急響，松吹助狂傾。", "䆉䅉無邊潤，籧篨一味清。", "仁心樂同飽，擁鼻發吟聲。"]'),
('ef1e4999-c497-4aff-99d0-ee99664383c5','次韵熊叔雅七言','劉子翬','宋','宋诗','song-poetry','','[]','只今漂蕩賈長沙，來往三山躡緯霞。',64,'全唐诗/poet.song.111000.json','["只今漂蕩賈長沙，來往三山躡緯霞。", "馬上新詩猶憶友，枕邊幽夢不離家。", "風驚枯葦連汀雨，霜著寒楓滿樹花。", "却記梁園初識面，干戈豈料落天涯。"]'),
('c7f38e39-8f9c-4cc7-80be-e85b3dbeb8f4','題石井二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','玲瓏巖穴巧如刳，中貯滄浪百斛餘。',32,'全唐诗/poet.song.111000.json','["玲瓏巖穴巧如刳，中貯滄浪百斛餘。", "衰懶自憐遊世久，襟懷未及汝常虛。"]'),
('04eaf135-72ad-49db-9e2f-499ecc2129df','題石井二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','道經蘭若偶停鞭，客裏逢幽意惘然。',32,'全唐诗/poet.song.111000.json','["道經蘭若偶停鞭，客裏逢幽意惘然。", "一把綠蘿蒙石竇，夢魂翻憤醒心泉。"]'),
('6ddebcdd-494c-40fe-9c28-129950bf23eb','登鵝湖妙峰亭次韵','劉子翬','宋','宋诗','song-poetry','','[]','偶向妙峯亭上望，一襟寒色近春分。',32,'全唐诗/poet.song.111000.json','["偶向妙峯亭上望，一襟寒色近春分。", "晴風吹放天全露，吹盡江南江北雲。"]'),
('63414bd4-f1a0-4c88-b010-ea051c784372','題吳若愚一經堂','劉子翬','宋','宋诗','song-poetry','','[]','老矣惟書愛未消，喜聞新塾出塵囂。',64,'全唐诗/poet.song.111000.json','["老矣惟書愛未消，喜聞新塾出塵囂。", "軒窗近水來無厭，弦誦因風聽忽遥。", "遊藝定知輕拾芥，正心端欲似耘苗。", "一經教子誠爲樂，家世從今未寂寥。"]'),
('cfcc1435-f25a-48e9-a1e6-d3196582be0f','寄如愚珙二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','射殿遥聞駐六飛，天顔咫尺引儒衣。',32,'全唐诗/poet.song.111000.json','["射殿遥聞駐六飛，天顔咫尺引儒衣。", "吾家亦有臚傳喜，叔姪聯名賜第歸。"]'),
('f42a0ac7-ebe0-4922-b4d3-1897c92fc800','寄如愚珙二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','雁塔蟾宮盡假途，要須行實副名譽。',32,'全唐诗/poet.song.111000.json','["雁塔蟾宮盡假途，要須行實副名譽。", "六經堂上歸來日，飽讀平生未見書。"]'),
('923bc481-97c5-4ce6-9d3f-f3a846d677a7','次韵朱喬年送山老住三峰二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','已愛雲山信脚行，撩人詩句更增情。',32,'全唐诗/poet.song.111000.json','["已愛雲山信脚行，撩人詩句更增情。", "直須吏部尋盟日，急遣雙魚一寄聲。"]'),
('ea068a0c-97e0-4977-bf46-3cd2dabbe172','次韵朱喬年送山老住三峰二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','平生耳裏三峯寺，况識峯頭新主人。',32,'全唐诗/poet.song.111000.json','["平生耳裏三峯寺，况識峯頭新主人。", "借我一筇扶病去，月林松吹度綸巾。"]'),
('11d4b9ac-4650-400e-bf7e-56f44de9782f','朱喬年同傅茂元見訪','劉子翬','宋','宋诗','song-poetry','','[]','校書蘭臺昔名士，懷□會稽今望郎。',64,'全唐诗/poet.song.111000.json','["校書蘭臺昔名士，懷□會稽今望郎。", "忽驚風采照戶牖，便覺肺腑流冰霜。", "手談逼剝屢爭局，眼食咍臺時對床。", "山林情話政可樂，只恐雲路雙鵰翔。"]'),
('c46d1a6e-832f-4be5-9ff4-e725f1eab9e7','寄題黄應亨東明齋二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','青藜不復來人世，好學如君自少雙。',32,'全唐诗/poet.song.111000.json','["青藜不復來人世，好學如君自少雙。", "頼有羲和鞭日轂，曉紅常照讀書窗。"]'),
('ec3535be-39e2-4809-807d-f345de0dc110','寄題黄應亨東明齋二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','齋居雅意與誰論，會見依光沐寵恩。',32,'全唐诗/poet.song.111000.json','["齋居雅意與誰論，會見依光沐寵恩。", "慚愧野人欺我懶，相招炙背坐松根。"]'),
('42936ccb-da9e-48bb-92b5-45de536c31cf','寄題清軒二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','聞說名軒寄遠情，得非遊世厭營營。',32,'全唐诗/poet.song.111000.json','["聞說名軒寄遠情，得非遊世厭營營。", "丈夫出處渾無累，只要心源一點清。"]'),
('de6421fb-6cb4-4936-9126-ba45627cd0eb','寄題清軒二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','中郎言語妙天下，曾向軒中記舊遊。',32,'全唐诗/poet.song.111000.json','["中郎言語妙天下，曾向軒中記舊遊。", "一尺翠珉揮染罷，冰輪夜轉屋山頭。"]'),
('50e3e24c-4919-4790-8a87-091d9f0fa444','有感三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','八葉炎圖茂，千齡聖主昌。',48,'全唐诗/poet.song.111000.json','["八葉炎圖茂，千齡聖主昌。", "農桑開漢域，禮樂煥周庠。", "晏粲三登樂，謳吟七閏長。", "徽名辭鏤玉，盛舉冠前王。"]'),
('4628ec4b-b1b0-48ef-981c-2294555d9499','有感三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','運屬宣和末，干戈變故仍。',48,'全唐诗/poet.song.111000.json','["運屬宣和末，干戈變故仍。", "倦勤修內禪，流澤啟中興。", "雎水千麾集，胡沙八駿騰。", "尺書傳諱日，寰宇淚如澠。"]'),
('da919b5d-080c-483f-b63b-529f0196789c','有感三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','孝感柔强敵，和盟定一朝。',48,'全唐诗/poet.song.111000.json','["孝感柔强敵，和盟定一朝。", "龍輴來瀚海，鶴駕返神霄。", "歌吹仍祠禹，羹牆若見堯。", "稽山同峻極，從此百神朝。"]'),
('7dae7153-63a1-4101-9af9-bf3bad273f9b','和黄德欽韵贈公路二孫','劉子翬','宋','宋诗','song-poetry','','[]','佩鰈趨蹌政妙年，階庭蘭玉固天然。',32,'全唐诗/poet.song.111000.json','["佩鰈趨蹌政妙年，階庭蘭玉固天然。", "人間百藝皆由學，惟有讀書知子賢。"]'),
('4bac9896-98e8-41e5-8473-4856ebb6a243','謝劉致中瓜二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','萬言不直一杯水，才似謫仙良可嗟。',32,'全唐诗/poet.song.111000.json','["萬言不直一杯水，才似謫仙良可嗟。", "顧我小詩偏發市，年年博得蕭屯瓜。"]'),
('09456861-601d-4255-8198-878cd1037706','謝劉致中瓜二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','病翁癡絕端可笑，文墨骫骳誰得稱。',32,'全唐诗/poet.song.111000.json','["病翁癡絕端可笑，文墨骫骳誰得稱。", "故人分甘聊爾耳，更向詩流說我能。"]'),
('2b330c6e-a5f7-4891-99e3-20f8bc125e63','詹君則賦光壁堂詩拉余同作','劉子翬','宋','宋诗','song-poetry','','[]','幽行已辦百枝扶，况有溪山近故廬。',32,'全唐诗/poet.song.111000.json','["幽行已辦百枝扶，况有溪山近故廬。", "水碧山光都幾許，道人著眼恰無餘。"]'),
('1c0d43b2-c1b3-46b0-bea6-3ee33697842f','李佐國携致中贈別詩來戲成二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','星郎絕筆版曹卧，懶翁病翁稀綴文。',32,'全唐诗/poet.song.111000.json','["星郎絕筆版曹卧，懶翁病翁稀綴文。", "豈料詩壇今再鼓，蕭屯頼有故將軍。"]'),
('b3707445-9e19-48a8-87f6-0dc22648ecba','李佐國携致中贈別詩來戲成二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','贊皇吟毫不可掣，交遊酬答被惱深。',32,'全唐诗/poet.song.111000.json','["贊皇吟毫不可掣，交遊酬答被惱深。", "贈言排拫入吾里，以鄰爲壑君何心。"]'),
('521ca0d3-e384-4fe7-9e35-57892bab7415','次韵白水雪梅二詩  其一','劉子翬','宋','宋诗','song-poetry','','[]','閩雪少曾棲瓦白，怪來浩浩擁寒濱。',64,'全唐诗/poet.song.111000.json','["閩雪少曾棲瓦白，怪來浩浩擁寒濱。", "嚴威故作敝裘厄，淡彩潛催幽幌晨。", "眼觀醉中迷有色，心華浄處照無垠。", "摇松旋拾晶熒煮，已覺肥生齒頰津。"]'),
('d4ebc78c-2a2c-4fcf-9801-40330cb6a7f8','次韵白水雪梅二詩  其二','劉子翬','宋','宋诗','song-poetry','','[]','豪氣無根老自摧，尚留餘習愛尋梅。',64,'全唐诗/poet.song.111000.json','["豪氣無根老自摧，尚留餘習愛尋梅。", "苦寒扶病也須去，薄暮微吟垂欲開。", "靜納長芬風外塢，醉臨高白水邊臺。", "無言自得幽貞意，莫吐肝腸錦繡才。"]'),
('9def69b8-cf2c-4df5-97a2-e71ef7368493','原仲致中寄梅雪二詩再次前韵  其一','劉子翬','宋','宋诗','song-poetry','','[]','一雪度臘寒不春，風光淡然溪谷濱。',64,'全唐诗/poet.song.111000.json','["一雪度臘寒不春，風光淡然溪谷濱。", "清湖讀易月當午，烏石掛廬梅照晨。", "未借流膏耕沃野，聊乘爽氣款蒼垠。", "嗣音風雅愧辭竭，安得筆翻雲漢津。"]'),
('b3c2f66c-1493-440f-a684-e38887413a64','原仲致中寄梅雪二詩再次前韵  其二','劉子翬','宋','宋诗','song-poetry','','[]','飯了意行忘遠近，翛翛老眼入疏梅。',64,'全唐诗/poet.song.111000.json','["飯了意行忘遠近，翛翛老眼入疏梅。", "愁邊賞味平生劇，亂後橫斜幾度開。", "勝韵撩詩頻呫囁，冷香薰夢破咍臺。", "莫將花客輕題品，自有渠儂十倍才。"]'),
('b5ffad49-9842-4875-885b-af89810c509c','橙子四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','尚懷細雨初移日，著子已見清霜潸。',32,'全唐诗/poet.song.111000.json','["尚懷細雨初移日，著子已見清霜潸。", "絕憐面有貴人色，偶致吾儕樽俎間。"]'),
('af250622-5765-47ff-87a7-223f2a0a6925','橙子四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','橙虀細縷風韵勝，我不痛飲那知音。',32,'全唐诗/poet.song.111000.json','["橙虀細縷風韵勝，我不痛飲那知音。", "何如金丸走衾枕，三月夢遊薝蔔林。"]'),
('07e09ab9-c5a6-49ac-9ad0-8b6356935405','橙子四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','自從天籞守吏散，老樹零落煙雲淒。',32,'全唐诗/poet.song.111000.json','["自從天籞守吏散，老樹零落煙雲淒。", "今朝我爲作知己，小摘秋風黄欲齊。"]'),
('5fb1f7a3-28a1-455d-8b2e-83d7b22c3197','橙子四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','花瓷泛蜜小劑供，極有痛快鏖邪功。',32,'全唐诗/poet.song.111000.json','["花瓷泛蜜小劑供，極有痛快鏖邪功。", "生枝滋味雖可口，流品故應甘下風。"]'),
('86f3fe42-c43d-4287-95a3-30921afb4c77','寄巨山','劉子翬','宋','宋诗','song-poetry','','[]','故人浮家檇李傍，爲愛修竹分僧房。',64,'全唐诗/poet.song.111000.json','["故人浮家檇李傍，爲愛修竹分僧房。", "霏霏玉塵夢千里，剡剡銀鈎書數行。", "極知神潛鼻端白，祇恐喜動眉間黄。", "烟波莫久費吟筆，好繪日月增天光。"]'),
('bf7f9f76-5e45-45c4-aeb9-88fee47c86ee','次韵傅茂元二絕  其一','劉子翬','宋','宋诗','song-poetry','','[]','濠樂亭前花已披，馬軍送酒故來遲。',32,'全唐诗/poet.song.111000.json','["濠樂亭前花已披，馬軍送酒故來遲。", "只愁風雨卷春去，紅染芳郊一徑泥。"]'),
('bd6e1ae7-60b9-4ea3-983a-aebb2dc48031','次韵傅茂元二絕  其二','劉子翬','宋','宋诗','song-poetry','','[]','酒興何如畢吏部，詩情已過鮑參軍。',32,'全唐诗/poet.song.111000.json','["酒興何如畢吏部，詩情已過鮑參軍。", "醉吟自足了一世，肯羨飄飄出岫雲。"]'),
('fbd52471-e203-45d1-b1d5-715d155d7e1b','居仁報李季言論養生之益','劉子翬','宋','宋诗','song-poetry','','[]','平生外騖已知非，木枕藤衾老可依。',64,'全唐诗/poet.song.111000.json','["平生外騖已知非，木枕藤衾老可依。", "春半風光唯掩戶，病邊懷抱自忘機。", "不知靜守綿綿息，何似閒隨栩栩飛。", "欲寄勤渠問仙李，玄關底處是真歸。"]'),
('ca34d806-06fe-42f6-96f5-99a2d3874287','次居仁韵','劉子翬','宋','宋诗','song-poetry','','[]','是身如樹槁窮冬，一點心華自閉封。',64,'全唐诗/poet.song.111000.json','["是身如樹槁窮冬，一點心華自閉封。", "久矣吹噓存泛愛，偶於遲暮得相從。", "頗聞妙用縱橫是，深愧真源左右逢。", "白雪黄芽計雖下，可能無意起龍鍾。"]'),
('0f1a5353-b289-4805-bac0-607588e27c17','送致明之高沙三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','忽驚風袂去翻翻，老子吟毫强更援。',32,'全唐诗/poet.song.111000.json','["忽驚風袂去翻翻，老子吟毫强更援。", "底事幽懷却成惡，鵝峯一點入離樽。"]'),
('8f715c70-f3e2-4f41-b459-19194a5001a6','送致明之高沙三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','不夢清淮鬢欲凋，因君行色意飄飄。',32,'全唐诗/poet.song.111000.json','["不夢清淮鬢欲凋，因君行色意飄飄。", "鐵頭船子舊遊處，三尺霜鱗鏡面跳。"]'),
('ce06144d-af65-4cca-ac11-f0012cbe23b4','送致明之高沙三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','棠棣陰中更唱和，嘉賓助勇氣如雲。',32,'全唐诗/poet.song.111000.json','["棠棣陰中更唱和，嘉賓助勇氣如雲。", "勢孤屢欲拱降手，恐辱高沙小使君。"]'),
('234b05bd-091f-46a4-a2da-72e27801114c','次韵新鄉諸公雪詩二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','臘裏天公未得閒，重陰先殿晚來寒。',64,'全唐诗/poet.song.111000.json','["臘裏天公未得閒，重陰先殿晚來寒。", "數絲綽約流空際，一陳繽紛糝夜闌。", "已傍餘光窺蠹簡，更消清液試龍團。", "杜門自覺心神瑩，老去追隨只强歡。"]'),
('48e50a85-827a-4c86-a6ed-dc4901c8cef6','次韵新鄉諸公雪詩二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','貪行璀璨意無寒，不管飛花著鬢斑。',64,'全唐诗/poet.song.111000.json','["貪行璀璨意無寒，不管飛花著鬢斑。", "一段清光貽老境，十年勝覽在家山。", "遥知物外徜徉樂，肯放毫端造化閒。", "寸鐵不携當百戰，欲申前令愧辭艱。"]'),
('b4809b60-dd47-4d8e-a67b-77ef8b77b629','大年三月書來許訪敝廬繼聞阻雨已歸近聞復有來意以詩溫之','劉子翬','宋','宋诗','song-poetry','','[]','畫沙筆妙言猶在，折角巾欹興已窮。',64,'全唐诗/poet.song.111000.json','["畫沙筆妙言猶在，折角巾欹興已窮。", "不見此豪春色晚，至今遺恨雨聲中。", "詞華端是補天手，謔浪故存高世風。", "聞欲尋盟石峯下，人生能費幾枝筇。"]'),
('c97e2c30-05a2-468f-b2a6-b220f0937ccc','分茶公美子應預爲白曬之約','劉子翬','宋','宋诗','song-poetry','','[]','夢裏壺山尋二妙，不因荔子鬢絲華。',64,'全唐诗/poet.song.111000.json','["夢裏壺山尋二妙，不因荔子鬢絲華。", "聊分茗碗應年例，故有筠籠來海涯。", "鮮苞尚想妃子笑，槁面何取西施羓。", "老饞惟作耐久計，一瞬紅紫真空花。"]'),
('7fe297ad-7a4c-4b07-a411-ed052c58f457','奇仲德華第二轉語皆有旨趣致中乃謂僕操兩可於其間戲成長句','劉子翬','宋','宋诗','song-poetry','','[]','不可無詩絕盍簪，雜然嘲玩寄嘉音。',64,'全唐诗/poet.song.111000.json','["不可無詩絕盍簪，雜然嘲玩寄嘉音。", "唯阿似是摸稜手，虛靜初無照物心。", "蓮蕩遠陰波面合，堇峯橫翠雨中深。", "頗能逐勝此來否，一笑又成梁甫吟。"]'),
('39f1519d-de0d-49f9-b07d-7b0a7395cada','寄致中因溫前約','劉子翬','宋','宋诗','song-poetry','','[]','故山歸路豈云賒，憶對春風餞物華。',64,'全唐诗/poet.song.111000.json','["故山歸路豈云賒，憶對春風餞物華。", "尚口乃窮憐反舌，以年當廢惜殘花。", "勤渠載酒傳非誤，倉卒回輿事偶差。", "今日重來綠槐夏，已拚纈面醉君家。"]'),
('1098b3d6-71fb-4da6-82be-558f0890ad21','原仲紅釀甚佳嘗有十壺之約小詩發一笑','劉子翬','宋','宋诗','song-poetry','','[]','廣文挾書門戶閉，廣文置書尊罍開。',64,'全唐诗/poet.song.111000.json','["廣文挾書門戶閉，廣文置書尊罍開。", "但欣引人著勝地，豈暇問客從何來。", "走浪畦風初綠稻，屑塵村雨欲黄梅。", "十泓琥珀今餘幾，壘塊非澆不可摧。"]'),
('3f6c126f-68d5-49ce-949a-94dd3ab8ee52','居仁與季言論養生方往叩之而原仲詩有金花充膆之語乃知致中妙用如此近捨皇甫遠取居易豈不迂耶以詩請事','劉子翬','宋','宋诗','song-poetry','','[]','紫微談道渺無津，逸步飄然歎絕塵。',64,'全唐诗/poet.song.111000.json','["紫微談道渺無津，逸步飄然歎絕塵。", "但向函關迎老子，不知鄭圃有真人。", "數絲雪髮神彌瑩，一點金花意自春。", "莫謂余衰難語此，胸中勇氣尚輪囷。"]'),
('db09c21c-aaab-494e-b055-a3195ebecc97','致中詩戲論詩棋酒輒次原韵','劉子翬','宋','宋诗','song-poetry','','[]','只應心醉六經醇，自是陶陶晉魏人。',64,'全唐诗/poet.song.111000.json','["只應心醉六經醇，自是陶陶晉魏人。", "每向幽居橫素榻，惟容我輩岸烏巾。", "毫端空有千題巧，枰上原無一著真。", "要得坦然懷抱穩，煩君澆潑乳泓春。"]'),
('3d48789c-80e2-4a37-a21a-7657d43c68c5','致中招原仲遊武夷','劉子翬','宋','宋诗','song-poetry','','[]','病暑冠裳與體忘，一廛幽僻得深藏。',64,'全唐诗/poet.song.111000.json','["病暑冠裳與體忘，一廛幽僻得深藏。", "微風時度澗光活，殘日忽無山氣凉。", "但想子綦方隠几，終慚南郭謾連牆。", "何時九曲尋幽事，船尾應須著漫郎。"]'),
('015d3b8c-64b1-4abc-83bf-05ef51912364','致中手談見知胡漳州而奇仲未有定論','劉子翬','宋','宋诗','song-poetry','','[]','了無勝負著胸中，三百枯棋破老慵。',64,'全唐诗/poet.song.111000.json','["了無勝負著胸中，三百枯棋破老慵。", "雲陳春收花脫樹，雹聲夜碎月銜峯。", "危機每憚張頤虎，窘步休誇獨眼龍。", "無復漳州賞新妙，只應公論付吾宗。"]'),
('195cfe93-51c0-463a-8e2a-cd8f4d1163bb','次韵茂元茉莉花詩二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','翠葉光如沃，冰葩淡不妝。',48,'全唐诗/poet.song.111000.json','["翠葉光如沃，冰葩淡不妝。", "一番秋早秀，徹日坐傍香。", "色照祇園靜，清回瘴海凉。", "儻堪紉作佩，老子欲浮湘。"]'),
('cb8e10be-d65b-4836-b630-876f0c4d14a6','次韵茂元茉莉花詩二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','三尺婆娑樹，千英一律妝。',48,'全唐诗/poet.song.111000.json','["三尺婆娑樹，千英一律妝。", "眼孤猶眩彩，鼻熟不知香。", "向月資清潤，承風發素凉。", "衆芳如不忌，移植近瀟湘。"]'),
('04c58177-0f95-4c38-b9bd-6e490952071c','同才仲入山有懷奇仲','劉子翬','宋','宋诗','song-poetry','','[]','客至那容懶，牽筇入翠蘿。',48,'全唐诗/poet.song.111000.json','["客至那容懶，牽筇入翠蘿。", "山光知雨過，野色見秋多。", "妙語時相奪，微吟只自哦。", "吹塤來獨晚，此日恨如何。"]'),
('b1120335-afb0-47c7-bb49-afff8ff0b796','寄行夫兼懷如愚珙','劉子翬','宋','宋诗','song-poetry','','[]','已把重陽菊，吟懷不爲秋。',48,'全唐诗/poet.song.111000.json','["已把重陽菊，吟懷不爲秋。", "江湖三俊遠，天地一翁愁。", "日近書來少，宵長夢不休。", "吳雲猶可望，時上堇峯頭。"]'),
('54ef72dd-05e6-46ce-b58e-9ed7835d253f','致中相拉遊武夷有六耳不同謀之語原仲和章意似未平也再次原韵','劉子翬','宋','宋诗','song-poetry','','[]','年衰漸涸玉池津，擬丐明窗一匕塵。',64,'全唐诗/poet.song.111000.json','["年衰漸涸玉池津，擬丐明窗一匕塵。", "底用趨風防六耳，須知對影已三人。", "高情政喜追靈運，飽學那容欠大春。", "右挈左提俱有頼，應憐懷抱久傾囷。"]'),
('4e90b31d-caad-41ed-8432-e4544f44c2fb','呂居仁挽詞三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','粹美元功畀，風流相國傳。',48,'全唐诗/poet.song.111000.json','["粹美元功畀，風流相國傳。", "有文光聖道，無物累心淵。", "侃侃常春氣，堂堂忽逝川。", "東萊一點秀，冥漠楚山邊。"]'),
('43b0e0fb-a3ec-4c11-96e7-3bcfd7a20228','呂居仁挽詞三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','皓首猶貪學，謙虛德益豐。',48,'全唐诗/poet.song.111000.json','["皓首猶貪學，謙虛德益豐。", "潛神無朕際，悟物不言中。", "雖處持荷貴，常安捽茹窮。", "笑談驚委蛻，儒事有英雄。"]'),
('1116ed3f-2b01-48d8-ad61-7baa8faea5d4','呂居仁挽詞三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','江左欣初見，傾輸便豁然。',48,'全唐诗/poet.song.111000.json','["江左欣初見，傾輸便豁然。", "挽留嘗一粥，契闊已三年。", "老去無新得，書來每自鞭。", "幽明雖永絕，凜若在吾前。"]'),
('bcdf220d-e99d-424f-9bd2-f017d1eb2f7c','奇仲和致中棋詩有玄中一著是吾宗之句','劉子翬','宋','宋诗','song-poetry','','[]','局上深機未足窮，玄中一著若爲通。',64,'全唐诗/poet.song.111000.json','["局上深機未足窮，玄中一著若爲通。", "五宗惟明不是物，三語孰解將無同。", "常恨老懷多憒憒，每逢益友太匆匆。", "金篦刮眼寧無頼，况是牆西有德公。"]'),
('c10aadfb-5c68-4cb7-ae26-4bb50df97aef','奇仲和詩有吸盡西江說是公之句','劉子翬','宋','宋诗','song-poetry','','[]','南鄰袖手只如愚，東里談玄亦甚都。',64,'全唐诗/poet.song.111000.json','["南鄰袖手只如愚，東里談玄亦甚都。", "可是據鞍方矍鑠，須防鬻璞得盧胡。", "春空潮響來何自，秋浦天容落欲無。", "萬古西江只如許，何煩呼吸費工夫。"]'),
('d2034981-d9dc-40b8-9104-7d3382113b3c','吳公路作功德院記成同居安入山書丹','劉子翬','宋','宋诗','song-poetry','','[]','浄坊疏寵自吾君，盍有豐碑載策勳。',64,'全唐诗/poet.song.111000.json','["浄坊疏寵自吾君，盍有豐碑載策勳。", "方見隳崖礱翠琰，忽驚落筆散彤雲。", "言言未索西山氣，噩噩新摛左氏文。", "從此拱辰非厚夜，月明鐘鼓九霄聞。"]'),
('66381d49-681f-4af8-ac30-c54b45b1abba','子靜閲僕舊舉子文有詩因次原韵','劉子翬','宋','宋诗','song-poetry','','[]','雪縠烏紗氣似雲，摇毫不瞬已成文。',64,'全唐诗/poet.song.111000.json','["雪縠烏紗氣似雲，摇毫不瞬已成文。", "兒時追逐無三捷，老去荒唐更十分。", "木裏液樠將底用，韶邊朋肯豈堪聞。", "却慚鋟板能流惡，一付焚如政頼君。"]'),
('88a37431-8b15-47fc-bd51-84d3633ea86f','寄秀峰忠老','劉子翬','宋','宋诗','song-poetry','','[]','高鐘號月掩巖扉，遥想幽人不夢時。',64,'全唐诗/poet.song.111000.json','["高鐘號月掩巖扉，遥想幽人不夢時。", "曾聽微言知見妙，應憐懶我用功遲。", "幘疏種種寧相貸，窗靜山山尚可疑。", "儻有一單容過客，眼中須接秀峰奇。"]'),
('98a958ae-7d9c-44b9-a77e-c957e098badb','轉秩奉祠蒙朝佐子靜慶以四六戲裁長句爲謝','劉子翬','宋','宋诗','song-poetry','','[]','一嶺無情阻面談，鳴翰忽墮得雙函。',64,'全唐诗/poet.song.111000.json','["一嶺無情阻面談，鳴翰忽墮得雙函。", "抽黄對白雖云妙，刻朽噓枯祇益慚。", "小轉只緣官带右，雄飛無復夢圖南。", "借留頼有天台侶，老矣真成七不堪。"]'),
('bcfbd66f-239b-4ac6-84a5-94f65eba0cc0','致明贈茯苓如嬰孩狀以詩爲報','劉子翬','宋','宋诗','song-poetry','','[]','老松寒不死，密壤聚流脂。',48,'全唐诗/poet.song.111000.json','["老松寒不死，密壤聚流脂。", "小斸凌蒼翠，深藏發怪奇。", "應憐霜鬢客，爲寄玉嬰兒。", "屑餌消殘疢，同尋汗漫期。"]'),
('d504d4b4-3ad5-4bb1-8029-ceda5621efe7','次翁來借諸家易解聞已有新說以詩借觀','劉子翬','宋','宋诗','song-poetry','','[]','天庭吐氣作青紅，警邏猶煩小試中。',64,'全唐诗/poet.song.111000.json','["天庭吐氣作青紅，警邏猶煩小試中。", "政使著鞭無暇日，惟應讀易有清風。", "晝評一卦紛然異，夜夢三爻廓爾通。", "聞說新箋極玄妙，可無殘剩到衰翁。"]'),
('ae40e0a1-989f-40ca-8774-028704146eda','寄子靜','劉子翬','宋','宋诗','song-poetry','','[]','有約來何晚，行吟遡遠風。',48,'全唐诗/poet.song.111000.json','["有約來何晚，行吟遡遠風。", "老懷清似水，雙鬢亂如蓬。", "晤語非無得，疏慵政畧同。", "秋來湖上集，只是欠單公。"]'),
('43fbe2c0-a152-4073-a883-97afb04139a2','夢如愚珙','劉子翬','宋','宋诗','song-poetry','','[]','驚破池塘夢，宵長不再眠。',48,'全唐诗/poet.song.111000.json','["驚破池塘夢，宵長不再眠。", "寒聲摇谷口，側月到床邊。", "一自芝蘭遠，都無翰墨傳。", "老懷安得寫，孤詠不成篇。"]'),
('72e2db3a-a98f-4fda-aaee-7b8eebad6209','食鵝梨三首  其一','劉子翬','宋','宋诗','song-poetry','','[]','寒烽夜滅楚淮長，客舸輕摇度碧光。',32,'全唐诗/poet.song.111000.json','["寒烽夜滅楚淮長，客舸輕摇度碧光。", "北果初來珍重意，層層般紙透清香。"]'),
('850b0e40-dc13-4bb9-9cbd-65712557df75','食鵝梨三首  其二','劉子翬','宋','宋诗','song-poetry','','[]','拂拂鵝黄初借色，涓涓蜜醴爲輸津。',32,'全唐诗/poet.song.111000.json','["拂拂鵝黄初借色，涓涓蜜醴爲輸津。", "泠然一滌心淵浄，熱惱無因著莫人。"]'),
('6b91392f-35b7-481b-a42e-f66f59d7f5ad','食鵝梨三首  其三','劉子翬','宋','宋诗','song-poetry','','[]','琱盤一卵寧論價，新带中原雨露來。',32,'全唐诗/poet.song.111000.json','["琱盤一卵寧論價，新带中原雨露來。", "却憶春行梁宋野，雪花瓊蕊數程開。"]'),
('11c538b2-c4aa-4b5e-94ae-d4e8a06f4c12','次李巽伯韵','劉子翬','宋','宋诗','song-poetry','','[]','蠟封泥印了不勤，索居十載常念羣。',64,'全唐诗/poet.song.111000.json','["蠟封泥印了不勤，索居十載常念羣。", "戀鄉寧飲建溪水，懷友忽夢龜山雲。", "閒中意度不沾俗，老去詞華全付君。", "阿戎來歸得新語，戲筆報謝非誇文。"]'),
('c440c30c-2ebc-4bd9-aa52-1c6a73624754','送暐侍者之湖南','劉子翬','宋','宋诗','song-poetry','','[]','茗碗深澆破別愁，摻裾猶得小遲留。',64,'全唐诗/poet.song.111000.json','["茗碗深澆破別愁，摻裾猶得小遲留。", "不將流落遇知己，故向艱難作遠遊。", "春動閩山迎兩屐，夜凉楚月趁孤舟。", "相逢應說龐翁笑，黑頞黄髯萬念休。"]'),
('e5a2c01a-f2c9-41f3-a713-8ae996ddca91','次六四叔青字韵','劉子翬','宋','宋诗','song-poetry','','[]','寫出吳中勝，平生歷歷經。',48,'全唐诗/poet.song.111000.json','["寫出吳中勝，平生歷歷經。", "露窺烟渚靜，山入柁樓青。", "老氣何由逸，奔暉不肯停。", "北潭摇夢否，淥面照軒櫺。"]'),
('bdde86f1-975a-4ead-84e5-8e0bd033d167','題慎儀餘清閣','劉子翬','宋','宋诗','song-poetry','','[]','並溪取次得奇觀，更舞新甍翠木端。',64,'全唐诗/poet.song.111000.json','["並溪取次得奇觀，更舞新甍翠木端。", "政喜閒身時可到，忽驚醉眼晚來寬。", "故添山色浮嵐潤，不逐湍流獨月寒。", "散帙南窗更清絕，興來直欲跨飛翰。"]'),
('02ec3973-5279-446a-9266-e833ac13f7e4','春興','劉子翬','宋','宋诗','song-poetry','','[]','弱淥才勝舫，危青更著樓。',48,'全唐诗/poet.song.111000.json','["弱淥才勝舫，危青更著樓。", "管弦非老伴，風雨定花讎。", "兀坐還無味，微行却自由。", "只嫌詩作祟，呫呫不能休。"]'),
('a90b24aa-9f42-4591-8b91-f6c7cfc0768d','時中良弼茂元慎儀集水閣','劉子翬','宋','宋诗','song-poetry','','[]','水色兼山影，漂摇小閣西。',48,'全唐诗/poet.song.111000.json','["水色兼山影，漂摇小閣西。", "風來幽囀活，雨過萬紅低。", "烱烱杯中趣，喧喧枕裏迷。", "新年一聲笑，四友在潭溪。"]'),
('9bf654a6-b6d7-43a3-8076-521343ad6eaa','致中晚集','劉子翬','宋','宋诗','song-poetry','','[]','笑語北潭晚，微寒入綺疏。',48,'全唐诗/poet.song.111000.json','["笑語北潭晚，微寒入綺疏。", "雨聲留篆霧，燈影躍潛魚。", "病間欲疏酒，老便惟讀書。", "喜君新隠地，山翠切吾廬。"]'),
('7fa9c7f4-6c37-4a01-a427-18d218857386','酴醿四首  其一','劉子翬','宋','宋诗','song-poetry','','[]','蒙籠春幰頂，夭矯赤虬身。',24,'全唐诗/poet.song.111000.json','["蒙籠春幰頂，夭矯赤虬身。", "雨蓓猶緘暖，精神照晚春。"]'),
('56a3d41d-4905-46ad-be93-184545e51647','酴醿四首  其二','劉子翬','宋','宋诗','song-poetry','','[]','斑斑心點紫，疊疊萼承冰。',24,'全唐诗/poet.song.111000.json','["斑斑心點紫，疊疊萼承冰。", "除却橫枝韵，羣芳盡與能。"]'),
('1faa4bf2-1ff9-4111-977d-dd89cfff5204','酴醿四首  其三','劉子翬','宋','宋诗','song-poetry','','[]','獨立幽亭晚，春風玉一圍。',24,'全唐诗/poet.song.111000.json','["獨立幽亭晚，春風玉一圍。", "殘英不著地，去作嶺雲飛。"]'),
('62eab626-fe0f-4c14-8d04-84107fdf68dd','酴醿四首  其四','劉子翬','宋','宋诗','song-poetry','','[]','霜蕤薰碧醥，氣味已相傳。',24,'全唐诗/poet.song.111000.json','["霜蕤薰碧醥，氣味已相傳。", "終以香爲累，無人解倒懸。"]'),
('c32c78c2-7aa3-4df0-9166-80a0d22b48ed','寄張子平','劉子翬','宋','宋诗','song-poetry','','[]','老矣張平子，飄零客此州。',48,'全唐诗/poet.song.111000.json','["老矣張平子，飄零客此州。", "清樽如有伴，白髮不知愁。", "雨燕捎簾入，風花擁檻浮。", "夢中家在否，歸興莫悠悠。"]'),
('4e7df1ee-887b-476d-b992-39d03b5a8a1a','次明仲凉字韵','劉子翬','宋','宋诗','song-poetry','','[]','浮暑熏人只欲狂，秋聲未肯抹橫塘。',64,'全唐诗/poet.song.111000.json','["浮暑熏人只欲狂，秋聲未肯抹橫塘。", "倦看黄嬭渾無味，醉著白綀如許凉。", "掃砌政須脩竹舞，蔭花絕愛巨荷張。", "紫髯不是輕風景，更擬回鞭向葛强。"]'),
('f2d14ecf-99b3-4f2a-bde1-470f3f8cb81d','晚飲','劉子翬','宋','宋诗','song-poetry','','[]','招提聊駐屐，却去白雲堆。',48,'全唐诗/poet.song.111000.json','["招提聊駐屐，却去白雲堆。", "老眼看山倦，餘懷向酒開。", "晚凉微雨送，秋意一蟬催。", "醉裏揮犀妙，方知有逸才。"]'),
('db01afd9-b6ab-4eab-89eb-314f41b7b32c','次韵長汀壁間韵','劉子翬','宋','宋诗','song-poetry','','[]','竄鼠驚殘夢，蕭蕭老屋虛。',48,'全唐诗/poet.song.111000.json','["竄鼠驚殘夢，蕭蕭老屋虛。", "風聲傳遠瀨，寒意入秋蔬。", "客路漂摇久，歸身憔悴餘。", "西窗滿殘照，彷彿似吾廬。"]'),
('ab8748b4-45fd-41c2-8d13-b27a0042df1c','問明仲遊武夷日','劉子翬','宋','宋诗','song-poetry','','[]','兀兀聽凉雨，開門雪漲川。',48,'全唐诗/poet.song.111000.json','["兀兀聽凉雨，開門雪漲川。", "獨行楓葉底，秋興雁行邊。", "老去無多事，閒知有勝緣。", "何時縱仙舸，我亦願周旋。"]'),
('113cd643-9c70-449f-94a3-db74ef256198','次韵文殊五言','劉子翬','宋','宋诗','song-poetry','','[]','小雨貽新句，端如印印泥。',48,'全唐诗/poet.song.111000.json','["小雨貽新句，端如印印泥。", "凝眸方過鳥，倚杖忽橫溪。", "老態猶堪强，真豪已覺低。", "鐘聲隔林寺，慚愧有幽棲。"]'),
('bb44ec10-bda9-466c-8f40-d6968ad07928','次韵梔坑七言','劉子翬','宋','宋诗','song-poetry','','[]','酒香渾若過新豐，心事悠悠冷笑中。',64,'全唐诗/poet.song.111000.json','["酒香渾若過新豐，心事悠悠冷笑中。", "徹夜道傍梔葉雨，幾年馬上桂枝風。", "高情未許愁能挽，歸意惟應夢可通。", "準擬今秋剩追逐，暗泉鏘佩月潭東。"]'),
('7c909434-cbef-4daa-a139-1b18bd4fd565','次韵明仲幽居春來十首  其一','劉子翬','宋','宋诗','song-poetry','','[]','醉毫叵我落烏絲，况是桃源乍入時。',32,'全唐诗/poet.song.111000.json','["醉毫叵我落烏絲，况是桃源乍入時。", "祇恐昇平要華藻，賜牋春動萬年枝。"]'),
('5e25b07c-db45-444b-bee5-0549a3623315','次韵明仲幽居春來十首  其二','劉子翬','宋','宋诗','song-poetry','','[]','幽居十絕巧凌春，我亦刳腸强效顰。',32,'全唐诗/poet.song.111000.json','["幽居十絕巧凌春，我亦刳腸强效顰。", "憂樂懸知不同調，山南山北寂寥人。"]'),
('233fb099-1ca4-4206-af73-acd620c54978','次韵明仲幽居春來十首  其三','劉子翬','宋','宋诗','song-poetry','','[]','一幅烏巾雪髮盈，村深時聽鵽刀聲。',32,'全唐诗/poet.song.111000.json','["一幅烏巾雪髮盈，村深時聽鵽刀聲。", "浪將蘭艾評春事，我自平生小屈平。"]'),
('2afdd009-8533-40cc-a33c-192b33c7d3e0','次韵明仲幽居春來十首  其四','劉子翬','宋','宋诗','song-poetry','','[]','歸來十六見新元，種得黄楠繞舊村。',32,'全唐诗/poet.song.111000.json','["歸來十六見新元，種得黄楠繞舊村。", "豈是翛然便遺物，吾衰不復夢修門。"]'),
('a27e9151-a723-4193-9a15-ea4e26e97b71','次韵明仲幽居春來十首  其五','劉子翬','宋','宋诗','song-poetry','','[]','蒲團宴坐若還家，羅縠如空了不遮。',32,'全唐诗/poet.song.111000.json','["蒲團宴坐若還家，羅縠如空了不遮。", "可是春風摇得我，蘭芳輕噀淡黄芽。"]'),
('404398d0-c73b-41d1-b22f-d379a6406edf','次韵明仲幽居春來十首  其六','劉子翬','宋','宋诗','song-poetry','','[]','莫遣瀟湘雙鯉來，歸心生怕曉禽催。',32,'全唐诗/poet.song.111000.json','["莫遣瀟湘雙鯉來，歸心生怕曉禽催。", "咄嗟新轉渠渠屋，寒士懽顔正爾開。"]'),
('2d28714b-eb46-4e2e-93b7-f56661b53770','次韵明仲幽居春來十首  其七','劉子翬','宋','宋诗','song-poetry','','[]','䠞䠞鳴山筇一枝，逢春聊復詠歌之。',32,'全唐诗/poet.song.111000.json','["䠞䠞鳴山筇一枝，逢春聊復詠歌之。", "故園風光本具足，浪蕊浮花莫作迷。"]'),
('36da4616-14bd-4c51-a1dd-5adbac82ad81','次韵明仲幽居春來十首  其八','劉子翬','宋','宋诗','song-poetry','','[]','蓬鬆衰髮倦重簪，一榻惟便獨寢甘。',32,'全唐诗/poet.song.111000.json','["蓬鬆衰髮倦重簪，一榻惟便獨寢甘。", "却憶少陵詩句好，依然雲木曉相參。"]'),
('0372ed28-f8ce-45d3-b67a-1cac7268b839','次韵明仲幽居春來十首  其九','劉子翬','宋','宋诗','song-poetry','','[]','近鄰分得續隨栽，準擬新晴手自培。',32,'全唐诗/poet.song.111000.json','["近鄰分得續隨栽，準擬新晴手自培。", "不奈餘寒侵病骨，耡耰無味却歸來。"]'),
('ccf9f0fa-2726-4551-b85e-bc3c06c146b3','次韵明仲幽居春來十首  其一○','劉子翬','宋','宋诗','song-poetry','','[]','豈慚辛苦把漁竿，猶有機心傍釣灘。',32,'全唐诗/poet.song.111000.json','["豈慚辛苦把漁竿，猶有機心傍釣灘。", "文定書堂最深穩，何如袖手試觀瀾。"]'),
('4f9c6d79-6bf8-49ff-b81c-5a0461541441','次韵六四叔村居即事十二絕  其一','劉子翬','宋','宋诗','song-poetry','','[]','桃花偏傍謫仙居，點綴高岩今幾株。',32,'全唐诗/poet.song.111000.json','["桃花偏傍謫仙居，點綴高岩今幾株。", "力士鐺邊欠何物，著鞭跨馬是狂圖。"]'),
('7ee5702d-62ff-4a5e-8080-da313174d97b','次韵六四叔村居即事十二絕  其二','劉子翬','宋','宋诗','song-poetry','','[]','飯了呼童疊石門，雨餘幽事不勝繁。',32,'全唐诗/poet.song.111000.json','["飯了呼童疊石門，雨餘幽事不勝繁。", "花殘不用深惆悵，梧竹新陰又滿園。"]'),
('5a003405-ee9c-4ceb-989c-6e70b6cc3dbf','次韵六四叔村居即事十二絕  其三','劉子翬','宋','宋诗','song-poetry','','[]','偶隨流水到僧家，身世渾如焦穀芽。',32,'全唐诗/poet.song.111000.json','["偶隨流水到僧家，身世渾如焦穀芽。", "午夢不知緣底破，篆烟燒遍一盤花。"]'),
('48cf8f27-0a12-4d62-81fe-c73c8ca4803a','次韵六四叔村居即事十二絕  其四','劉子翬','宋','宋诗','song-poetry','','[]','聞道清湖別有春，花邊玉笋想長身。',32,'全唐诗/poet.song.111000.json','["聞道清湖別有春，花邊玉笋想長身。", "怪來幾日詩筒少，盡寫瑰奇賦洛神。"]'),
('9abb106c-6a44-41fc-b935-5e23586b936c','次韵六四叔村居即事十二絕  其五','劉子翬','宋','宋诗','song-poetry','','[]','潭邊春水碧於苔，爲聽泠泠溪畔來。',32,'全唐诗/poet.song.111000.json','["潭邊春水碧於苔，爲聽泠泠溪畔來。", "不耐顛風阻人興，漁舟欲上又吹開。"]'),
('8bcadc99-8b07-4348-b00f-d9a1b420234f','次韵六四叔村居即事十二絕  其六','劉子翬','宋','宋诗','song-poetry','','[]','蠲病惟應一日晴，小窗螢度暗還明。',32,'全唐诗/poet.song.111000.json','["蠲病惟應一日晴，小窗螢度暗還明。", "韋編讀罷聞幽鳥，演出精微是此聲。"]'),
('74f77346-bdb8-4b95-a8e4-d7c6e3f54d27','次韵六四叔村居即事十二絕  其七','劉子翬','宋','宋诗','song-poetry','','[]','酒惡時來漱淺谿，玉池汩汩自生肥。',32,'全唐诗/poet.song.111000.json','["酒惡時來漱淺谿，玉池汩汩自生肥。", "遊鯈豈解吾曹意，聊復蓬頭坐釣磯。"]'),
('ca082fde-183d-40fb-8298-2f773ce1dde1','次韵六四叔村居即事十二絕  其八','劉子翬','宋','宋诗','song-poetry','','[]','春來太半在農疇，邂逅相逢皆飲流。',32,'全唐诗/poet.song.111000.json','["春來太半在農疇，邂逅相逢皆飲流。", "貪看暮烟馳萬柳，不知明月上前洲。"]'),
('e5a10755-d7b8-4a7c-9e2d-bbd4143fdbac','次韵六四叔村居即事十二絕  其九','劉子翬','宋','宋诗','song-poetry','','[]','庾郎食事惟三九，適口方知味味珍。',32,'全唐诗/poet.song.111000.json','["庾郎食事惟三九，適口方知味味珍。", "擬欲招邀無此客，虎頭不是箇中人。"]'),
('46f3761c-d2d5-4c44-9381-290006ba1dd2','次韵六四叔村居即事十二絕  其一○','劉子翬','宋','宋诗','song-poetry','','[]','遼鶴歸來本姓丁，咿啞幾見弄文䙀。',32,'全唐诗/poet.song.111000.json','["遼鶴歸來本姓丁，咿啞幾見弄文䙀。", "人間過眼事如許，何用封侯羨戛羹。"]'),
('1a414fcb-4ed7-4161-aeeb-732c075e0a5b','次韵六四叔村居即事十二絕  其一一','劉子翬','宋','宋诗','song-poetry','','[]','屋角仙洲入眼明，清風澡滌醉魂醒。',32,'全唐诗/poet.song.111000.json','["屋角仙洲入眼明，清風澡滌醉魂醒。", "麻姑未必堪搔背，薄相由來是蔡經。"]'),
('b8cea17e-2581-43eb-8213-d71e38596fba','次韵六四叔村居即事十二絕  其一二','劉子翬','宋','宋诗','song-poetry','','[]','幾許椎埋盡把耡，而今戶戶偃犀渠。',32,'全唐诗/poet.song.111000.json','["幾許椎埋盡把耡，而今戶戶偃犀渠。", "太平無象從何見，一夜春風長碧蔬。"]'),
('9790ff3b-4f3e-46ef-aa42-f5e126b2d3da','凝雲堂詩次文賀州韵','劉子翬','宋','宋诗','song-poetry','','[]','君家遥借我家山，我亦時來一笑看。',64,'全唐诗/poet.song.111000.json','["君家遥借我家山，我亦時來一笑看。", "縹緲雲扶千疊秀，空濛翠滴兩州寒。", "已將老目供秋晚，未覺豪心怯酒闌。", "文伯詩無飄泊歎，盡將幽抱付遐觀。"]'),
('8db2ee78-9b05-43ac-a204-a948e6c9f181','次明仲勤字韵','劉子翬','宋','宋诗','song-poetry','','[]','苦無聊頼憶披雲，曳杖寧知四體勤。',64,'全唐诗/poet.song.111000.json','["苦無聊頼憶披雲，曳杖寧知四體勤。", "握手便成忘適適，縱談終愧自聞聞。", "浮蛆釀熟貽彭澤，斫鱠圖成想右軍。", "莫爲冷風發歸興，石峯秋月許平分。"]'),
('4b4d82a6-f35e-4511-925b-351a91221b25','次韵明仲贈六四叔之作','劉子翬','宋','宋诗','song-poetry','','[]','平生一笑輕離別，林下相從各壯年。',64,'全唐诗/poet.song.111000.json','["平生一笑輕離別，林下相從各壯年。", "絕愛步兵胸壘塊，更欣阿大語蟬連。", "杖藜只作尋常出，巵酒何辭一再傳。", "燕頷虎頭經賞識，定應接武向甘泉。"]'),
('e0fd5ef7-16b6-42ea-b12d-d69430fb0887','次六四叔韵','劉子翬','宋','宋诗','song-poetry','','[]','筍輿霑汗每蒼黄，今日追隨得快凉。',64,'全唐诗/poet.song.111000.json','["筍輿霑汗每蒼黄，今日追隨得快凉。", "水落不知沙徑改，風微如靳橘林香。", "我緣新病仍添懶，君不時來有底忙。", "只恐家山誚人去，十年秋興在殊方。"]'),
('0cf513f7-5fde-4ab6-bfcb-bc55a44c870c','祝道人日供梅蘭偶成小詩二首  其一','劉子翬','宋','宋诗','song-poetry','','[]','病眼亡聊祇强回，道人得得供新梅。',32,'全唐诗/poet.song.111000.json','["病眼亡聊祇强回，道人得得供新梅。", "谷寒未必春先到，幾夜冰蟾照得開。"]'),
('eb941c43-31e1-45be-b018-9645f99548ca','祝道人日供梅蘭偶成小詩二首  其二','劉子翬','宋','宋诗','song-poetry','','[]','野客分花入戶間，此心今合付翛然。',32,'全唐诗/poet.song.111000.json','["野客分花入戶間，此心今合付翛然。", "平生費盡金鴉嘴，不負幽芳十七年。"]'),
('b046f9e0-3f25-4946-a974-eaa5a4ace650','梅詩呈六四叔','劉子翬','宋','宋诗','song-poetry','','[]','一枝新白破長林，定想霜毫落有神。',32,'全唐诗/poet.song.111000.json','["一枝新白破長林，定想霜毫落有神。", "䠥𨇨若予將底用，猶堪卧護北潭春。"]'),
('9f9bb0fd-c3f2-4b35-a420-c97b336fb42e','寄致明并紀惠雁觀梅之舊','劉子翬','宋','宋诗','song-poetry','','[]','稚劉於我最多情，此日詩筒不絕聲。',64,'全唐诗/poet.song.111000.json','["稚劉於我最多情，此日詩筒不絕聲。", "孤雁相依真得地，早梅一粲又傾城。", "向來蘭好知誰許，病後霜林懶獨行。", "小几清香慰臨別，極知了了萬緣輕。"]'),
('2feb07ce-20c5-498f-9239-7a74a4740f54','拙句謝伯達老友','劉子翬','宋','宋诗','song-poetry','','[]','贈梅發言吾過矣，衛生無術誰之尤。',32,'全唐诗/poet.song.111000.json','["贈梅發言吾過矣，衛生無術誰之尤。", "魯兀游心聊自遣，樂春舉足豈無憂。"]'),
('5303baa4-8006-4cd0-b4ab-ae746b98c21c','次韵上梅嶺','劉子翬','宋','宋诗','song-poetry','','[]','鞭粳紅入臼，剪菜玉登盤。',48,'全唐诗/poet.song.111000.json','["鞭粳紅入臼，剪菜玉登盤。", "是處喜相挽，我來如許難。", "沙清才㶁㶁，陟翠入磻磻。", "勃窣乾坤裏，伊誰不自安。"]'),
('86c77a9c-b6d7-4675-8d1b-6844a25e601d','江上寺','劉子翬','宋','宋诗','song-poetry','','[]','東岸樓臺西岸山，瀟湘一片在中間。',32,'全唐诗/poet.song.111000.json','["東岸樓臺西岸山，瀟湘一片在中間。", "紅塵不到滄波上，僧與白雲相對閑。"]'),
('c3034cf3-2248-4c72-853c-08e0477a19ac','題丞廳','劉子翬','宋','宋诗','song-poetry','','[]','暮年叢薄寄鷦鷯，搔首巡檐歲月銷。',32,'全唐诗/poet.song.111000.json','["暮年叢薄寄鷦鷯，搔首巡檐歲月銷。", "留與後人還要否，一軒松竹冷瀟瀟。"]'),
('a1cb3313-59b9-40ac-a7c7-8a0e95bd4ffe','館中簡張約齋','劉子翬','宋','宋诗','song-poetry','','[]','書生賦分合窮愁，官與休辰不肯休。',64,'全唐诗/poet.song.111000.json','["書生賦分合窮愁，官與休辰不肯休。", "清曉犯寒開省戶，誰家見雪似瀛洲。", "爛銀宮闕雲端見，素柰園林月下遊。", "說與南湖張祕閣，速來同直道山頭。"]'),
('7f3e7189-21b5-4d97-98af-5088ff973b10','送彭奭應禮部試','劉子翬','宋','宋诗','song-poetry','','[]','君家詩禮冠南區，文陣堂堂盡壯夫。',64,'全唐诗/poet.song.111000.json','["君家詩禮冠南區，文陣堂堂盡壯夫。", "漢傑姓名歸大族，周官事業屬吾儒。", "爭題玉字傳金榜，悉奮朱鸞與鳳雛。", "月桂香傳南北巷，千言長策耀天衢。"]'),
('0d84e5f1-4f67-43ee-a1fe-fb40e2a6cc90','桃源','劉子翬','宋','宋诗','song-poetry','','[]','桃花深處蜜蜂喧，山近前峰鷄犬村。',32,'全唐诗/poet.song.111000.json','["桃花深處蜜蜂喧，山近前峰鷄犬村。", "若有胡麻泛流水，武夷轉作武陵源。"]'),
('bc429ffa-271c-4d81-8253-aa1a3799c314','花椒','劉子翬','宋','宋诗','song-poetry','','[]','欣忻笑口向西風，噴出元珠顆顆同。',64,'全唐诗/poet.song.111000.json','["欣忻笑口向西風，噴出元珠顆顆同。", "採處倒含秋露白，晒時嬌映夕陽紅。", "調漿美著騷經上，涂壁香凝漢殿中。", "鼎餗也應知此味，莫教薑桂獨成功。"]'),
('092cccc1-e5b9-42ec-9104-97946f0b6230','和晁應之大暑書事','劉子翬','宋','宋诗','song-poetry','','[]','蓬門久閉謝來車，畏暑尤便小閣虛。',64,'全唐诗/poet.song.111000.json','["蓬門久閉謝來車，畏暑尤便小閣虛。", "青引嫩苔留鳥篆，綠垂殘葉带蟲書。", "寒泉出井功何有，白羽邀凉計已疏。", "忍待西風一蕭颯，碧鱸銀鱠意何如。"]'),
('a9a2b963-4e9e-495a-9a16-8907a12840fc','桐江弔子陵','詹慥','宋','宋诗','song-poetry','','[]','光武親從血戰回，舉朝誰識渭川才。',32,'全唐诗/poet.song.111000.json','["光武親從血戰回，舉朝誰識渭川才。", "羆熊果有周王卜，未必先生戀釣臺。"]'),
('adf6573a-45d5-4e43-960e-7865a94a1881','月夜','詹慥','宋','宋诗','song-poetry','','[]','平生最好月，况此秋夜闌。',132,'全唐诗/poet.song.111000.json','["平生最好月，况此秋夜闌。", "長風送蕩漾，浩露况團團。", "仰頭視虛空，光彩如可餐。", "星辰歛芒角，河漢收波瀾。", "更無微雲翳，挂此白玉盤。", "六合靜皎皎，萬木凉珊珊。", "爲爾廢昏卧，裴回更漏殘。", "更登高處坐，歷歷見湖山。", "爽氣集冰雪，清心生羽翰。", "便欲御泠然，因之遊廣寒。", "一臨天池水，沐浴隨飛仙。"]'),
('30a96abf-de18-4795-88a2-92f367d82d4e','上巳後一日登快哉亭','詹慥','宋','宋诗','song-poetry','','[]','上巳信嘉辰，流觴傳舊俗。',96,'全唐诗/poet.song.111000.json','["上巳信嘉辰，流觴傳舊俗。", "良遊悵不遂，吏局方有屬。", "東風吹曉雨，萬竅嗥林麓。", "疑有泊舟人，狂歌河女曲。", "逾朝始澄霽，物色如新沐。", "城角趨危亭，登臨慰幽獨。", "紛華埽不見，蝴蝶飛平綠。", "竚倚窮夕曛，悠哉此心目。"]'),
('3814ecdd-e329-4d54-86f8-d4a3c898cdcb','客談荆渚武昌慨然有作','詹慥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','去歲出蜀初東遊，峨舸大艑下荆州。',128,'全唐诗/poet.song.111000.json','["去歲出蜀初東遊，峨舸大艑下荆州。", "便風轉頭五百里，吟嘯已在黄鶴樓。", "戲拈鐵笛吹出塞，水湧月落魚龍愁。", "明朝喧傳古仙過，碧玉带來黄絁裘。", "豈知一官自桎梏，簿書期會無時休。", "豐城寶劍已化久，我自吐氣沖斗牛。", "洞庭四萬八千頃，蟹舍正對蘆花洲。", "速脫衣冠掛神武，散髮爛醉垂虹秋。"]'),
('c03d0d3c-35a9-4780-89ff-b5b3ffff376d','道中寒食','詹慥','宋','宋诗','song-poetry','','[]','斗粟淹吾駕，浮雲笑此生。',48,'全唐诗/poet.song.111000.json','["斗粟淹吾駕，浮雲笑此生。", "有詩酬歲月，無夢到功名。", "客裏逢歸雁，愁邊有亂鶑。", "楊花不解事，更作倚風輕。"]'),
('05366636-1ac3-40c0-86d4-61ee0ed29627','舟行遣興','詹慥','宋','宋诗','song-poetry','','[]','會稽尚隔三千里，臨賀初盤一百灘。',64,'全唐诗/poet.song.111000.json','["會稽尚隔三千里，臨賀初盤一百灘。", "殊俗問津言語異，長年爲客歧路難。", "背人山嶺重重去，照鷁梅花樹樹殘。", "酌酒柂樓今日意，題詩船壁後來看。"]'),
('1b7fe4ec-9b84-4a7d-b3e1-dfeb221ca19c','春懷示鄰里','詹慥','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u60dc\u6625", "\u751f\u6d3b", "\u5b8b\u8bd7"]','斷牆著雨蝸成字，老屋無僧燕作家。',64,'全唐诗/poet.song.111000.json','["斷牆著雨蝸成字，老屋無僧燕作家。", "剩欲出門追語笑，却嫌歸髩著塵沙。", "風翻蛛網開三面，雷動蜂窠趁兩衙。", "屢失南鄰春事約，只今容有未開花。"]'),
('aef08002-c8fa-439d-9983-52f6e1c59411','南浦','詹慥','宋','宋诗','song-poetry','','[]','南浦隨花去，迴舟路已迷。',24,'全唐诗/poet.song.111000.json','["南浦隨花去，迴舟路已迷。", "暗香無處覓，日落板橋西。"]'),
('b0494c14-1677-417e-ab51-21b4a0d67639','早行','詹慥','宋','宋诗','song-poetry','','[]','村鷄已報晨，曉月漸無色。',24,'全唐诗/poet.song.111000.json','["村鷄已報晨，曉月漸無色。", "行人馬上去，殘燈照空驛。"]'),
('a2b8d0ac-6a78-4e71-87c3-7e705d62329c','寄胡籍溪','詹慥','宋','宋诗','song-poetry','','[]','雨過溪頭鳥篆沙，溪山深處野人家。',32,'全唐诗/poet.song.111000.json','["雨過溪頭鳥篆沙，溪山深處野人家。", "門前桃李都飛盡，又見春光到楝花。"]'),
('be6d8f84-2db2-4e64-b2c4-39b43e72cacb','渡湘江弔嚴子陵','詹慥','宋','宋诗','song-poetry','','[]','光武親征血戰回，舉朝誰識渭川才。',32,'全唐诗/poet.song.111000.json','["光武親征血戰回，舉朝誰識渭川才。", "熊羆果有周王卜，未必先生戀釣臺。"]'),
('0bcc297a-49d1-42bd-a302-7feccee73e2f','送笋與屏山','劉仲行','宋','宋诗','song-poetry','','[]','籜龍戢戢破苔斑，風味從來奈歲寒。',32,'全唐诗/poet.song.111000.json','["籜龍戢戢破苔斑，風味從來奈歲寒。", "知有高人清愛白，定應燒煮薦珠盤。"]'),
('c5b282c1-b78e-4bab-aa6b-4446bb6084df','句','周元仲','宋','宋诗','song-poetry','','[]','愁別園林後夜春。',8,'全唐诗/poet.song.111000.json','["愁別園林後夜春。"]'),
('7e1388bd-0cec-4485-81ac-903948ee0f51','句  其一','劉奇仲','宋','宋诗','song-poetry','','[]','玄中一著是吾宗。',8,'全唐诗/poet.song.111000.json','["玄中一著是吾宗。"]'),
('596e85fe-8bb0-452e-bf98-f8c33251c602','句  其二','劉奇仲','宋','宋诗','song-poetry','','[]','吸盡西江說是公。',8,'全唐诗/poet.song.111000.json','["吸盡西江說是公。"]'),
('45eda5a1-4d0b-4638-9b91-67a337e9c1f9','留題桐柏石道師妙聲堂次曾史君韵','石延慶','宋','宋诗','song-poetry','','[]','一派奔湍響迅雷，噴雲翻雪繞瓊臺。',32,'全唐诗/poet.song.111000.json','["一派奔湍響迅雷，噴雲翻雪繞瓊臺。", "應通天上銀潢路，準擬乘槎八月來。"]'),
('635e0abd-1def-4bfe-a0d3-3fe21e270a92','題鑑軒','石延慶','宋','宋诗','song-poetry','','[]','一軒曾揭鑑爲名，軒下方池徹底清。',64,'全唐诗/poet.song.111000.json','["一軒曾揭鑑爲名，軒下方池徹底清。", "坐客不須頻拂拭，主人猶恐太分明。", "一塵不染原無物，萬象俱涵豈有情。", "堪笑越湖三百里，等閑風浪不曾平。"]'),
('87423ede-fe45-46ae-af82-45397478a8cd','感秋','鍾離松','宋','宋诗','song-poetry','','[]','破壁亂蛩吟，愁添鬢雪侵。',48,'全唐诗/poet.song.111000.json','["破壁亂蛩吟，愁添鬢雪侵。", "凉生孤館夢，秋入旅人心。", "排遣難憑酒，淒清不在琴。", "中原戎馬躪，白露寢園深。"]'),
('489a3ef6-4172-4431-9981-a24158f3fa80','送舅氏王亨道知湖州','秦熺','宋','宋诗','song-poetry','','[]','暫別甘泉豹尾中，隼旟仍駐水晶宮。',64,'全唐诗/poet.song.111000.json','["暫別甘泉豹尾中，隼旟仍駐水晶宮。", "文昌地禁論思久，燕寢香凝簿領空。", "可但龔黄宜共理，使應顔謝與同風。", "飽聞回老榴皮字，試問溪頭鶴髮翁。"]'),
('cf8d9c41-0126-4422-8ecc-041cecd93d6f','遊茅山題華陽觀','秦熺','宋','宋诗','song-poetry','','[]','家山福地古云魁，一日三峰秀氣回。',32,'全唐诗/poet.song.111000.json','["家山福地古云魁，一日三峰秀氣回。", "會散寶珠何處去，碧巖南洞白雲堆。"]'),
('43e6d5c4-6a6a-4916-855a-385bea4320cf','句','秦熺','宋','宋诗','song-poetry','','[]','兢兢驕侈戒，誓不愧周官。',12,'全唐诗/poet.song.111000.json','["兢兢驕侈戒，誓不愧周官。"]'),
('0ce7620d-bb56-45b8-9928-371719deb46c','秦郵晚泊','王綸','宋','宋诗','song-poetry','','[]','水宿風餐第幾程，落帆剛趁晚霞明。',64,'全唐诗/poet.song.111000.json','["水宿風餐第幾程，落帆剛趁晚霞明。", "村醪小飲不成醉，明月推篷初欲生。", "自愧菲才膺閒命，誰能高卧閉柴荆。", "茫茫家國偏多感，靜聽漁榔斷續聲。"]'),
('bcb2656b-e257-4019-866c-bdc8e7641540','晚步','陳棠','宋','宋诗','song-poetry','','[]','晚步沙頭倚小晴，南山正與暮雲橫。',64,'全唐诗/poet.song.111000.json','["晚步沙頭倚小晴，南山正與暮雲橫。", "棲鴉啼處野煙合，飛鳥去邊孤月生。", "樹暗風微花氣度，溪深雨漲水痕平。", "夜闌衣溼迷歸路，彷彿前村燈火明。"]'),
('c3784b9e-4106-47e1-83db-144c85dc7f3a','早朝十絕  其一','趙子潚','宋','宋诗','song-poetry','','[]','門門閶闔早春初，恭遘龍飛御太虛。',32,'全唐诗/poet.song.111000.json','["門門閶闔早春初，恭遘龍飛御太虛。", "聖德巍巍隆譽望，坐令四海誦唐虞。"]'),
('c8651429-5624-498a-a6e9-5621342098b2','早朝十絕  其二','趙子潚','宋','宋诗','song-poetry','','[]','文德輝煌寶炬然，侍臣身染御爐煙。',32,'全唐诗/poet.song.111000.json','["文德輝煌寶炬然，侍臣身染御爐煙。", "丹心一點惟懷報，願祝皇圖億萬年。"]'),
('314c0c9e-e8c2-4cb3-8ca3-f6e476b81596','早朝十絕  其三','趙子潚','宋','宋诗','song-poetry','','[]','龍德當陽開泰運，凰樓南面御階平。',32,'全唐诗/poet.song.111000.json','["龍德當陽開泰運，凰樓南面御階平。", "恩波浩蕩寬如海，八彩重瞳仰聖明。"]'),
('ea96eeef-e629-406b-8f31-58e8a953006a','早朝十絕  其四','趙子潚','宋','宋诗','song-poetry','','[]','仰荷天恩雨露同，涓埃無地答宸衷。',32,'全唐诗/poet.song.111000.json','["仰荷天恩雨露同，涓埃無地答宸衷。", "侍朝惟秉忠和孝，遥見爐香上九重。"]'),
('a531b9e1-50ff-4402-90a7-067eb3770263','早朝十絕  其五','趙子潚','宋','宋诗','song-poetry','','[]','凰闕鐘聲曙色開，香飄瑞氣靄蓬萊。',32,'全唐诗/poet.song.111000.json','["凰闕鐘聲曙色開，香飄瑞氣靄蓬萊。", "侍臣鵠立班初合，齊進龍墀萬壽杯。"]'),
('69e2c4ba-9abf-4315-ae99-d601179a116a','早朝十絕  其六','趙子潚','宋','宋诗','song-poetry','','[]','北面高呼拜冕旒，星垂華渚彩虹浮。',32,'全唐诗/poet.song.111000.json','["北面高呼拜冕旒，星垂華渚彩虹浮。", "春風滿泛蒲萄酒，喜溢謳聲遍九州。"]'),
('adb1cc6e-19ba-44d2-900a-aab3903fa341','早朝十絕  其七','趙子潚','宋','宋诗','song-poetry','','[]','一天星斗燦晴霄，香爇沉檀瑞靄飄。',32,'全唐诗/poet.song.111000.json','["一天星斗燦晴霄，香爇沉檀瑞靄飄。", "環佩趨朝天闕曉，五雲重睹凰儀韶。"]'),
('ecef526a-16ad-4b61-9487-46514a5d37ae','早朝十絕  其八','趙子潚','宋','宋诗','song-poetry','','[]','象笏羅袍間綉衣，斑斕五采絢朝暉。',32,'全唐诗/poet.song.111000.json','["象笏羅袍間綉衣，斑斕五采絢朝暉。", "退朝擎出龍香篆，知是丹楓拜賜歸。"]'),
('e5a63ad8-fed8-450e-a79f-17d1df74b470','早朝十絕  其九','趙子潚','宋','宋诗','song-poetry','','[]','廿載承恩侍九重，泰階玉燭喜遭逢。',32,'全唐诗/poet.song.111000.json','["廿載承恩侍九重，泰階玉燭喜遭逢。", "嘉禾瑞協當年兆，竚看遠夷貢獻同。"]'),
('7cb1ccb4-b053-4386-a240-8f27d19a701b','早朝十絕  其一○','趙子潚','宋','宋诗','song-poetry','','[]','壯時瞻仰近龍顔，老尚簪纓侍從班。',32,'全唐诗/poet.song.111000.json','["壯時瞻仰近龍顔，老尚簪纓侍從班。", "戀闕敢辭筋力倦，銘心刻骨更輸丹。"]'),
('9eca4ef0-8ebb-4e6b-b1dc-871c4c8513d2','宰餘姚道詠上虞山水二首  其一','趙子潚','宋','宋诗','song-poetry','','[]','重華遺澤在東州，景物留奇聚勝遊。',32,'全唐诗/poet.song.111000.json','["重華遺澤在東州，景物留奇聚勝遊。", "翠濕金罍山獨秀，碧環玉带水交流。"]'),
('e1c18247-06f6-4352-868b-0adb0a788a92','宰餘姚道詠上虞山水二首  其二','趙子潚','宋','宋诗','song-poetry','','[]','山自南來崇地位，水從東去泳江流。',32,'全唐诗/poet.song.111000.json','["山自南來崇地位，水從東去泳江流。", "徘徊四顧情何限，直欲於中構小樓。"]'),
('20f5b78c-c518-4928-958f-e20ffccca3e8','題漫天坡  其一','郭奕','宋','宋诗','song-poetry','','[]','大漫天是小漫天，小漫天是大漫天。',32,'全唐诗/poet.song.111000.json','["大漫天是小漫天，小漫天是大漫天。", "只因大小漫天後，遂使生靈入四川。"]'),
('9ab4d716-76e6-4a32-9431-408afb80b258','題漫天坡  其二','郭奕','宋','宋诗','song-poetry','','[]','秦山未盡蜀山來，日照關門兩扇開。',32,'全唐诗/poet.song.111000.json','["秦山未盡蜀山來，日照關門兩扇開。", "刺史莫嫌迎候遠，相公新送陝西回。"]'),
('88a3a226-535d-4ab8-88f4-cbdfcb6d9081','詠張中孚兄弟','郭奕','宋','宋诗','song-poetry','','[]','張中孚，張中彥，江南塞北都行遍。',24,'全唐诗/poet.song.111000.json','["張中孚，張中彥，江南塞北都行遍。", "教我如何做列傳。"]'),
('33562f68-2f69-4b3c-8778-af41a59df341','建炎丞相成國呂忠穆公退老堂  其一','陳棠','宋','宋诗','song-poetry','','[]','黄閤雍容靜塞塵，淩煙功就便抽身。',64,'全唐诗/poet.song.111000.json','["黄閤雍容靜塞塵，淩煙功就便抽身。", "三年暫別長安日，五畝來追獨樂春。", "槐鼎政須還國老，谿山聊且慰騷人。", "似聞天語傳中使，行告廷臣設九賓。"]'),
('c3208e37-8a0a-4951-95ce-90ebf848fb0b','建炎丞相成國呂忠穆公退老堂  其二','陳棠','宋','宋诗','song-poetry','','[]','解組歸來萬事休，買茅初葺一堂幽。',64,'全唐诗/poet.song.111000.json','["解組歸來萬事休，買茅初葺一堂幽。", "綠筠曉月摇蒼珮，紅樹春風散綵斿。", "鷗鷺心情雖退志，麒麟圖畫尚追求。", "行看馳馹趨丹陛，趁取閒時秉燭遊。"]'),
('6451302a-0842-467c-8428-6f32b09b5667','登帢幘峰','陳棠','宋','宋诗','song-poetry','','[]','雲礙虛簷日，風號老木秋。',48,'全唐诗/poet.song.111000.json','["雲礙虛簷日，風號老木秋。", "山城圍晚翠，江檻俯寒流。", "世事悲蒼狗，生涯付白鷗。", "煙塵猶在眼，渾欲不勝愁。"]'),
('ad69baa0-d5d9-49da-83bc-a9960db3fba3','紀夢','涂楷','宋','宋诗','song-poetry','','[]','拜伏庭前又一番，天書雖捧未容看。',32,'全唐诗/poet.song.111000.json','["拜伏庭前又一番，天書雖捧未容看。", "南陽久作蟠龍卧，應爲蒼生起謝安。"]'),
('e636ace4-d849-44bf-94e3-db1c76aa7b90','題英州金山寺壁  其一','俞似','宋','宋诗','song-poetry','','[]','莫遣韝鷹飽一呼，將軍誰志滅匈奴。',32,'全唐诗/poet.song.111000.json','["莫遣韝鷹飽一呼，將軍誰志滅匈奴。", "年來萬事灰人意，只有看山眼不枯。"]'),
('1436f186-39d0-4b84-a2f1-709d06df770c','題英州金山寺壁  其二','俞似','宋','宋诗','song-poetry','','[]','轉食膠膠擾擾間，林泉高步未容攀。',32,'全唐诗/poet.song.111000.json','["轉食膠膠擾擾間，林泉高步未容攀。", "興來尚有平生履，管領東南到處山。"]'),
('21f27327-0502-42ef-9e0b-12933224eba8','題長洲張氏舍壁','莊綽','宋','宋诗','song-poetry','','[]','昔年隨牒佐邊侯，愁望長安向戍樓。',32,'全唐诗/poet.song.111000.json','["昔年隨牒佐邊侯，愁望長安向戍樓。", "今日衰頹來澤國，又看烽火照長洲。"]'),
('0eeac5c0-217b-4e4c-9a96-30aa1496bf53','和吳正仲觀李廷珪墨','莊綽','宋','宋诗','song-poetry','','[]','頼召陳玄典籍傳，肯教邊腹擅便便。',64,'全唐诗/poet.song.111000.json','["頼召陳玄典籍傳，肯教邊腹擅便便。", "竟誇削木真餘事，却笑磨人得永年。", "三友不居毛穎後，五車仍在褚生前。", "祇愁公子從醫說，火煅生分不直錢。"]'),
('a170e796-c504-4b6f-a662-3eca37b38639','建炎丞相成國呂忠穆公退老堂','莊綽','宋','宋诗','song-poetry','','[]','力辭富貴回天上，不事樓臺起宅中。',64,'全唐诗/poet.song.111000.json','["力辭富貴回天上，不事樓臺起宅中。", "問道但懷重舍蓋，對優甯興獨延崇。", "精神宛似初平蔡，信宿那應久在東。", "帝念中興思舊德，未容高枕北窗風。"]'),
('b8eed3c4-09b6-4ba3-a0a8-17a3f37eb048','詩一首','蘇緘','宋','宋诗','song-poetry','','[]','使君尊老致聃彭，躋彼公堂醉兕觥。',64,'全唐诗/poet.song.111000.json','["使君尊老致聃彭，躋彼公堂醉兕觥。", "祝饐俾觀新禮節，縱談猶說舊昇平。", "厖眉昔日商山皓，尚齒當年洛社英。", "盛事歡傳旴水上，賡歌歸羨屬儒生。"]'),
('aaaa453e-22d9-422f-a535-fb135c90fec0','送李按察之任','王之奇','宋','宋诗','song-poetry','','[]','先生持使節，極力救生民。',48,'全唐诗/poet.song.111000.json','["先生持使節，極力救生民。", "郡縣寧無弊，朝廷未有聞。", "某官貪可去，若事屈宜伸。", "更爲君王說，如今可用文。"]'),
('01f87ecb-db63-4e39-ae77-896388895a5f','句','王之奇','宋','宋诗','song-poetry','','[]','炳若丹青敷德義，後人於此取良規。',16,'全唐诗/poet.song.111000.json','["炳若丹青敷德義，後人於此取良規。"]'),
('8b8b9854-b74f-4a71-bd34-2c0bda7b1ae4','句','張紘','宋','宋诗','song-poetry','','[]','時見空中飛八百，每聞岸上叫三千。',16,'全唐诗/poet.song.111000.json','["時見空中飛八百，每聞岸上叫三千。"]'),
('5ebf31e7-70c5-493d-8eeb-38efa8150814','次鄭大資競渡詩韵','蓋諒','宋','宋诗','song-poetry','','[]','昔年冶遊浚都城，溶溶春水漲金明。',192,'全唐诗/poet.song.111000.json','["昔年冶遊浚都城，溶溶春水漲金明。", "龍舟鱗次鼓蘭槳，勝日講武風波平。", "沸地笑歌混簫笛，轟天金鼓驚鷺鷁。", "當年冠蓋盡英游，飛鞚聯翩迅翔翼。", "只今潛盤向荒陂，疇曩偉觀那再期。", "熙熙王化及遠近，春來勝事還相隨。", "十百分朋同川濟，咸欲得梟無異意。", "屈原死向千載餘，今不敬弔翻成戲。", "敬弔賦就獨賈生，可見君子異小人。", "公詩賈賦獨追傷，忍以爲戲向芳春。", "企聽賜環在朝暮，衮繡遄歸廟堂去。", "故先濯我塵土心，琅琅哦公七字句。"]'),
('3c4b586a-e75d-4f6e-b56e-fb81988a176f','真妃小娘子廟','王仙客','宋','宋诗','song-poetry','','[]','當日孤貞不可窮，邦人千載仰其功。',32,'全唐诗/poet.song.111000.json','["當日孤貞不可窮，邦人千載仰其功。", "而今漢上多遊女，誰繼巍巍烈女風。"]'),
('1e6e1f03-b14b-4563-b43b-a438acdf4f79','題安陽山翠微寺','唐皞','宋','宋诗','song-poetry','','[]','平地巍然起一峰，歷山西畔隔湖東。',64,'全唐诗/poet.song.111000.json','["平地巍然起一峰，歷山西畔隔湖東。", "勢侵雲漢千尋直，影落烟村四面同。", "龍窟正當螺髻頂，僧居端在畫圖中。", "邦人不獨資觀賞，旱歲爲霖更有功。"]'),
('163f6132-0555-48c4-a1c8-e8ab6945698e','上方','唐皞','宋','宋诗','song-poetry','','[]','佛龕經閣等巖㠂，地在高中此最高。',64,'全唐诗/poet.song.111000.json','["佛龕經閣等巖㠂，地在高中此最高。", "日出四楹浮寶氣，雲開百里見秋毫。", "登臨暫得心機靜，徙倚翻嫌目力勞。", "况是雄飛先上者，强揮吟筆繼詩豪。"]'),
('37161424-2aa7-48a6-98cf-ccab226a577d','謝詹環仲','祖逢清','宋','宋诗','song-poetry','','[]','在學得益友，結廬得寶鄰。',24,'全唐诗/poet.song.111000.json','["在學得益友，結廬得寶鄰。", "自慚蒹葭質，長倚玉嶙峋。"]'),
('037ca1d2-cf55-4cb9-9a11-b4427e72a0ce','山行見菊','李鼐','宋','宋诗','song-poetry','','[]','野色芬敷洗露香，籬邊不減御衣黄。',32,'全唐诗/poet.song.111000.json','["野色芬敷洗露香，籬邊不減御衣黄。", "繁英自翦無人插，應笑陶潛兩鬢霜。"]'),
('a95f09b7-2937-4e12-9786-20530b974a8a','送修書記遊天台','李鼐','宋','宋诗','song-poetry','','[]','塵事日敗人，筋力隨以勞。',180,'全唐诗/poet.song.111000.json','["塵事日敗人，筋力隨以勞。", "三年梁溪上，俯仰如桔槔。", "窮巷躬水菽，杜門匪禪逃。", "修公巖壑人，臭味合我曹。", "閒從茗碗集，有往不待招。", "清芬落浄几，宴坐揮霜毫。", "脫略畦畛外，寂寞期久要。", "春風草離離，飛花照方袍。", "朝來遽別我，明月挂一瓢。", "笑指天台雲，意氣東南高。", "去去不可挽，獨鶴鳴九皋。", "會看精進力，覺性一宿超。", "全提法王法，衆說障奔濤。", "大千廓沙界，體現無絲毫。", "異時藥山偈，問道慚非翱。"]'),
('4f1c4895-9b4b-4a35-8703-109c14fb9cc6','送燕明仲歸常熟','李鼐','宋','宋诗','song-poetry','','[]','東南江海郡，瘴霧腥蛟螭。',192,'全唐诗/poet.song.111000.json','["東南江海郡，瘴霧腥蛟螭。", "土俗異鄉縣，客子懷歸思。", "歸思何從返，遠道傷百危。", "干戈久未定，一水分華夷。", "壯士爭挽强，覓爵唾手期。", "而我癡絕甚，尚復事毛錐。", "三年行在所，短褐風霜欺。", "生理寄茅棟，不飽藿與藜。", "苦辛攻積憂，欲語聽者誰。", "頼有燕公子，好事頗見奇。", "鄰墻肯相過，情話肝膽披。", "君才駃騠駿，不受塵埃覊。", "驤首志千里，蹲踏風雲垂。", "乃翁名世將，先朝補邦基。", "殊勳鼎彜在，勁節不少虧。", "後昆德澤盛，衮衮固未衰。"]'),
('b9a05d0d-a008-4f9a-8773-04015e2fad48','句','李鼐','宋','宋诗','song-poetry','','[]','南流底處所，絳帳居尊嚴。',12,'全唐诗/poet.song.111000.json','["南流底處所，絳帳居尊嚴。"]'),
('8d5cb3d9-686f-4000-a268-794bc0c8f036','句  其一','王晞鴻','宋','宋诗','song-poetry','','[]','峽覆琵琶彎水带，山歌氈帽送江聲。',16,'全唐诗/poet.song.111000.json','["峽覆琵琶彎水带，山歌氈帽送江聲。"]'),
('6094a3bb-cf7d-4fcf-ae43-97cc7ce92e1a','句  其二','王晞鴻','宋','宋诗','song-poetry','','[]','紅塵紫陌江聲外，綠嶂青嵐書几間。',16,'全唐诗/poet.song.111000.json','["紅塵紫陌江聲外，綠嶂青嵐書几間。"]'),
('5d8796a9-5eaa-4da0-803c-674c5fbb8e84','遊鍾山題八功德水菴壁  其一','陳序','宋','宋诗','song-poetry','','[]','寒騎瘦馬度山腰，目斷青溪第一橋。',32,'全唐诗/poet.song.111000.json','["寒騎瘦馬度山腰，目斷青溪第一橋。", "盡是帝王陵墓處，野風荒草暝蕭蕭。"]'),
('1e931142-c797-49f6-b513-4cbee8ca07fd','遊鍾山題八功德水菴壁  其二','陳序','宋','宋诗','song-poetry','','[]','十年塵土暗衣巾，亂走江鄉一病身。',32,'全唐诗/poet.song.111000.json','["十年塵土暗衣巾，亂走江鄉一病身。", "西第將軍成底事，北朝開府是何人。"]'),
('c4f12c42-e422-4bff-aa87-78b06688b8e8','游茅山和諸侄','陳序','宋','宋诗','song-poetry','','[]','山南細路半青霄，人昔共游非俗交。',64,'全唐诗/poet.song.111000.json','["山南細路半青霄，人昔共游非俗交。", "浮玉故鄉驚上國，埋丹清夢記中茅。", "峰頭仙客歸黄鵠，石面靈根走翠蛟。", "見說西園渾草莽，手栽寸柏已勝巢。"]'),
('e87b19c0-64cf-47a8-ac03-378f27368be0','滄浪亭','沈東','宋','宋诗','song-poetry','','[]','草蔓花枝與世新，登臨空復想清塵。',32,'全唐诗/poet.song.111000.json','["草蔓花枝與世新，登臨空復想清塵。", "只今唯有亭前水，曾識春風載酒人。"]'),
('fd915924-f05a-43bb-ad08-7c6a3b4be9af','梅花邨詠梅作','陳煥','宋','宋诗','song-poetry','','[]','雪裏溪橋獨樹春，客來驚起曉粧勻。',32,'全唐诗/poet.song.111000.json','["雪裏溪橋獨樹春，客來驚起曉粧勻。", "試從意外看風味，方信留侯似婦人。"]'),
('f0261ab8-d1cf-4054-b9cd-c64e8de64fa4','遺衣壇','陳煥','宋','宋诗','song-poetry','','[]','一點殘燈照夜闌，洞深雲氣逼人寒。',32,'全唐诗/poet.song.111000.json','["一點殘燈照夜闌，洞深雲氣逼人寒。", "仙翁從此乘鸞去，不見遺衣見古壇。"]'),
('220b4249-3d90-4dd7-b617-08e4a460e845','黄龍洞口道人送茶及筇竹杖','陳煥','宋','宋诗','song-poetry','','[]','露泣新芽九節筇，芽如雀舌節如龍。',32,'全唐诗/poet.song.111000.json','["露泣新芽九節筇，芽如雀舌節如龍。", "烹來習習風生腋，拄上羅浮第一峯。"]'),
('4b792374-91f1-4977-8496-9a5857a40620','茶菴觀茶','陳煥','宋','宋诗','song-poetry','','[]','脚底晴雷殷殷過，浮山四面布干戈。',32,'全唐诗/poet.song.111000.json','["脚底晴雷殷殷過，浮山四面布干戈。", "鎗旗不染陰山血，留與人間戰睡魔。"]'),
('8ca13133-860f-46ca-8c70-21fc540ca650','過蘭亭書堂','劉度','宋','宋诗','song-poetry','','[]','蘭亭擬金谷，逸少比季倫。',108,'全唐诗/poet.song.111000.json','["蘭亭擬金谷，逸少比季倫。", "史臣作此語，無異屠沽人。", "君看蘭亭墨，歲久迹豈陳。", "當時本嬉戲，後世乃見真。", "我行適春暮，及此禊飲辰。", "墨池奏環玦，書堂暗松筠。", "堂中有遺像，儼坐遺冠巾。", "情知金堂仙，可望不可親。", "物色倘見之，欲去猶逡巡。"]'),
('187843db-0d20-45af-b044-0bf4f6908913','題蘇子美滄浪亭','陳瀧','宋','宋诗','song-poetry','','[]','整履上飛虹，風高退酒容。',48,'全唐诗/poet.song.111000.json','["整履上飛虹，風高退酒容。", "葉黄翻亂蝶，樹老卧蒼龍。", "古徑秋霜滑，空山暮靄濃。", "滄浪棋石在，題筆暗塵封。"]'),
('756e341d-50ce-41ba-a439-accc2d07db70','懷高履常','陳瀧','宋','宋诗','song-poetry','','[]','蒼頭背錦囊，別我渡淮鄉。',48,'全唐诗/poet.song.111000.json','["蒼頭背錦囊，別我渡淮鄉。", "一去又無信，相思幾斷腸。", "柳橋初過雨，瓜步正斜陽。", "知己同行樂，應忘歸路長。"]'),
('64543f2a-a5d7-4ae7-b7ac-2c2a6f48d817','自賦小隠','陳瀧','宋','宋诗','song-poetry','','[]','環堵蕭然一破廬，市塵不到足安居。',32,'全唐诗/poet.song.111000.json','["環堵蕭然一破廬，市塵不到足安居。", "知心惟有梅梢月，來照寒窗夜讀書。"]'),
('d6d93c36-a563-4ff5-835f-e5f398f4817c','鳳凰臺','陳瀧','宋','宋诗','song-poetry','','[]','老盡梧桐鳳不來，虛名猶占舊層臺。',32,'全唐诗/poet.song.111000.json','["老盡梧桐鳳不來，虛名猶占舊層臺。", "朝陽照破興亡夢，一徑花陰自綠苔。"]'),
('ee1c29f8-f442-4d35-8d41-d3f9504e4e10','合州望黔樓','釋義光','宋','宋诗','song-poetry','','[]','江上望黔樓，望中烟靄浮。',48,'全唐诗/poet.song.111000.json','["江上望黔樓，望中烟靄浮。", "微凉生戶牖，新雨過汀洲。", "遠岫千重疊，清波萬里流。", "此時何限興，回首寄羣鷗。"]'),
('29b9f4c4-7f04-41e2-a990-32ce275f93da','句','釋義光','宋','宋诗','song-poetry','','[]','安閑有深味。',6,'全唐诗/poet.song.111000.json','["安閑有深味。"]'),
('f23301a9-92e4-4d59-8bbd-ef34e32335f3','臞菴  其一','釋道舉','宋','宋诗','song-poetry','','[]','竹裏蓬茅掩棘扉，主人詩瘦带寬圍。',64,'全唐诗/poet.song.111000.json','["竹裏蓬茅掩棘扉，主人詩瘦带寬圍。", "種成苜蓿先生飯，製就芙蓉隠者衣。", "柳絮春江魚婢至，荻花秋渚雁奴歸。", "小溪短艇能容我，先向溪隈築釣磯。"]'),
('ef7707d9-388f-4e48-805c-168b4bf11bf1','臞菴  其二','釋道舉','宋','宋诗','song-poetry','','[]','谿南谿北繞清漪，舍後舍前圍短籬。',64,'全唐诗/poet.song.111000.json','["谿南谿北繞清漪，舍後舍前圍短籬。", "九九算來成底夢，休休歸去復何疑。", "添丁見客走賒酒，阿買能書供賦詩。", "丘壑政非公子事，綺紈當預少年知。"]'),
('0cc682a7-f9b1-4441-a25b-2b116d70bd2a','丹丘道中寄錢大資二首  其一','釋道舉','宋','宋诗','song-poetry','','[]','谿橋人度柳青葱，困卧羈孤雪鬢翁。',64,'全唐诗/poet.song.111000.json','["谿橋人度柳青葱，困卧羈孤雪鬢翁。", "鷺宿煙沙晴復暖，雞鳴茅店雨連風。", "早年史冊書名節，晚歲燕然妙勒功。", "急詔鳳池歸去客，紫宸殿後看鞓紅。"]'),
('0ea805b7-8fb6-48e5-a76b-7fdd98c64217','丹丘道中寄錢大資二首  其二','釋道舉','宋','宋诗','song-poetry','','[]','向來湯餠潑油葱，思舊所懷惟此翁。',64,'全唐诗/poet.song.111000.json','["向來湯餠潑油葱，思舊所懷惟此翁。", "日暮樓邊梅子雨，夜凉亭下藕花風。", "凌煙晉室謝文靖，陰德唐朝徐有功。", "二十年間蓮社客，酡顔不是少時紅。"]'),
('a8516572-0e8d-4f81-80c3-94059bf0e3fe','句  其一','徐某','宋','宋诗','song-poetry','','[]','仙臺之陽石壇東，下有亭亭太古松。',16,'全唐诗/poet.song.111000.json','["仙臺之陽石壇東，下有亭亭太古松。"]'),
('cf2cbfcb-34bd-4305-bcaa-9399e757798e','句  其二','徐某','宋','宋诗','song-poetry','','[]','至誠感格合天意，露零青松真上瑞。',16,'全唐诗/poet.song.111000.json','["至誠感格合天意，露零青松真上瑞。"]'),
('2905ffc9-c36c-48d2-a439-4dbf40a86a73','題譙樓','吹角老兵','宋','宋诗','song-poetry','','[]','畫角吹來歲月深，譙樓無古亦無今。',32,'全唐诗/poet.song.111000.json','["畫角吹來歲月深，譙樓無古亦無今。", "不如歸我龍山去，松柏青青何處尋。"]'),
('93eaa8fd-847d-4768-8a6c-a7f6caec9e75','句','軒氏','宋','宋诗','song-poetry','','[]','栗棘蓬，栗棘蓬，一口吞却更無蹤。',16,'全唐诗/poet.song.111000.json','["栗棘蓬，栗棘蓬，一口吞却更無蹤。"]'),
('e78bd3c0-9eed-4c3b-bc50-74e9eecaa48b','雜興五首  其一','范浚','宋','宋诗','song-poetry','','[]','雉驕有擅澤，雞雄亦專栖。',60,'全唐诗/poet.song.111000.json','["雉驕有擅澤，雞雄亦專栖。", "乘人肆桀傲，未異雉與雞。", "虛張盡客氣，不知墮危機。", "雉驕或登俎，雞雄亦爲犧。", "嗟爾桀傲子，不戒將安之。"]'),
('3193e39b-0594-4247-819e-53b44d9ac14f','雜興五首  其二','范浚','宋','宋诗','song-poetry','','[]','荆梟昔見惡，去楚將巢吳。',48,'全唐诗/poet.song.111000.json','["荆梟昔見惡，去楚將巢吳。", "妖音不知革，吳豈荆人殊。", "梟能戒頰舌，勿復輕鳴呼。", "雖荆亦容爾，何必他邦居。"]'),
('cc823bfd-31a2-48a8-a838-cc085c17d4d6','雜興五首  其三','范浚','宋','宋诗','song-poetry','','[]','高蟬蔭嘉木，未省螗斧危。',48,'全唐诗/poet.song.111000.json','["高蟬蔭嘉木，未省螗斧危。", "勇蟲亦何愚，不顧黄雀饑。", "癡癡挾彈子，已復露霑衣。", "世事無不然，古今同一悲。"]'),
('02ce6c8b-0b06-43a6-8a78-e667b8f49a35','雜興五首  其四','范浚','宋','宋诗','song-poetry','','[]','鵲噪得歡喜，烏鳴得憎嗔。',48,'全唐诗/poet.song.111000.json','["鵲噪得歡喜，烏鳴得憎嗔。", "烏鵲自有口，噪鳴何預人。", "烏飛聲啞啞，鵲飛聲嘖嘖。", "凡鳥從紛紛，未用置肝鬲。"]'),
('76d530a9-d2fd-4239-b93d-911c25648c0c','雜興五首  其五','范浚','宋','宋诗','song-poetry','','[]','彭亨著冠豬，踉蹡上車鶴。',60,'全唐诗/poet.song.111000.json','["彭亨著冠豬，踉蹡上車鶴。", "皇家一清明，此輩束高閣。", "龍夔雜鵷鷺，庶位已參錯。", "少安真可待，四海得耕鑿。", "我亦幸豐年，從容一丘壑。"]'),
('207a8b81-255d-4545-9a75-aa77ca8a31a2','遣興五首  其一','范浚','宋','宋诗','song-poetry','','[]','商山園綺徒，雪髮映松露。',96,'全唐诗/poet.song.111000.json','["商山園綺徒，雪髮映松露。", "山間謂終老，不踏市朝路。", "一朝前星匿，羽翼起調護。", "婆娑古衣冠，笑定國儲副。", "留侯計偶爾，曷遽動貞素。", "因知古今士，出處自冥數。", "功名苟不免，四老猶一助。", "寧庸巧馳驅，失爾邯鄲步。"]'),
('bf7170e5-9ca9-4895-9d00-9eacccc3ceb1','遣興五首  其二','范浚','宋','宋诗','song-poetry','','[]','少陵古詩伯，未必真豪人。',48,'全唐诗/poet.song.111000.json','["少陵古詩伯，未必真豪人。", "胡爲冷炙辱，自分潛悲辛。", "莫倚善題賦，未悟嚴武嗔。", "徒言磊落士，不肯異其身。"]'),
('daf9304c-5fcb-4451-8afa-6c9d6aacd9fe','遣興五首  其三','范浚','宋','宋诗','song-poetry','','[]','我逢劉潁川，竟夕不向枕。',48,'全唐诗/poet.song.111000.json','["我逢劉潁川，竟夕不向枕。", "餘人偶對面，白晝輒欲寢。", "生來不耐俗，敢妄作題品。", "猶嫌太分明，客至姑與飲。"]'),
('76b22f25-d89a-493a-b042-5ebc7d3ea27b','遣興五首  其四','范浚','宋','宋诗','song-poetry','','[]','龐眉困郎署，白首命不遭。',60,'全唐诗/poet.song.111000.json','["龐眉困郎署，白首命不遭。", "猿臂無侯封，徒負射虎豪。", "兩者阨天運，材智俱莫逃。", "向來鄧氏子，志行劣可褒。", "藉非逢際會，未免掾功曹。"]'),
('8985ebe5-47c3-40c6-8a6c-a0705b2571f0','遣興五首  其五','范浚','宋','宋诗','song-poetry','','[]','翻雲覆忽雨，昨火今已冰。',48,'全唐诗/poet.song.111000.json','["翻雲覆忽雨，昨火今已冰。", "三塗九州險，未似今人情。", "人言餘耳事，令我不忍聽。", "嗟哉泜水上，刎頸遂寒盟。"]'),
('7342cf94-80f1-42a7-8c35-436992aa5a6d','題八馬圖','范浚','宋','宋诗','song-poetry','','[]','何年畫工搦毛錐，貌此八馬姿權奇。',224,'全唐诗/poet.song.111000.json','["何年畫工搦毛錐，貌此八馬姿權奇。", "青絲絡頭十二蹄，調柔意態行愉怡。", "五馬放浪無維羈，或齕或望仍迴嘶。", "一牧牽鞚一牧騎，製度彷彿唐巾衣。", "不知此馬生何時，昔周穆王遠遊嬉。", "駕跨八駿驅東西，高升崑崙躡瑶池。", "騮騄驥義勞飛馳，日走萬里無停騑。", "興元唐家危累棋，百弮僅脫朱泚圍。", "黄屋進狩懷光追，八馬入谷七馬疲。", "筋攣肉綻行人悲，兩者資世皆顛羸。", "虛名何有千載垂，空得傳記流歌詩。", "未如此馬閑猶夷，牧坰不受鞭筴威。", "不踣險遠安無危，泉甘草薦足自肥。", "安用號駿稱雲騅，嗟哉畫意誰能知。"]'),
('4cf21f6f-e084-4de2-af73-24bbb6ac778a','寄謝潘舍人贈烏紗帽','范浚','宋','宋诗','song-poetry','','[]','野人儀矩初無華，况復破帽風簷斜。',128,'全唐诗/poet.song.111000.json','["野人儀矩初無華，况復破帽風簷斜。", "先生有意念衰醜，折簡遠送新烏紗。", "束巾試著出妨戶，色若露洗凌晨鴉。", "舍人樣好信殊俗，朽質得此慚無涯。", "白癡稚子强解事，競道宜稱相讙譁。", "輕寬不但愜當暑，掉頭曝背仍堪誇。", "修容他日奉遊宴，便可笑誚參軍嘉。", "從今旦暮戴公賜，閉關無事聊煎茶。"]'),
('781d0d44-a13b-4c31-b50c-8691b6c1eae4','遊蘭谿靈洞','范浚','宋','宋诗','song-poetry','','[]','朝曦杲晴空，宿霧開紛披。',192,'全唐诗/poet.song.111000.json','["朝曦杲晴空，宿霧開紛披。", "縈紆度墟曲，犖确行溪湄。", "橫橋轉山腰，丹堊明招提。", "豁谺覷陰洞，欲入愁途迷。", "流泉暗淙琤，噴壑跳珠璣。", "巖根石彩翠，映水光參差。", "窮高上蒼岑，支策行欹危。", "林端出紺宇，兀與浮雲齊。", "曾來念舊事，歷歷經行時。", "松長向如人，今已老十圍。", "我尚喜青鬢，還年未生絲。", "偕遊數君子，意擬探幽奇。", "諸峰未歷覽，寒日還平西。", "同携下前麓，却望蘭陰歸。", "明年艷陽春，更約相追隨。", "當須各努力，補屐尋幽期。"]'),
('7c5a4c47-ac51-4ff0-bbb4-12db6368cdf1','題弟茂通斗齋','范浚','宋','宋诗','song-poetry','','[]','昔人驕豪自髫鬌，萬里浪欲乘風破。',160,'全唐诗/poet.song.111000.json','["昔人驕豪自髫鬌，萬里浪欲乘風破。", "暮年志計轉難量，眼看一州如斗大。", "今君容膝能自安，高館不與身相關。", "作齋似斗意闊達，宇量寧妨廣百間。", "足明居世惟知足，寬窄在心非在屋。", "莫言齋小礙人眉，清絕坐銷愁萬斛。", "奉身那用有餘爲，身穩心安君自知。", "軟褥傍爐時枕肘，不須小帳更低垂。", "也知丈室含無際，自有壺公容客地。", "斗齋我已戲題詩，斗酒還當就君醉。"]'),
('ca39826d-fa25-4d73-b0eb-2863b7af7929','寄題錢伯茂致政奉議遥碧軒','范浚','宋','宋诗','song-poetry','','[]','君不聞漢時遺榮兩大夫，羣公祖道傾京都。',163,'全唐诗/poet.song.111000.json','["君不聞漢時遺榮兩大夫，羣公祖道傾京都。", "去塵寂寞絕繼踵，但見畫手空傳圖。", "君今心事能超古，早束衣冠掛神武。", "掉頭不待迫懸車，廣受視君知孰愈。", "世人分著金籠頭，或貪微名魚中鈎。", "寧如君脫宦海去，飽看遥碧臨清流。", "似聞遠目增明處，宛如畫出城南句。", "款門何日赴幽期，坐挹雲岑爲君賦。", "想當遐矚窮天垠，吟憐修眉濃綠新。", "應嗤爭利推車客，不惜青山碾作塵。"]'),
('a8193b5f-d673-4807-8dbe-967b88050d7d','寄題何元晉亦樂堂','范浚','宋','宋诗','song-poetry','','[]','士生墮塵網，窘若囚飛蟲。',120,'全唐诗/poet.song.111000.json','["士生墮塵網，窘若囚飛蟲。", "思牽黄耳不可得，况欲雲卧聽松風。", "何郎可憐人，恥與俗同調。", "不作窮愁懊惱詩，獨抱青山坐長嘯。", "誅茅結屋傍林塘，石蘭露菊秋風香。", "掉頭萬事一不顧，仰天白眼傾壺觴。", "邈予坐阻窺幽躅，夢到東窗攀綠玉。", "裁詩寄似堂中人，爲楷銀鈎寫高竹。"]'),
('a249dc8d-c00e-4371-a584-fb58faf56826','送春曲','范浚','宋','宋诗','song-poetry','','[]','春光春光，勸汝一杯酒。',167,'全唐诗/poet.song.111000.json','["春光春光，勸汝一杯酒。", "我能爲春作高歌，未解春能聽歌否。", "春歸有底急，落盡桃花紅。", "園蹊漠漠野陰靜，兔葵燕麥空摇風。", "風光幾何時，背我忽如客。", "殘絲欲斷感春心，語燕勞勞上簾額。", "我有惜芳意，一春憐物華。", "春來雪裏索梅笑，春去悵望飛楊花。", "春歸知復來，奈此斷年別。", "摇楊三月暮天愁，鶗鴂一聲芳草歇。", "歌竟我亦醉，一掉觥船空。", "明年待春花樹下，放歌擎酒相迎逢。"]'),
('f66c6576-c11a-4d94-b2de-6c6c401eb557','春融融效李長吉體','范浚','宋','宋诗','song-poetry','','[]','天暄地媚春融融，化工點染分花容。',80,'全唐诗/poet.song.111000.json','["天暄地媚春融融，化工點染分花容。", "東風夜半入香陌，雜樹曉繁爭白紅。", "蘭叢蕙根芳翠滴，柳艷明眉輕羃䍥。", "紅顔綠鬢青春客，壺中新醅鴨頭色。", "殘絲冉惹愁如織，日暮低迷草萋碧。"]'),
('cb3a5861-fd7c-4f0b-bff6-b1ee5c0c68d1','同姪伯通端杲效盧仝體','范浚','宋','宋诗','song-poetry','','[]','一春癡癖門長扃，兩耳不聞鶗鴂聲。',128,'全唐诗/poet.song.111000.json','["一春癡癖門長扃，兩耳不聞鶗鴂聲。", "不知東南風，掃盡紅紫英。", "行行點檢桃李徑，但見樹子青冥冥。", "門前水流渠，照灼鬚眉清。", "科斗游其間，脚股各已生。", "渠旁草鬰鬰，草底蚯蚓鳴。", "韵如抽繭絲，幽咽得我聽。", "念此瑣細物，隨時變音形。", "黄河赤鯉或點額，老驥塞默長羈纓，嗟嗟世路真難行。"]'),
('be4a0a5a-f687-41e2-84af-170145778bd5','同弟茂通效溫飛卿體','范浚','宋','宋诗','song-poetry','','[]','海棠紅歇鶑停歌，麥風時候猶清和。',64,'全唐诗/poet.song.111000.json','["海棠紅歇鶑停歌，麥風時候猶清和。", "簾垂箓簌深院靜，赤欄細柳陰婆娑。", "池塘正覺幽事好，萍葉藻蔓涵清波。", "一雙胡燕薇叢外，銜得芹泥來補窠。"]'),
('28548012-44eb-4059-b746-fa7b7191fd8c','送喬民瞻倅武昌','范浚','宋','宋诗','song-poetry','','[]','春風未綠江南草，春信臘前梅蕊早。',160,'全唐诗/poet.song.111000.json','["春風未綠江南草，春信臘前梅蕊早。", "水村著處是南枝，想見君行被花惱。", "如君久合上華途，胡爲半刺猶題輿。", "奉引未騎沙苑馬，佐藩且食武昌魚。", "頻年欣接遊從樂，忽手別書空作惡。", "江干跋馬望行艫，日暮山寒雲錯莫。", "往聞南紀百戰場，腥風殺氣吹湖湘。", "只今江漢俱練靜，棹謳雜發行連檣。", "君從鸚鵡洲邊去，歷歷遥看漢陽樹。", "莫言槌碎黄鶴樓，準擬書來寄佳句。"]'),
('3375d459-6efe-4b66-9a95-d972756ffef5','送徐履之倅南昌','范浚','宋','宋诗','song-poetry','','[]','春山罨畫春江平，江頭春船椎鼓聲。',160,'全唐诗/poet.song.111000.json','["春山罨畫春江平，江頭春船椎鼓聲。", "鍾陵別乘喚帆席，笑看獵獵風摇旌。", "明朝太末經行處，懸愁望斷煙綿樹。", "勞勞檣燕亦留君，且共推蓬話情素。", "鍾陵地雄古名都，美官况復稱題輿。", "看君逸足展夷路，逐電追風萬里餘。", "前知按部勞綏撫，箳篂行濕西山雨。", "君家孺子有遺臺，試向東湖聊訊古。", "蘭陰新漉酒吹醅，更折江花勸引杯。", "聖代興廉訪良吏，遲君却抱鶴書回。"]'),
('38246bdf-9200-4597-be19-84668ec3dfee','六笑','范浚','宋','宋诗','song-poetry','','[]','我笑支道林，遠移買山書。',208,'全唐诗/poet.song.111000.json','["我笑支道林，遠移買山書。", "巢由古達士，不聞買山居。", "我笑賀知章，欲乞鑑湖水。", "嚴陵釣清江，何曾問天子。", "我笑陶靖節，自祭真忘情。", "胡爲托青鳥，乃欲長年齡。", "我笑王無功，琴外無所欲。", "當其戀五斗，乃獨不知足。", "我笑杜子美，夙昔具扁舟。", "老大意轉拙，欲伴習池遊。", "我笑韓退之，不取萬乘相。", "三黜竟不去，觸事得讒謗。", "客言莫謾笑古人，笑人未必不受嗔。", "螳螂襲蟬雀在後，只恐有人還笑君。", "迴頭生愧不能語，嘲評從今吞不吐。", "譽堯非桀亦何爲，訕周譏禹終無取。"]'),
('5a33492e-4253-43af-8110-67c169046a5f','讀楊子雲傳','范浚','宋','宋诗','song-poetry','','[]','老不曉事楊子雲，綴文譏訶堅逐貧。',160,'全唐诗/poet.song.111000.json','["老不曉事楊子雲，綴文譏訶堅逐貧。", "班生曲筆甚假借，謂不戚戚元非真。", "草玄欲作後人計，投閣自迷身不利。", "王涯筮中好其書，寧復逆知甘露事。", "蛙聲紫色欺昏童，義士遠引如冥鴻。", "胡爲顛眩尚執戟，美新屈首稱臣雄。", "岷山沃野蹲鴟大，拓落不歸良已過。", "近危竟似井眉瓶，虛作反騷嗤楚些。", "詭情懷祿遭嘲評，但用筆墨垂聲名。", "文章要亦千古事，久矣法言今正行。"]'),
('0fb6ad3b-a579-484b-b0e2-d64313885adb','讀王建射虎行','范浚','宋','宋诗','song-poetry','','[]','我讀射虎行，感概興長歎。',198,'全唐诗/poet.song.111000.json','["我讀射虎行，感概興長歎。", "官羌射虎得虎難，山下遠立常空還。", "惜留猛虎著山裏，射殺顧恐終身閑。", "有如邊將圖偷安，遵養時賦容其姦。", "翻愁努力盡高鳥，良弓掛壁無由彎。", "君不見劉巨容高千里，留賊自資媒富貴，恐賊盡誅身不利。", "坐令屈律裹頭人，橫暴九州狂螫噬。", "嗟嗟忠臣心不移，受刀摩頸甘如飴。", "紛紛血刃勇不顧，一死未謝君王知。", "官軍壯志吞蠻夷，匈奴不滅寧家爲。", "相公誓欲平淮西，慨言賊在歸無期。", "霍公裴公今已矣，我吟射虎徒歔欷。"]'),
('26d2e4c4-8c9f-4d9e-bc0d-2fe2508646aa','冬夜有感','范浚','宋','宋诗','song-poetry','','[]','宵長倦觀書，掩帙起微步。',144,'全唐诗/poet.song.111000.json','["宵長倦觀書，掩帙起微步。", "徘徊簷隙月，點綴竹稍露。", "寒空頑無風，寂歷雁時度。", "不知何處村，尚急野塘戽。", "哀哉當丙夜，取水窮沮洳。", "得無空魚羣，一舉不復顧。", "那知今竭澤，無復魚可捕。", "天公仁百物，暴殄天所怒。", "褰裳欲從之，告以盍長慮。", "浮雲暗林野，恐墮荆棘路。", "出門還入門，此意定誰喻。", "遣興强微吟，淒涼不能句。"]'),
('401eda52-d84b-410a-b743-45f7460669c9','送兄茂瞻機宜之官廣東','范浚','宋','宋诗','song-poetry','','[]','黄蘆鬣鬣秋風肥，鬼雨灑草南山悲。',240,'全唐诗/poet.song.111000.json','["黄蘆鬣鬣秋風肥，鬼雨灑草南山悲。", "長塗客子動愁肺，往往捫轍多思歸。", "我兄豈不感時節，東床卷席將何之。", "自言南州有元帥，標鑒本是陽秋皮。", "薦紳奔走欲定價，一見許我奇男兒。", "提撕表奏置戎幕，使我坐握官機宜。", "高生所愧國士知，不辭觸熱向武威。", "我今去路雖千里，敢以驅馳負知己。", "南州最盛肩京都，昔人欲語停杯餘。", "地靈孕秀多異産，鼊皮蚺蟾如蟲蛆。", "舊聞民俗蠻頑甚，蜂屯蟻雜難爬梳。", "聖朝神化與換骨，詎事草薙髠根株。", "我兄智囊載大腹，撫俗自應才有餘。", "腰間長劍生銅吼，可膾蠻王快屠狗。", "後當歸路持旌麾，六印黄金大如斗。"]'),
('da15579e-6b08-4fd2-8819-17c6b714e384','贈青城道人','范浚','宋','宋诗','song-poetry','','[]','道人來自青城巔，飄飄逸氣凌雲烟。',192,'全唐诗/poet.song.111000.json','["道人來自青城巔，飄飄逸氣凌雲烟。", "青鞋布襪久遊世，踏盡海宇名山川。", "琴心三疊得妙旨，華頂一路通幽禪。", "自言早歲拾瑶草，往往鶴上逢真仙。", "惜哉食服只半劑，猶與人世相周旋。", "曾期汗漫九垓外，决去已復揮騾鞭。", "伊予此生一念誤，遂墮塵網嗟拘攣。", "鏡中華髮已疏索，肘後丹經猶棄捐。", "三山銀闕眇何許，悵望碧海波翻天。", "因君告我獨往意，伎癢竦踴心茫然。", "莫言得道兩塵隔，蓬島只在拄杖前。", "定知後會君刮眼，看我玉練還頹年。"]'),
('8bacd584-c522-4d29-9791-e0ec244c7bd1','理喻  其一','范浚','宋','宋诗','song-poetry','','[]','郵亭羈客寒無氊，夜懷家山情惘然。',96,'全唐诗/poet.song.111000.json','["郵亭羈客寒無氊，夜懷家山情惘然。", "燈前坐感雨蕭瑟，浩歎達曉愁無眠。", "鄰翁不出蓬茨裏，聽雨聽風心似水。", "黄昏鼻息已雷鳴，往往簷喧不經耳。", "愁霖一種聲紛紛，鄰翁不聞羈客聞。", "是中轉物有妙理，起予暗契瞿曇旨。"]'),
('caf89965-d5da-4080-8f82-11c415c305a1','理喻  其二','范浚','宋','宋诗','song-poetry','','[]','我眠鼻息鄰家驚，耳不自聞齁䶎聲。',76,'全唐诗/poet.song.111000.json','["我眠鼻息鄰家驚，耳不自聞齁䶎聲。", "我耳忽鳴韵清磬，旁人對面那能聽。", "耳鳴如心念，鼻息如己過。", "心念潛萌衆莫知，己過自迷人看破。", "歷歷眼前皆要理，舉世何人無鼻耳。"]'),
('32e2e61f-3268-4eaf-aa7f-686d530d1d73','雜興四首  其一','范浚','宋','宋诗','song-poetry','','[]','水母雖目蝦，竟自了無覩。',48,'全唐诗/poet.song.111000.json','["水母雖目蝦，竟自了無覩。", "如人心苟盲，記誦亦何補。", "當須見精義，一覽洞千古。", "可效章句徒，冥迷自聾瞽。"]'),
('4eac9386-9790-4c8e-9629-be2cd4758d49','雜興四首  其二','范浚','宋','宋诗','song-poetry','','[]','乞火固得火，不如鑽燧多。',48,'全唐诗/poet.song.111000.json','["乞火固得火，不如鑽燧多。", "寄汲非無泉，鑿井泉盈科。", "君子貴自得，顧豈求之他。", "心焉有餘師，奈彼自棄何。"]'),
('2e29a468-b9bc-4e60-b416-d567dbf851fe','雜興四首  其三','范浚','宋','宋诗','song-poetry','','[]','饑人嗜敗肉，渴者甘腐漿。',48,'全唐诗/poet.song.111000.json','["饑人嗜敗肉，渴者甘腐漿。", "一爲饑渴害，食飲俱失常。", "况茲方寸間，邪欲紛難量。", "微哉此心害，禍甚饑渴傷。"]'),
('938716c1-bf9a-4f38-b8e0-339acab0bae6','雜興四首  其四','范浚','宋','宋诗','song-poetry','','[]','昔人稱水淫，好潔若無奈。',48,'全唐诗/poet.song.111000.json','["昔人稱水淫，好潔若無奈。", "居然一日間，洗滌十餘過。", "君看七尺軀，孰與此心大。", "洗心儻亦爾，會絕客塵涴。"]'),
('3919e959-5011-4046-ac88-bd9fe7bd1e82','聽琴','范浚','宋','宋诗','song-poetry','','[]','坐人皆聽琴，未必知琴音。',107,'全唐诗/poet.song.111000.json','["坐人皆聽琴，未必知琴音。", "相知紛滿眼，未必相知心。", "知音如子期，知心如鮑叔。", "此道久寥寥，誰其踵高躅。", "古聲勿復彈，古心徒自憐。", "知音惟月露，知我其惟天。", "君不見只今人情如紙薄，只今世路如溪惡。", "咄嗟許事不足論，鳥跡微茫度寥廓。"]'),
('2d10765e-ccab-4c47-9b57-584b3a855a6a','寓居寶惠寺喜晴登山','范浚','宋','宋诗','song-poetry','','[]','喜霽出招提，愛山登嶪岌。',72,'全唐诗/poet.song.111000.json','["喜霽出招提，愛山登嶪岌。", "林端已殘照，路草猶半濕。", "丹崖斷雲歸，翠竇飛泉入。", "長天沒鳥影，遠水動虹吸。", "塵襟得必瞰，爽氣橫來集。", "欲逐野僧還，更看空翠立。"]'),
('75bf1218-a8a8-4525-9c32-2f5145b5a474','次韵姪端方過予偕行南村玩月','范浚','宋','宋诗','song-poetry','','[]','焚魚共酌田家醴，歡酣遞嘯凉風起。',192,'全唐诗/poet.song.111000.json','["焚魚共酌田家醴，歡酣遞嘯凉風起。", "子諳懶叔故相携，指點村南聊縱履。", "行行林影摇參差，拄杖扶我長過眉。", "幽尋極眺不知倦，路轉石角時鈎衣。", "泉聲入耳淙琤玉，何許泠泠砧杵續。", "悠然發興見南山，林壑盤紆如岳麓。", "喧卑迥隔區中緣，况復華月升東邊。", "明凝苔露正皎皎，浄映石瀨彌娟娟。", "方欣清景多幽事，揚煇莫遣浮雲蔽。", "絕憐螢影巧自持，却厭蛙讙苦無謂。", "歸來阿朗傍隅趨，示我長吟意有餘。", "明宵有月更相就，還看玉輪遊舞雲。"]'),
('8a31804c-1c08-4d3a-bdfe-03280ecb2693','送四兄茂安之任永嘉','范浚','宋','宋诗','song-poetry','','[]','不齊宰單父，廩廩德垂久。',120,'全唐诗/poet.song.111000.json','["不齊宰單父，廩廩德垂久。", "當年誠化洽，誰忍輒欺負。", "能令夜漁人，有得棄不取。", "何因政乃爾，賢助則多有。", "東嘉侔洛師，雅號士淵藪。", "儒風既純古，俗習自忠厚。", "兄行試牛刀，豈復勞决剖。", "鳴弦會多暇，遇事無掣肘。", "懸知著嘉蹟，遠與宓生偶。", "匪謂得聲榮，期兄富師友。"]'),
('a427d376-dfa8-4397-8216-49f452cdca30','次韵姪端臣雨晴出郊','范浚','宋','宋诗','song-poetry','','[]','雨中爛熳睡，門徑橫林扉。',156,'全唐诗/poet.song.111000.json','["雨中爛熳睡，門徑橫林扉。", "朝暉入甕牖，起我聊伸眉。", "良遊眺江郊，攬袂風披披。", "平瀛漲新綠，灧漾摇晴陂。", "雲巒靄空翠，煙樹森華滋。", "潭漁下罜䍡，隴種行樓犁。", "貪穿康樂屐，更杖原思藜。", "阿宜倦遊還，心事嗟多違。", "新功在琢句，非復吳下時。", "淵明賦歸來，今是知昨非。", "君看古賢達，茹草甘長饑。", "悠悠身外事，凜凜胸中奇。", "因賡喜霽作，用代城南詩。"]'),
('d4f3c934-acb5-4969-9804-f22cd5eb1d02','送袁上人還銅山','范浚','宋','宋诗','song-poetry','','[]','上人眼睛黄，游藝出天悟。',192,'全唐诗/poet.song.111000.json','["上人眼睛黄，游藝出天悟。", "胸中七曜曆，掌上九籌數。", "通醫詔百藥，襲氣了三住。", "餘猶窮衆術，辨口劇河注。", "誰云不拘教，心實謹律度。", "提携木上座，白足勤遠步。", "丁丁啄郊扉，起我曳塵屨。", "高談翠竹法，時覓碧雲句。", "語以丘軻書，竦踴知詠慕。", "南山古花界，可隠玄豹霧。", "挽使小淹留，懷歸錫難駐。", "長途雪沒脛，栗烈正寒沍。", "披披拂風袖，笑話巖中趣。", "巾瓶到銅山，鍾梵歲云暮。", "浮雲亦何意，南北自來去。", "遲爾青春深，過予碧溪路。"]'),
('bfb5ddac-e6fa-4260-8173-b255d8f99143','寄題餘姚嚴公堂','范浚','宋','宋诗','song-poetry','','[]','漢家蒲車邀客星，嚴公高舉鴻冥冥。',224,'全唐诗/poet.song.111000.json','["漢家蒲車邀客星，嚴公高舉鴻冥冥。", "故人作帝且不屈，肯復俯首趨羣卿。", "姚江知是公卿聚，鄉人尚敬陳山墓。", "寧須封鬣卧麒麟，古隴荒凉名自著。", "徐侯健令聊弦歌，草鞠犴圄庭張羅。", "作堂縣圃得面勢，正見列岫青峨峨。", "堂名不爲遊觀設，標榜嚴公仰前哲。", "令方冰蘗事清修，日企陳山思砥節。", "世人慕貴不足論，下馬泣拜汾陽墳。", "令今但望釣翁塚，好尚與俗真蕕薰。", "往聞范公當守睦，嚴瀨奉祠初結屋。", "至今壓水抗軒楹，高椓簷牙映喬木。", "此堂徐侯能始基，後來繼者知爲誰。", "堊丹他日儻漫漶，補理勿廢茲良規。"]'),
('0363d53d-da9d-4b2f-88df-4621b2cb0d69','歎旱','范浚','宋','宋诗','song-poetry','','[]','我行田間歎且驚，田間旱塊絲縱橫。',256,'全唐诗/poet.song.111000.json','["我行田間歎且驚，田間旱塊絲縱橫。", "荆榛惡草亦枯瘁，雖有稷黍何由生。", "田邊老人爲予語，欲語先愁淚如雨。", "老兒百指住山西，世業農桑不工賈。", "年年此田收好穀，玉粒長腰舂百斛。", "公私取給有贏餘，作飯爲麋肥口腹。", "今年旱種良辛苦，抱甕澆畦寧入土。", "囷傾舊穀已無餘，新穀疏蕪復如許。", "年年百指無憂畏，今年百指俱憔悴。", "餓死填溝自不辭，只愁逋負官家稅。", "即今官稅催輸入，督吏臨門如火急。", "老兒可是樂徵呼，其奈黍頭無一粒。", "我感翁言情激烈，却笑老翁言太拙。", "爲陳天子有深仁，子惠窮民念民切。", "况今官府皆時賢，會將租責都蠲捐。", "庶幾儉歲亦得飽，且與爾曹圖醉眠。"]'),
('c2f4d093-6ea2-4135-8b57-253233043d95','戲贈蜀僧清鑒','范浚','宋','宋诗','song-poetry','','[]','西川有一鑒子，非銅非鐵非鉛。',112,'全唐诗/poet.song.111000.json','["西川有一鑒子，非銅非鐵非鉛。", "不假江心百鍊，自然本體精堅。", "從來無臺可安，瑩磨拂拭都捐。", "歷歷森羅萬象，豈分胡漢蚩妍。", "旁人不敢窮窺，照渠肝膽懸懸。", "東來吳越萬里，依舊虛明湛然。", "識者知爲法寶，不識酬之幾錢。", "泥塵埋沒不得，光透三千大千。"]'),
('b301406b-9c52-42ad-8fdd-1d66b1008474','讀長門賦','范浚','宋','宋诗','song-poetry','','[]','阿嬌負恃顔姝好，那知漢帝恩難保。',256,'全唐诗/poet.song.111000.json','["阿嬌負恃顔姝好，那知漢帝恩難保。", "一朝秋水落芙蕖，幾歲長門閉春草。", "自憐身世等前魚，舊寵全移衛子夫。", "獨夜不眠香草枕，東箱斜月上金鋪。", "曉驚永巷車音近，失喜疑君枉瑶軫。", "臨風望幸立多時，却是輕雷聲隠隠。", "年年織女會牽牛，百子池邊侍宴遊。", "自從一落離宮後，無復穿針更上樓。", "長記髫年聘時節，愛深金屋寧衰歇。", "而今遽覺冷如冰，不解向人佯暖熱。", "愁看空樹集珍禽，孔翠追飛鸞鳳吟。", "顧步深嚬生悵望，伊誰一爲迴天心。", "人言消渴臨邛客，天下工文專大冊。", "黄金取酒奉文君，願悟君王賜顔色。", "賦成果得大家憐，鳳觜煎膠續斷絃。", "不似昭君離漢土，一生埋沒犬羊天。"]'),
('86c0c17d-c99e-48ea-8411-c291c11c4e85','上李舍人','范浚','宋','宋诗','song-poetry','','[]','李侯半天霞，絕俗幾千丈。',252,'全唐诗/poet.song.111000.json','["李侯半天霞，絕俗幾千丈。", "平生有勁氣，傲岸力高尚。", "波濤驅筆底，萬里一奔放。", "清風凜鬚眉，挺拔舍人樣。", "蚤以鴛鷺姿，簉羽邇天仗。", "拖綬奉朝請，論列專靡讓。", "言辭劇酸灼，貶竄辱傷謗。", "官資如馬足，曾不興怊悵。", "宴遊長笑傲，忠鯁期自諒。", "江山窮賞目，搜抉歸吟唱。", "於今富篇章，態度難悉况。", "精清極孤高，麗雅略談浪。", "乘豪騁雄怪，句法時跌宕。", "端如撫良琴，杳默變清亮。", "連篇時諷詠，飧寢每輒忘。", "我慚語俗下，有類牛鳴盎。", "遽耳咸池音，吟魂驚沮喪。", "聞之良匠氏，侏儒非冗長。", "醫師兼百藥，馬勃用或當。", "微言出堂下，挈手煩叔向。", "倘許揖戈鋋，願奉詩壇將。"]'),
('744fd5b3-9f37-4a69-b200-60077a6d3076','送徐彥思倅建安','范浚','宋','宋诗','song-poetry','','[]','君不聞詩人一席眠𥳌{𥫗窮}，夜泊建溪微月中。',134,'全唐诗/poet.song.111000.json','["君不聞詩人一席眠𥳌{𥫗窮}，夜泊建溪微月中。", "猶能即事慰岑寂，隔簾朗詠看朣朧。", "今君笑擁箳篂去，正有繁花明驛路。", "修程百越渺風烟，發興自應多麗句。", "知君踔越是名流，朱紱聊煩佐上州。", "貳政少安郎罷囝，却登要路贊皇猷。", "西風略略摇征旆，過往題詩援離袂。", "武夷鶴膝杖扶羸，寄我他時訪松桂。"]'),
('be2dbc1b-f839-478f-a54c-e387320c8af9','擬李太白笑矣乎','范浚','宋','宋诗','song-poetry','','[]','笑矣乎，笑矣乎。',254,'全唐诗/poet.song.111000.json','["笑矣乎，笑矣乎。", "交情貧富古已殊，翟公底用門間書。", "爾真自爾我自我，囂然將奈吾何如。", "笑矣乎，笑矣乎。", "世人那得相賢愚，是非正用一理樞。", "目光莫著牛背上，但付捧腹聊盧胡。", "笑矣乎，笑矣乎。", "是生百歲猶蘧廬，勿謾辛苦愁其軀。", "丁年無事且須醉，可待華髮傷頭顱。", "笑矣乎，笑矣乎。", "馮讙悲歌食無魚，少陵老跨東家馿。", "寧如三高飽斫鱠，坐嘯一舸凌烟湖。", "笑矣乎，笑矣乎。", "相隨出關漢兩疏，散資千萬荀隠居。", "彼皆棄置慕閑逸，得閒何乃翻區區。", "君不見向來熱手勢莫俱，側肩羹沸權門朱。", "又不見元家胡椒八百斛，石家水碓三十區。", "只今人骨久已朽，空餘古塚號寒狐。"]'),
('2c65d4e0-d140-4ce5-8246-67f761709dbd','龍游吳宰因勸農過寓居  其一','范浚','宋','宋诗','song-poetry','','[]','令君剖劇久推賢，人謂賢如百里天。',32,'全唐诗/poet.song.111000.json','["令君剖劇久推賢，人謂賢如百里天。", "最績已優恩已洽，訟堂無事日鳴絃。"]'),
('58fe6bfe-850a-4876-8859-8409aeb7bdec','龍游吳宰因勸農過寓居  其二','范浚','宋','宋诗','song-poetry','','[]','夙駕勤民力勸耕，肯停車軌訪柴荆。',32,'全唐诗/poet.song.111000.json','["夙駕勤民力勸耕，肯停車軌訪柴荆。", "誰言羈旅知交態，君似春風不世情。"]'),
('57856555-1a78-4c36-a02e-b79d98a91382','龍游吳宰因勸農過寓居  其三','范浚','宋','宋诗','song-poetry','','[]','阡陌東西馴雉鳴，陌頭父老望前旌。',32,'全唐诗/poet.song.111000.json','["阡陌東西馴雉鳴，陌頭父老望前旌。", "爭言字我今三歲，真是冰清見底清。"]'),
('b5665039-46a7-4371-9469-aa4c38cacafa','龍游吳宰因勸農過寓居  其四','范浚','宋','宋诗','song-poetry','','[]','雲根仙館駐鳬飛，倚閣遐觀笏拄頤。',32,'全唐诗/poet.song.111000.json','["雲根仙館駐鳬飛，倚閣遐觀笏拄頤。", "但賞春山多勝事，不知桃李被恩私。"]'),
('e993010f-8c8b-4f55-a073-7607e4e3d057','龍游王丞相過寓居  其一','范浚','宋','宋诗','song-poetry','','[]','邑丞族望邁平韋，謙槩能過白板扉。',32,'全唐诗/poet.song.111000.json','["邑丞族望邁平韋，謙槩能過白板扉。", "應是德門流慶遠，清芬今復繼烏衣。"]'),
('22b034c6-1527-48f3-ae17-20eb57190ef8','龍游王丞相過寓居  其二','范浚','宋','宋诗','song-poetry','','[]','能事知君不負丞，况逢令長著賢聲。',32,'全唐诗/poet.song.111000.json','["能事知君不負丞，况逢令長著賢聲。", "同心坐了公家事，那肯空書紙尾名。"]'),
('6e6bf1bd-b013-4b8e-9207-a637949ace9a','龍游王丞相過寓居  其三','范浚','宋','宋诗','song-poetry','','[]','君家丞相世豪英，字畫文章不朽名。',32,'全唐诗/poet.song.111000.json','["君家丞相世豪英，字畫文章不朽名。", "盥手何時披墨妙，烏絲欄上看真行。"]'),
('2935cd40-2c76-4860-8b80-f62061a4ffd6','四月一日偶成三絕句奉勉諸友  其一','范浚','宋','宋诗','song-poetry','','[]','麥風澹蕩氣清和，又見陰陰夏木多。',32,'全唐诗/poet.song.111000.json','["麥風澹蕩氣清和，又見陰陰夏木多。", "試問社中同志士，經春舉力竟如何。"]'),
('5d332716-0b8e-46b4-8893-96b26b7ea289','四月一日偶成三絕句奉勉諸友  其二','范浚','宋','宋诗','song-poetry','','[]','日正舒長好著鞭，會須聞早慕高堅。',32,'全唐诗/poet.song.111000.json','["日正舒長好著鞭，會須聞早慕高堅。", "君看少壯荒嬉子，多向衰遲却諱年。"]'),
('bdf2c0cd-b43b-4f0f-86c0-0d5a2604789c','四月一日偶成三絕句奉勉諸友  其三','范浚','宋','宋诗','song-poetry','','[]','讀書意緒戒荒蕪，要使心清一事無。',32,'全唐诗/poet.song.111000.json','["讀書意緒戒荒蕪，要使心清一事無。", "過眼飛光流水急，莫矜頤頷始生鬚。"]'),
('d213c243-f516-4e3b-b4df-4c7b610b0c1b','送李國佐還三衢','范浚','宋','宋诗','song-poetry','','[]','昔人好與勝己處，今世陋學多專愚。',64,'全唐诗/poet.song.111000.json','["昔人好與勝己處，今世陋學多專愚。", "惜哉計出柏馬下，往往自足令人吁。", "子今年少且競爽，徑拂歸袖真良圖。", "人言十步有茂草，行矣求益無躊躇。"]'),
('951b2882-f3be-4032-8020-5414a8cd9021','送趙安伯縣丞之任婺源','范浚','宋','宋诗','song-poetry','','[]','邑丞清操如臞儒，人言帝宗千里駒。',160,'全唐诗/poet.song.111000.json','["邑丞清操如臞儒，人言帝宗千里駒。", "燃膏夜絕學更苦，下筆欲命騷爲奴。", "往年給札試西省，堵牆學士紛驚呼。", "歸來汀草亂袍色，上食日向庭闈趨。", "君家先烈今誰如，江州黄州忠義俱。", "綠林豪客爲蒲伏，刮腸洗胃投戈殳。", "我方三歎揖盛事，欲紀勁節慚才蕪。", "君其努力濟世美，倘登要路須捐軀。", "春流起柂花芬敷，取別草草如驚鳬。", "君逢後日南來客，莫忘書札貽潛夫。"]'),
('902ff2fd-1d4d-46ce-be4d-1239668ccda5','凌霄花','范浚','宋','宋诗','song-poetry','','[]','栽松待成陰，種漆擬作器。',96,'全唐诗/poet.song.111000.json','["栽松待成陰，種漆擬作器。", "人皆笑艱拙，往往後得利。", "君看植凌霄，百尺蔓柔翠。", "新花鬰煌煌，照日吐妍媚。", "風霜忽摇落，大木亦彫瘁。", "視爾托根生，枯莖無殘蔕。", "先榮疾蕭瑟，物理固艱恃。", "凌霄亟芳華，衰歇亦容易。"]'),
('ac1ebfb5-2f7e-44d4-8b55-2384b6945fb6','題武康唐伯南掃月軒','范浚','宋','宋诗','song-poetry','','[]','竹影掃秋月，乃是仙人詩。',96,'全唐诗/poet.song.111000.json','["竹影掃秋月，乃是仙人詩。", "至今幽隠士，想像沙塘陂。", "開軒笑長風，坐看山月吐。", "修篁出清姿，會作婆娑舞。", "莫遣兒輩覺，此樂無人知。", "誰家復多竹，風月同幽期。", "幸當語竹弟，俗士久暌闕。", "主人倘無嫌，爲掃石上月。"]'),
('203521a8-ae4f-447b-af37-0258228705fe','寄題鄭亨仲可友亭','范浚','宋','宋诗','song-poetry','','[]','鄭君坐交窮，結柳窮不去。',120,'全唐诗/poet.song.111000.json','["鄭君坐交窮，結柳窮不去。", "無朋長獨立，老大荒村住。", "荒村掃人迹，取友惟西山。", "當應愛山標，可望不可攀。", "牽蘿架風亭，嶻嶭揖高調。", "修簷入危碧，阮眼坐相照。", "嗟今輕薄子，對面生九疑。", "寧如友真山，貞質終無移。", "憐君意超超，愧我勞勿勿。", "未共結交心，漫負心脾骨。"]'),
('fe9a6298-064f-441d-b579-6f8bd76376b5','四睡次三兄茂載韵  其一','范浚','宋','宋诗','song-poetry','','[]','門外啼鴉暗柳濃，華堂翠幕度香風。',32,'全唐诗/poet.song.111000.json','["門外啼鴉暗柳濃，華堂翠幕度香風。", "流鶑不識夢魂遠，自向窗前訴落紅。"]'),
('8883162e-1fc2-4fe9-9480-6356a321314c','四睡次三兄茂載韵  其二','范浚','宋','宋诗','song-poetry','','[]','水亭珍簟卧瑠璃，日暮凉生小雨催。',32,'全唐诗/poet.song.111000.json','["水亭珍簟卧瑠璃，日暮凉生小雨催。", "誰刺蓮船過前渚，榜歌聲落枕邊來。"]'),
('ac68a0cb-d7bc-4edc-81de-facab16ed531','四睡次三兄茂載韵  其三','范浚','宋','宋诗','song-poetry','','[]','小窗卧冷聽吟蛩，半擁輕衾乍怯風。',32,'全唐诗/poet.song.111000.json','["小窗卧冷聽吟蛩，半擁輕衾乍怯風。", "清夢不成空有恨，蕭騷疏雨打梧桐。"]'),
('5c232211-eaa9-4d63-a64f-23c3feaee38a','四睡次三兄茂載韵  其四','范浚','宋','宋诗','song-poetry','','[]','滿面風霜道上兒，箝銜口角甲生肌。',32,'全唐诗/poet.song.111000.json','["滿面風霜道上兒，箝銜口角甲生肌。", "幽人只有高眠興，雪擁柴門了不知。"]'),
('615d6b87-55ee-4535-b05b-710814b043cf','暮春病起絕句二首  其一','范浚','宋','宋诗','song-poetry','','[]','病起春深白晝閑，瓦松花老掩柴關。',32,'全唐诗/poet.song.111000.json','["病起春深白晝閑，瓦松花老掩柴關。", "坐調心息無浮念，沉水烟銷古博山。"]'),
('322ffc90-bc52-44af-8e83-43f4086af965','暮春病起絕句二首  其二','范浚','宋','宋诗','song-poetry','','[]','老去長閑百不營，推書習靜更真清。',32,'全唐诗/poet.song.111000.json','["老去長閑百不營，推書習靜更真清。", "西窗日脚籬篩動，時有飛蟲撲紙聲。"]'),
('25d11313-da29-45ce-b260-e1072fdf244b','浦江華藏寺如勝上人欲募施者開田佐僧供以長老皎公書來求予詩作二十韵奉勉','范浚','宋','宋诗','song-poetry','','[]','浮圖謝朋親，屏跡藏巖幽。',240,'全唐诗/poet.song.111000.json','["浮圖謝朋親，屏跡藏巖幽。", "多規脫徭賦，豈必皆禪流。", "自言佛遺經，墾土爲愆尤。", "不耕徒穀腹，何異鼠雀偷。", "告之勿浮食，當須力鋤耰。", "前修舉鍬事，千載垂風猷。", "奈何啞羊僧，百語不頷頭。", "皎公老禪伯，雅慕吾孔周。", "其徒有如勝，用意非常儔。", "欲開千畦田，更辦兩具牛。", "率彼枯木衆，躬耕食其秋。", "釋門有添丁，乃翁坐無憂。", "與國助耘耔，疲甿庶其瘳。", "此志良足嘉，感之歎綢繆。", "昔聞白黑衆，十萬俱清修。", "鳩金置千畝，給供無時休。", "於今豈無人，勝也當尋求。", "長途觸隆冬，一衲寒颼飀。", "朱門立雪久，歡喜無生愁。", "作詩勸勇往，以俟歲晚收。"]'),
('8a254798-b04a-4b48-8333-1fad8fbe0af5','郊行探春得梅林攀玩爲樂因成詩示偕行','范浚','宋','宋诗','song-poetry','','[]','公不見白衣居士春風裏，浪走尋芳南澗底。',163,'全唐诗/poet.song.111000.json','["公不見白衣居士春風裏，浪走尋芳南澗底。", "要見深紅躑躅花，不辭辛苦行三里。", "吾人風味復不惡，異代幽情敢相擬。", "故穿密竹過山腰，却下橫橋度沙嘴。", "寧甘著脚踏殘雪，正欲搜春訪桃李。", "天寒桃李都未花，只有山梅破紅蕊。", "低欹巖石俯蒼翠，倒影方塘照清泚。", "臨風三嗅忍迴頭，細看長吟聊徙倚。", "牽花及此當作意，歸把疏香泛浮蟻。", "莫令摽落亂飛空，惆悵殘英隨隴水。"]'),
('b0296bce-4713-4dd7-9415-2f3ff985c5c2','次韵樓仲輝郎中游天王寺登城晚歸三絕句  其一','范浚','宋','宋诗','song-poetry','','[]','㸌㸌城頭五丈旗，萬人輦土事增陴。',32,'全唐诗/poet.song.111000.json','["㸌㸌城頭五丈旗，萬人輦土事增陴。", "念當拔白俱登守，恨乏驍雄濟一時。"]'),
('5dbf0de7-f069-41ff-aeb6-a258b6ce900e','次韵樓仲輝郎中游天王寺登城晚歸三絕句  其二','范浚','宋','宋诗','song-poetry','','[]','春來物色已爭妍，梅柳低昂古道邊。',32,'全唐诗/poet.song.111000.json','["春來物色已爭妍，梅柳低昂古道邊。", "放步徑從蓮社去，逃禪要學飲中仙。"]'),
('0c3fef8c-1f76-403c-9b78-a9ece2c6d81f','次韵樓仲輝郎中游天王寺登城晚歸三絕句  其三','范浚','宋','宋诗','song-poetry','','[]','歸路行吟慘夕風，愁煩聊遣酒兵攻。',32,'全唐诗/poet.song.111000.json','["歸路行吟慘夕風，愁煩聊遣酒兵攻。", "也知念國髭鬚白，不忘朝廷醉眼中。"]'),
('379cfc47-3939-4525-86ae-38a694d7039e','次韵姪端臣感興','范浚','宋','宋诗','song-poetry','','[]','日車走長天，劫劫不容息。',144,'全唐诗/poet.song.111000.json','["日車走長天，劫劫不容息。", "坐令韶稚子，面有凍梨色。", "崎嶇百年內，貴賤俱物役。", "獨往屬幽人，膏肓嗜泉石。", "伊予真愛山，所向留屐跡。", "遥岑難歷脚，望望憐寸碧。", "阿卿昨遠遊，厭俗眼常白。", "歸來對家山，隨遇有餘適。", "哦詩洗窮愁，感事念今昔。", "婆娑碧溪上，俛仰欣自得。", "應嗤曩行路，萬事等兒劇。", "相期從此始，幽賞且連夕。"]'),
('004d3775-0ee8-471b-8850-a361d8b56713','次韵婺守林懿成檢正游赤松絕句四首  其一','范浚','宋','宋诗','song-poetry','','[]','寶積峯前露朮香，使君行旆照晴陽。',32,'全唐诗/poet.song.111000.json','["寶積峯前露朮香，使君行旆照晴陽。", "佳遊會自希高躅，可是空尋叱石羊。"]'),
('3093604c-ad96-4fe0-a417-bf0fdc043b57','次韵婺守林懿成檢正游赤松絕句四首  其二','范浚','宋','宋诗','song-poetry','','[]','黄堂流化古風還，夙駕勤民隴畝間。',32,'全唐诗/poet.song.111000.json','["黄堂流化古風還，夙駕勤民隴畝間。", "已變呻吟作謠詠，山中那用覓還丹。"]'),
('082edb3b-91f8-4e50-866b-e709e0f270f2','次韵婺守林懿成檢正游赤松絕句四首  其三','范浚','宋','宋诗','song-poetry','','[]','紫烟仙客古祠堂，青士蒼官屹道傍。',32,'全唐诗/poet.song.111000.json','["紫烟仙客古祠堂，青士蒼官屹道傍。", "想見隼旟穿翠帳，有人迎路曉騎羊。"]'),
('7c4fd25d-ef8d-44fa-aa91-c6f7227d0e4f','次韵婺守林懿成檢正游赤松絕句四首  其四','范浚','宋','宋诗','song-poetry','','[]','殿邦政蹟茂棠陰，著屐題詩寄意深。',32,'全唐诗/poet.song.111000.json','["殿邦政蹟茂棠陰，著屐題詩寄意深。", "應有高人陪皂蓋，烟蘿深處得幽尋。"]'),
('9135ba6e-8001-4624-aa66-51aa609011a9','次韵姪端臣喜雨','范浚','宋','宋诗','song-poetry','','[]','初弦落微月，草宇夜岑寂。',144,'全唐诗/poet.song.111000.json','["初弦落微月，草宇夜岑寂。", "追凉拂桃笙，伸欠聊偃息。", "檐榮忽飛雨，散亂銀竹白。", "避漏起移床，青燈暈空壁。", "曉看蛙入戶，時有燕爲石。", "是節正驕陽，敲煩火雲赤。", "煩蒸等坐甑，百體勞按抑。", "良苗憂槁暴，空有庭樹碧。", "借免抱龜腸，猶應困蔬色。", "炎埃今一洗，萬井沐甘澤。", "望歲即交歡，寧容須暇隙。", "相逢如得酒，釂飲莫餘瀝。"]'),
('837ee7f2-b8c5-4b7a-ac18-a9f889ec7052','送別姚令聲刪定還諸暨','范浚','宋','宋诗','song-poetry','','[]','昔嗟九載一相見，伊我與君俱賦詩。',128,'全唐诗/poet.song.111000.json','["昔嗟九載一相見，伊我與君俱賦詩。", "只今又話十年別，襆被可辭同宿期。", "相歡美酒如傾水，我歌日暮驚風起。", "惜君抑塞抱奇才，拳跼驊騮垂兩耳。", "漢朝公卿忌賈生，世路古已悲難行。", "如君不入中興用，脫帽置酒來耦耕。", "君馬欲東還語別，細雨黄花正愁絕。", "一尊不更苦留君，後日空嗟共明月。"]'),
('35fb7670-ba8c-44dc-9c96-3e5b7da1f9f9','示姪','范浚','宋','宋诗','song-poetry','','[]','華顛老學似秉燭，及壯貴在勤書詩。',192,'全唐诗/poet.song.111000.json','["華顛老學似秉燭，及壯貴在勤書詩。", "男兒不解事文筆，何異婦女留鬚眉。", "予生早已度弱冠，畋漁籍素常嗟遲。", "爾今年纔十八九，著力鑽礪誠當時。", "胡爲講道率粗滅，浪自閑散多盤嬉。", "或時使酒昧檢束，怒駡臧獲驚紛披。", "我旁聞爾作氣勢，憐爾放驁如癡兒。", "人生稟受性不惡，鞚馭要使知高低。", "常時見爾亦遜順，頓以狂藥生尤違。", "便當懲艾悼往失，痛戒濡首疏尊巵。", "專心蓄力玩經笥，調護氣術循繩規。", "吾言一日可三復，勿謂浪語無資裨。"]'),
('eeef86c5-02a2-4aa5-a2c1-ace6999d9d11','示友','范浚','宋','宋诗','song-poetry','','[]','忍過事堪喜，斯言良不欺。',156,'全唐诗/poet.song.111000.json','["忍過事堪喜，斯言良不欺。", "當須去鉗忌，佩服西門韋。", "君看朋徒間，契濶多暌離。", "胡不事久要，有酒歡樂之。", "顧於毛髮輕，溢惡相嗔嗤。", "平生結情好，一旦成乖違。", "譏呵起交攻，醜語剝面皮。", "空貽兩不快，呀喘如筒吹。", "吾聞西山翁，棄惡怨用希。", "男子固尚氣，何以睚眥爲。", "請君謝犬尾，脫略除嫌疑。", "自然鄰曲交，耐久歡相持。", "儻復不自慰，君當讀吾詩。"]'),
('4e7fbf02-54a8-4bda-9107-3a1a81c6ce11','送張子經撫幹還臨安幕','范浚','宋','宋诗','song-poetry','','[]','一昨暌離五換年，相逢道舊各欣然。',96,'全唐诗/poet.song.111000.json','["一昨暌離五換年，相逢道舊各欣然。", "已陪文酒四百刻，更得車斜二十篇。", "君家閣老名能賦，蓬萊扈遊方遇主。", "吞曹奪李杜陵翁，句律從來付宗武。", "如君才藻信踰人，著帽猶爲入幕賓。", "別去當須自珍寵，行看策足出風塵。"]'),
('518fb2ec-3867-4754-9b67-170d180aa30e','送葉彥益縣丞之任江寧','范浚','宋','宋诗','song-poetry','','[]','君不聞赤縣詩人書案牘，兩衙苦被官拘束。',131,'全唐诗/poet.song.111000.json','["君不聞赤縣詩人書案牘，兩衙苦被官拘束。", "自嫌不辨世間忙，猶得吟看縣牆綠。", "今君器度鼎函牛，爲丞烹鮮餘地優。", "更當淥水吳京邑，豪士新亭舊勝遊。", "去追禮樂羣英盛，豈復區區勞貳令。", "兩株松下日長哦，會有劉郎五題詠。", "能來取別思依然，爲我津頭一繫船。", "解手看君有知己，吹噓高翮上青天。"]'),
('4e11bfc1-687c-4f7d-ab0a-3340c0fc53ae','對酒分和杜詩','范浚','宋','宋诗','song-poetry','','[]','桃花朱朱李花白，高柳花邊出多碧。',64,'全唐诗/poet.song.111000.json','["桃花朱朱李花白，高柳花邊出多碧。", "雨中物色更芳鮮，未礙劉郎中一石。", "醺酣裁詩角險麗，坐人豪逸俱勍敵。", "但令得醉復長吟，山雲從爾生虛壁。"]'),
('18d1b0c1-64c3-4567-8b9f-73934cc261f3','遊赤松觀','范浚','宋','宋诗','song-poetry','','[]','靈祠丹井餘真跡，祠下老松森百尺。',32,'全唐诗/poet.song.111000.json','["靈祠丹井餘真跡，祠下老松森百尺。", "仙子騎鯨去不歸，癡人猶問山中石。"]'),
('b84e186f-1cd8-440c-aa60-5670c6403a5a','次韵弟茂通立春四首  其一','范浚','宋','宋诗','song-poetry','','[]','物華俱入發生辰，喜見花梢刺眼新。',32,'全唐诗/poet.song.111000.json','["物華俱入發生辰，喜見花梢刺眼新。", "便好銜杯嚼紅蕊，不須枝上火燒春。"]'),
('58670d37-8f0e-4aac-a6e7-6163f6219685','次韵弟茂通立春四首  其二','范浚','宋','宋诗','song-poetry','','[]','青青覆雉麥畦肥，柳線輕黄拂面垂。',32,'全唐诗/poet.song.111000.json','["青青覆雉麥畦肥，柳線輕黄拂面垂。", "擬贈物華無麗句，徒慚口業未拋詩。"]'),
('5825989e-6194-4e10-bb72-2be158724112','次韵弟茂通立春四首  其三','范浚','宋','宋诗','song-poetry','','[]','春生稚戲我難同，聊復題詩方絮紅。',32,'全唐诗/poet.song.111000.json','["春生稚戲我難同，聊復題詩方絮紅。", "忽得池塘夢中語，知君句律有新功。"]'),
('ce7f7844-951d-40a4-b1dd-72e87fad3520','次韵弟茂通立春四首  其四','范浚','宋','宋诗','song-poetry','','[]','富人百屋看錢堆，不省東風幾日來。',32,'全唐诗/poet.song.111000.json','["富人百屋看錢堆，不省東風幾日來。", "報答春光須我輩，要當劇飲縱歡咍。"]'),
('5d2e7706-78ef-41b8-b063-c1a2c34b5f61','贈清鑒上人','范浚','宋','宋诗','song-poetry','','[]','川勤直下生馬駒，早追奔電越國都。',128,'全唐诗/poet.song.111000.json','["川勤直下生馬駒，早追奔電越國都。", "至今不肯著槽廄，蹴蹋萬里浮江湖。", "我來古寺長松下，邂逅解包逢藞䕢。", "尚看秀色带峨眉，墨玉貫珠常在把。", "問今客路迷風沙，得無勞苦行天涯。", "笑言煩惱真佛事，去家千里猶吾家。", "休公昔生我鄉曲，一瓶得得遊西蜀。", "鑒今却自蜀中來，好住蘭陰結茅屋。"]'),
('5abc5f61-8b3b-452e-b6e3-15e2d4b8338c','寄題趙叔才秀芝堂','范浚','宋','宋诗','song-poetry','','[]','君不見邯鄲邑令昔好奇，强指金燈花作芝。',99,'全唐诗/poet.song.111000.json','["君不見邯鄲邑令昔好奇，强指金燈花作芝。", "得非美瑞世罕見，遂假凡草相漫欺。", "君家聞有真三秀，近出高楹照簷霤。", "不須仙客費耘鋤，協氣蒸成自榮茂。", "信知爲善來嘉祥，得此上藥扶年長。", "庭階令子映蘭玉，要使如芝冠衆芳。"]'),
('f8a39527-5ed5-4775-bb72-2ba29d66145b','苦寒行','范浚','宋','宋诗','song-poetry','','[]','君不見詩人著布裘，願得大裘一萬里。',82,'全唐诗/poet.song.111000.json','["君不見詩人著布裘，願得大裘一萬里。", "又不見詩人歎茅屋，願得廣厦千萬間。", "重堂複宇御狐白，今世誰念人多寒。", "我衣穿空垂百結，蓬蘿蓋頭四壁裂。", "却顧悲號窮獨人，露宿牛衣冷如鐵。"]'),
('f0facbc6-2cbc-4406-bfa2-af3c5e405eeb','淒凉行','范浚','宋','宋诗','song-poetry','','[]','君不見神羊觸邪世不省，舞馬應節披華衣。',78,'全唐诗/poet.song.111000.json','["君不見神羊觸邪世不省，舞馬應節披華衣。", "又不見屈軼指佞沒空草，合歡蠲忿生庭墀。", "勳華一去幾千載，神羊屈軼令人悲。", "二物不可見，我悲何日忘。", "喧啾聞反舌，炎夏亦淒涼。"]'),
('9d0a168b-5eb8-4d04-bb7a-eb6e03983235','三月廿六日夜同姪端臣端杲觀異書效李長吉體','范浚','宋','宋诗','song-poetry','','[]','楊花亂落青春暮，燕拂簾旌傍人語。',64,'全唐诗/poet.song.111000.json','["楊花亂落青春暮，燕拂簾旌傍人語。", "縹壺買酒洗春愁，迴風落日簷花舞。", "赫蹏斷爛千載書，青燈照字驚蟫魚。", "冬烘老生時自哂，安用盤盂學田蚡。"]'),
('35295185-bf52-46f2-b9da-0ff71333ab30','四月十六日同弟姪效李長吉體分韵得首字','范浚','宋','宋诗','song-poetry','','[]','黄梅雨歇春歸後，摶黍哺雛鳩喚婦。',64,'全唐诗/poet.song.111000.json','["黄梅雨歇春歸後，摶黍哺雛鳩喚婦。", "紅殘小頰蹊上花，翠刷濃眉陌頭柳。", "籜痕半脫煙篁瘦，露裛幽香逗書牖。", "雲容漠漠曉陰愁，麥信風前一搔首。"]'),
('d19d983c-920e-4c2b-aa49-cd3f67277ce0','偶作二首  其一','范浚','宋','宋诗','song-poetry','','[]','晏食聊當肉，緩步聊當車。',48,'全唐诗/poet.song.111000.json','["晏食聊當肉，緩步聊當車。", "身閑貴莫比，心足富有餘。", "時飲一杯酒，歷觀千載書。", "正爾良獨難，亦復將何須。"]'),
('da25998e-725c-4a21-83bb-a96339082834','偶作二首  其二','范浚','宋','宋诗','song-poetry','','[]','飛花拂簾幌，亦有關籬牆。',48,'全唐诗/poet.song.111000.json','["飛花拂簾幌，亦有關籬牆。", "隨風各偶爾，何足較短長。", "富貴真傳舍，易人豈其常。", "寄語窮巷士，少安無自傷。"]'),
('477d4ef5-a8ce-4229-889c-a2af391d28c8','狂泉','范浚','宋','宋诗','song-poetry','','[]','昔有大荒國，水以狂泉名。',168,'全唐诗/poet.song.111000.json','["昔有大荒國，水以狂泉名。", "國人皆飲泉，狂顛率無寧。", "一者自穿汲，乃獨能常醒。", "國人既皆狂，反見不狂驚。", "顧謂不狂人，無乃鬼物憑。", "不然是狂疾，救療當痊輕。", "施針灼炷艾，膚肉無全平。", "而彼不狂者，被虐楚不勝。", "賁然走泉所，酌飲不敢停。", "既飲即亦狂，萬慮皆迷冥。", "其狂與衆一，衆始歡相傾。", "世事今亦然，嗟哉感詩鳴。", "安得跨鵬背，獨往遊天溟。", "寄謝彼狂子，酌泉吾不能。"]'),
('d6152745-a376-48a5-8a30-2dd5266143f4','次韵六兄茂永論有無之作','范浚','宋','宋诗','song-poetry','','[]','磨磚不成鏡，畫餠不可食。',120,'全唐诗/poet.song.111000.json','["磨磚不成鏡，畫餠不可食。", "談空如畫餠，要匪實消息。", "泥有如磨磚，未免見排闢。", "籌量有無中，背道費尋覓。", "先天爲心祖，此事冥太易。", "空毋墮渺茫，有勿著聲色。", "勿同半生滅，邪見徒役役。", "萬有齊一虛，寥廓鳥無跡。", "至虛本非無，豈謂滯神識。", "佳哉僧肇論，妙意真的的。"]'),
('110aa1a4-055a-4bf7-864d-5765414ce650','己巳十二月廿九日同姪端臣端杲觀王右軍帖并晉書以白藕薦酒成詩','范浚','宋','宋诗','song-poetry','','[]','星回景急歲聿除，更長燭明坐蓬廬。',96,'全唐诗/poet.song.111000.json','["星回景急歲聿除，更長燭明坐蓬廬。", "東風夜半欲入律，萬木先已爭號呼。", "小阮過予足風味，共觀古帖披前志。", "秋蛇綰字右軍書，朔馬騰風東晉記。", "紛紜萬古浩無涯，且啖白藕傾流霞。", "分甘恨不如船大，空想峰頭十丈花。"]'),
('cfa37741-79e7-445b-ac56-5652ffbc568a','池上晚酌','范浚','宋','宋诗','song-poetry','','[]','雨餘池上興悠哉，坐蔭藤花藉石苔。',64,'全唐诗/poet.song.111000.json','["雨餘池上興悠哉，坐蔭藤花藉石苔。", "白鳥聯拳相對立，紅蕖粲艷一時開。", "吐吞月色雲濃淡，經緯水紋風去來。", "幽事相關心自樂，岸巾獨嘯更銜杯。"]'),
('28dfa55e-20f1-4145-9a40-5fd39964e70c','題雙清堂','范浚','宋','宋诗','song-poetry','','[]','市合喧華外，堂開磊落明。',48,'全唐诗/poet.song.111000.json','["市合喧華外，堂開磊落明。", "大山橫面勢，積水带渟瀠。", "野靜讙蛙斷，林幽獨鳥鳴。", "杜陵詩句在，心跡喜雙清。"]'),
('2110dd14-4a9f-4576-8c4d-a392bb578194','陶潛詠','范浚','宋','宋诗','song-poetry','','[]','五箇門前柳，千年身後名。',48,'全唐诗/poet.song.111000.json','["五箇門前柳，千年身後名。", "掛冠真避俗，自祭頗忘情。", "且進杯中物，何勞絃上聲。", "詩篇經李杜，猶得擅精清。"]'),
('726ad315-e760-4978-8695-da4fad3ff05b','次韵六兄茂永首夏新晴','范浚','宋','宋诗','song-poetry','','[]','燕落雨知節，鳩鳴天欲晴。',48,'全唐诗/poet.song.111000.json','["燕落雨知節，鳩鳴天欲晴。", "行雲飛斷碧，斜日漏微明。", "筍上竹三徑，苗肥田一成。", "野人知得飽，索酒坐班荆。"]'),
('eda6983b-189a-43af-96dc-cd8c105cac0d','題四兄茂安藏春園','范浚','宋','宋诗','song-poetry','','[]','春入名園何處尋，東風引步上嶇嶔。',64,'全唐诗/poet.song.111000.json','["春入名園何處尋，東風引步上嶇嶔。", "平凝四面雲嵐合，曲折一丘花木深。", "碧草華滋迷絕徑，綠蘿陰影護芳林。", "韶光向此知歸處，長與先生供醉吟。"]'),
('e9c05dfa-7077-434c-b2d1-0945d5e5cd8c','題四兄茂安秀野亭','范浚','宋','宋诗','song-poetry','','[]','山作屏風雲作籬，岧嶢亭子俯漣漪。',64,'全唐诗/poet.song.111000.json','["山作屏風雲作籬，岧嶢亭子俯漣漪。", "絕知此地風光好，直爲主人心跡奇。", "側塞亂花紅被徑，檀欒高竹翠緣陂。", "惠連自喜陪幽賞，判却歸時倒接䍦。"]'),
('d1d0c0e0-bd56-404e-bed6-bb054455f437','次韵弟茂通晚晴','范浚','宋','宋诗','song-poetry','','[]','浮雲捲盡綺霞明，藜杖扶行得晚晴。',64,'全唐诗/poet.song.111000.json','["浮雲捲盡綺霞明，藜杖扶行得晚晴。", "斜日水邊鸂鶒影，孤煙林外鵓鳩聲。", "且從樂處安心地，可向艱時觸志兵。", "幽意欲言言不得，因君聊復動詩情。"]'),
('58f18a29-aaca-4696-bdb7-a7d80b404250','歲暮喜晴','范浚','宋','宋诗','song-poetry','','[]','晴山喜見曉巑岏，笑出蓬門不暇冠。',64,'全唐诗/poet.song.111000.json','["晴山喜見曉巑岏，笑出蓬門不暇冠。", "風掃斷雲齊萬弩，日融殘雪上三竿。", "早黄楊柳漏春信，晚翠枇杷凌歲寒。", "從此林芳入幽賞，凍醪新壓味甘酸。"]'),
('35da71f5-5ed6-446c-b7dc-72a1f8b27237','初冬郊行','范浚','宋','宋诗','song-poetry','','[]','空闊野雲疏，行行思鬰紆。',48,'全唐诗/poet.song.111000.json','["空闊野雲疏，行行思鬰紆。", "露花啼晚菊，風葉舞高梧。", "日落牛羊下，天寒雁鶩呼。", "却回南澗路，暝色擁蓬廬。"]'),
('f9871caf-7a3e-4be4-bbac-b871058d909a','遊嚴州景德寺','范浚','宋','宋诗','song-poetry','','[]','出郭雨初霽，到山雲欲無。',48,'全唐诗/poet.song.111000.json','["出郭雨初霽，到山雲欲無。", "老松看偃蹇，幽徑上崎嶇。", "佛屋藏巖曲，天花舞坐隅。", "向來愁絕意，此地一醒蘇。"]'),
('5cc8dabe-9519-4b1c-b5c5-f26a6196dec1','雨後出郊二首  其一','范浚','宋','宋诗','song-poetry','','[]','晴景收林靄，春郊剩物華。',48,'全唐诗/poet.song.111000.json','["晴景收林靄，春郊剩物華。", "麴塵官道柳，粉艷野牆花。", "竹裏草亭古，沙邊苔徑邪。", "遣心知有處，發興渺無涯。"]'),
('ac0d1974-2b1b-46f9-8ea5-e29511894034','雨後出郊二首  其二','范浚','宋','宋诗','song-poetry','','[]','扶輿穿密竹，度彴過前溪。',48,'全唐诗/poet.song.111000.json','["扶輿穿密竹，度彴過前溪。", "霽色煙橫野，春聲水繞畦。", "映山行白鷺，遷木韵黄鸝。", "客裏貪幽事，歸時日已西。"]'),
('00c1ff40-06fb-4970-961f-57b689460cb8','登富陽觀山亭','范浚','宋','宋诗','song-poetry','','[]','弭棹依寒渚，臨亭俯碧川。',48,'全唐诗/poet.song.111000.json','["弭棹依寒渚，臨亭俯碧川。", "嘶雲征海雁，椎鼓過風船。", "水闊天低樹，山空日暝煙。", "擬題江似練，終愧謝公賢。"]'),
('93b584d5-3034-4b27-bec2-afa406a13b85','張子經示所得後湖居士詩及書札想見其人寄意短韵','范浚','宋','宋诗','song-poetry','','[]','後湖翰墨真追古，前輩風流獨到今。',64,'全唐诗/poet.song.111000.json','["後湖翰墨真追古，前輩風流獨到今。", "二月書題看六紙，一篇詩律抵千金。", "周郎酒裏君相得，韋九花間我欲尋。", "飯顆山頭如會遇，慇懃爲道仰高心。"]'),
('5657fa87-0ad3-4b7a-82a0-c4574ecf4d2b','次韵姪端臣晚行南溪','范浚','宋','宋诗','song-poetry','','[]','幽草轉溪路，瘦藤扶我行。',48,'全唐诗/poet.song.111000.json','["幽草轉溪路，瘦藤扶我行。", "鯈魚知有樂，鷗鳥共忘情。", "嵂崒望中色，𨊵輈何處聲。", "賞心成朗詠，巢鶴不須驚。"]'),
('6dd07b71-4002-4fc5-b8e7-6bc76d31a3c9','課畦丁灌園','范浚','宋','宋诗','song-poetry','','[]','連筒隔竹度流泉，約束畦丁灌小園。',64,'全唐诗/poet.song.111000.json','["連筒隔竹度流泉，約束畦丁灌小園。", "拔薤自須還種白，刈葵輒莫苦傷根。", "瓜疇准擬狸頭大，草徑隄防馬齒繁。", "努力荷鋤當給酒，無令菜把乏朝昏。"]'),
('d4176a07-6432-4aab-af62-2103ce20b4c7','春望二首  其一','范浚','宋','宋诗','song-poetry','','[]','岑樓上獨園，高檻俯平原。',48,'全唐诗/poet.song.111000.json','["岑樓上獨園，高檻俯平原。", "野秀風烟合，春深草木繁。", "晴山明歷歷，遠水去渾渾。", "興出青冥外，心隨獨鶴翻。"]'),
('23d356c9-4825-4970-89b0-21823b93241a','春望二首  其二','范浚','宋','宋诗','song-poetry','','[]','眺聽不知暮，徘徊聊復吟。',48,'全唐诗/poet.song.111000.json','["眺聽不知暮，徘徊聊復吟。", "歸雲迷近谷，去鳥度前林。", "長日憑高目，傷春望遠心。", "邊方殺氣在，天北慘沉陰。"]'),
('397a18c4-7ead-48fa-a9c4-bcb622dc047d','讀孔北海傳','范浚','宋','宋诗','song-poetry','','[]','歎息東京亂，忠推北海豪。',48,'全唐诗/poet.song.111000.json','["歎息東京亂，忠推北海豪。", "未容禾女鬼，輒代卯金刀。", "義概秋霜勁，英名白日高。", "猶應凜生氣，遣恨失吞曹。"]'),
('e0809024-e395-4adc-ace4-f0b7eccd329e','春雪晚晴出西村','范浚','宋','宋诗','song-poetry','','[]','步屐尋春犯雪泥，村南村北鵓鳩啼。',64,'全唐诗/poet.song.111000.json','["步屐尋春犯雪泥，村南村北鵓鳩啼。", "墮梅殘白猶明樹，著柳暗黄初映堤。", "風景快晴雲擘絮，江天未暮日懸規。", "最憐碧漲侵沙尾，更傍橫橋一杖藜。"]'),
('10c1e924-5845-4e64-8846-ab648d64b950','送周西美主簿之任祁門','范浚','宋','宋诗','song-poetry','','[]','君向祁山去，修程幾日期。',48,'全唐诗/poet.song.111000.json','["君向祁山去，修程幾日期。", "江天梅子雨，驛路橘花時。", "知迫循陔養，寧辭糾邑卑。", "美才無不適，鸞翮豈棲遲。"]'),
('de7b5703-f298-451d-b01b-8019d4570676','次韵陳叔永山居二首  其一','范浚','宋','宋诗','song-poetry','','[]','聞君結屋廬，幽意枕山隅。',48,'全唐诗/poet.song.111000.json','["聞君結屋廬，幽意枕山隅。", "𠜴竹開三徑，栽桃課百株。", "眼根長寂寥，心地不崎嶇。", "試問新詩句，能窮勝事無。"]'),
('b4d507f6-31b3-4040-86ff-865300dc166e','次韵陳叔永山居二首  其二','范浚','宋','宋诗','song-poetry','','[]','子方誇小隠，我亦愛深居。',48,'全唐诗/poet.song.111000.json','["子方誇小隠，我亦愛深居。", "出補登山屐，歸携带月鋤。", "旋沽新漉酒，聊駐故人車。", "有此幽棲樂，雖貧亦晏如。"]'),
('58368874-17ec-4658-876a-ce253d3b96b8','西園','范浚','宋','宋诗','song-poetry','','[]','路入西園繞綠苔，我來倚杖一徘徊。',64,'全唐诗/poet.song.111000.json','["路入西園繞綠苔，我來倚杖一徘徊。", "霜林有樹葉皆落，風榭無人花自開。", "奴橘甘酸千百顆，侯梅蕭薄兩三栽。", "幽人自是便幽勝，終日孤吟只費才。"]'),
('c571451c-8c9b-419a-a25f-6575dc4ddb67','戲效白傅體送姚刪定','范浚','宋','宋诗','song-poetry','','[]','倦客長年嗟久客，交游此地喜偕遊。',64,'全唐诗/poet.song.111000.json','["倦客長年嗟久客，交游此地喜偕遊。", "後溪水接前溪碧，小響峰連大響幽。", "千里家山千里夢，一春風月一春愁。", "今朝共話明朝別，取醉君無不醉休。"]'),
('cec863b0-536a-48e2-8e39-e545941531f3','避盜泊舟武康遠光亭下與同行分和杜工部詩傷秋及宿江邊閣二首  其一','范浚','宋','宋诗','song-poetry','','[]','带郭人烟少，通村徑路微。',72,'全唐诗/poet.song.111000.json','["带郭人烟少，通村徑路微。", "水光浮棟宇，野色動窗扉。", "小樹無重數，前山不合圍。", "艱危鄰虎窟，奔迫詭牛衣。", "白舫竟何適，丹楓看即稀。", "西園小茅屋，知復幾時歸。"]'),
('e7293041-2723-4ed4-a482-9cdfebbcb911','避盜泊舟武康遠光亭下與同行分和杜工部詩傷秋及宿江邊閣二首  其二','范浚','宋','宋诗','song-poetry','','[]','客子舟維岸，人家樹作門。',48,'全唐诗/poet.song.111000.json','["客子舟維岸，人家樹作門。", "西風秋慘切，南鵲夜飛翻。", "惻惻驚心折，鞺鞺戍鼓喧。", "若爲容足地，廣大自乾坤。"]'),
('7d878816-4f04-490b-b6b8-2403d13eb988','遊南山晚歸二首  其一','范浚','宋','宋诗','song-poetry','','[]','樂事愜幽討，閑情便舊遊。',48,'全唐诗/poet.song.111000.json','["樂事愜幽討，閑情便舊遊。", "梳風修竹晚，掛日老楓秋。", "一飽桑門飯，百忘塵世憂。", "蕭條茅屋下，可以縱冥搜。"]'),
('9c6bafb2-5994-4774-850f-7fc642db424a','遊南山晚歸二首  其二','范浚','宋','宋诗','song-poetry','','[]','荒荒日已暮，迴首興何長。',48,'全唐诗/poet.song.111000.json','["荒荒日已暮，迴首興何長。", "䆉䅉紛乾穟，森疏嘯折篁。", "水枯山石露，風晚野花香。", "歸卧前簷下，詩成小雨凉。"]'),
('c23e557e-971e-4123-b2aa-6fca66d662ff','賀長兄茂寬賜緋','范浚','宋','宋诗','song-poetry','','[]','褒功傳紫詔，錫服下丹墀。',48,'全唐诗/poet.song.111000.json','["褒功傳紫詔，錫服下丹墀。", "朱紱榮書記，銀章付拾遺。", "舄鳬隨步趾，象笏映鬚眉。", "更卜垂三組，它年佩陸離。"]'),
('7665fe9b-553a-42fb-bcbb-4531aefd7edf','李修撰哀輓二首  其一','范浚','宋','宋诗','song-poetry','','[]','三朝推舊德，四海仰高名。',48,'全唐诗/poet.song.111000.json','["三朝推舊德，四海仰高名。", "起起方驚夢，嗟嗟忽奠楹。", "木冰傷達宦，薤露寄哀情。", "矯首西山下，懸河淚已傾。"]'),
('bc18459e-61dd-417c-9aad-72bb5bcadbce','李修撰哀輓二首  其二','范浚','宋','宋诗','song-poetry','','[]','公欲攀琪樹，天令墮玉棺。',48,'全唐诗/poet.song.111000.json','["公欲攀琪樹，天令墮玉棺。", "生前紆白艾，身後跨青鸞。", "令子清規在，遺書舊墨乾。", "英靈今已逝，千古一長歎。"]'),
('2629d699-e906-4bb2-bc49-747babd6d739','冬日行蘭谿道中六言二首  其一','范浚','宋','宋诗','song-poetry','','[]','雲頑欲雪不雪，梅凍將花未花。',28,'全唐诗/poet.song.111000.json','["雲頑欲雪不雪，梅凍將花未花。", "荒草狹蹊山路，斷橋流水人家。"]'),
('cd671805-4a70-4672-a3e1-8b8dac249edd','冬日行蘭谿道中六言二首  其二','范浚','宋','宋诗','song-poetry','','[]','瑟縮鴉栖古樹，聯拳鷺立回塘。',28,'全唐诗/poet.song.111000.json','["瑟縮鴉栖古樹，聯拳鷺立回塘。", "水際風低白葦，隔村時見牛羊。"]'),
('eeee4db9-fbb0-420d-8bfd-03a4a31011e9','忘言示曾仲思','范浚','宋','宋诗','song-poetry','','[]','范叔初非辯士，曾子本同道人。',28,'全唐诗/poet.song.111000.json','["范叔初非辯士，曾子本同道人。", "歡伯解兩家難，忘言一笑相親。"]'),
('84ba56c4-110f-4b1e-b33e-30d2dde768b4','春日行蘭谿道中六言','范浚','宋','宋诗','song-poetry','','[]','遠草連雲碧積，繁花照日紅酣。',28,'全唐诗/poet.song.111000.json','["遠草連雲碧積，繁花照日紅酣。", "信馬貪看春意，不知錯過村南。"]'),
('cedbbea4-5b1a-4b20-837b-9324fe75d80d','次韵弟茂通郊行見梅','范浚','宋','宋诗','song-poetry','','[]','好風催冷蕊，上番即芳葩。',48,'全唐诗/poet.song.111000.json','["好風催冷蕊，上番即芳葩。", "春色獨先得，年芳誰復加。", "日邊看暖艷，雪後識真花。", "吟玩歸來晚，江村月照沙。"]'),
('ace88ace-55dd-427a-b050-154c3454e48f','次韵姪端臣七夕','范浚','宋','宋诗','song-poetry','','[]','萬古東西隔女牛，停梭期會豈悠悠。',64,'全唐诗/poet.song.111000.json','["萬古東西隔女牛，停梭期會豈悠悠。", "蝦蟆輪破青天暮，烏鵲橋橫碧漢秋。", "莫放癡兒懽徹曙，且容老子强登樓。", "舉瓢更取天漿酌，一洗胸中萬斛愁。"]'),
('1e04d1d0-ef45-4e2c-aabc-ce6f04093a9b','贈光上人','范浚','宋','宋诗','song-poetry','','[]','道人工小筆，梅瘦竹嬋娟。',48,'全唐诗/poet.song.111000.json','["道人工小筆，梅瘦竹嬋娟。", "更學有聲畫，不參無眼禪。", "一枰聊復爾，七馬獨超然。", "爲足前年句，真成續斷弦。"]'),
('c0439643-f7f2-4ba7-a62e-a225c404be83','張生夜載酒相過','范浚','宋','宋诗','song-poetry','','[]','夜卷一鈎簾，衣寒覺露霑。',48,'全唐诗/poet.song.111000.json','["夜卷一鈎簾，衣寒覺露霑。", "未驚風割面，且看月磨鎌。", "玉椀鵝兒酒，花甆虎子鹽。", "張公雞黍舊，歡笑了無嫌。"]'),
('1406d1be-4d87-436d-8c35-181ce4ec6fc0','幽居','范浚','宋','宋诗','song-poetry','','[]','幽居長杜戶，竟日少來人。',48,'全唐诗/poet.song.111000.json','["幽居長杜戶，竟日少來人。", "花動蜂兒去，簾垂燕子嗔。", "脫巾慵不整，得酒醉仍頻。", "養拙風塵外，吾寧愧此身。"]'),
('d4bfe53b-31b2-4f6d-b2cf-23f3d48b6e15','寓龍丘次韵六兄茂永見寄','范浚','宋','宋诗','song-poetry','','[]','夢想常懷兄弟賢，何如合眼到東川。',64,'全唐诗/poet.song.111000.json','["夢想常懷兄弟賢，何如合眼到東川。", "客居自幸貧無事，歸計猶須大有年。", "一丈席間方隔闊，萬金書意要頻傳。", "詩筒更喜如飛鳥，願乞清新一百篇。"]'),
('be76de31-1a18-47c4-8258-5cd17743a6a7','姪端旻示遊浦江花藏寺詩且道皎老相問意因次韵併煩爲簡皎公禪師','范浚','宋','宋诗','song-poetry','','[]','子到祇陀舍，經行幾屐穿。',48,'全唐诗/poet.song.111000.json','["子到祇陀舍，經行幾屐穿。", "想當吟出月，不奈思如泉。", "真界飛花雨，寒山落木天。", "皎公知好在，香室夜安禪。"]'),
('6b3914d5-48fa-428c-afd7-b0af19a8bffb','次韵三兄茂載偶成二首  其一','范浚','宋','宋诗','song-poetry','','[]','自笑踆踆走海邊，棲遲已與俗相捐。',64,'全唐诗/poet.song.111000.json','["自笑踆踆走海邊，棲遲已與俗相捐。", "誰憐乞米問盧老，懶以無薪告仲連。", "案上三杯朝不飽，膝頭一榻夜驚穿。", "詩人未用生羞澀，尚覺囊中有一錢。"]'),
('540072b1-5b42-46d4-bef4-46f699ac6c2b','次韵三兄茂載偶成二首  其二','范浚','宋','宋诗','song-poetry','','[]','君看如絃死道邊，由來忠骾世人捐。',64,'全唐诗/poet.song.111000.json','["君看如絃死道邊，由來忠骾世人捐。", "劍除佞士朱狂直，笏擊姦臣顧少連。", "莫以古人蘄薄俗，空嗟膏軸運方穿。", "齒牙枉插於菟口，見說官家廢料錢。"]'),
('6037b939-1c11-4ca1-a313-a503c2d6a8b6','送歐丈朝請赴闕','范浚','宋','宋诗','song-poetry','','[]','祖道春風外，傷懷野水濱。',48,'全唐诗/poet.song.111000.json','["祖道春風外，傷懷野水濱。", "親盟丈人行，才力棟梁臣。", "好去鞭高足，榮期據要津。", "人言宣室召，未棄賈生貧。"]'),
('22ae17f7-d818-4906-9e77-681bb9dcbc9a','春飲分章字韵','范浚','宋','宋诗','song-poetry','','[]','傳杯行美釀，擊鉢課名章。',48,'全唐诗/poet.song.111000.json','["傳杯行美釀，擊鉢課名章。", "月借全窗白，花分小樹香。", "人情歡不盡，道術醉相忘。", "雞黍襟期厚，渠論漢范張。"]'),
('c3c63b3a-5789-421e-971a-694cb8fcf5dc','次韵富修仲見贈二首  其一','范浚','宋','宋诗','song-poetry','','[]','故人欣面款，令我得眉伸。',48,'全唐诗/poet.song.111000.json','["故人欣面款，令我得眉伸。", "意有千金重，詩無一字陳。", "清規看後裔，賢業想前人。", "會續安邊策，何當謁紫宸。"]'),
('e1ad7ca4-c9df-4483-9edd-c89029ef3887','次韵富修仲見贈二首  其二','范浚','宋','宋诗','song-poetry','','[]','幽棲長懶放，野性耻浮沈。',48,'全唐诗/poet.song.111000.json','["幽棲長懶放，野性耻浮沈。", "避俗真成僻，居山恨不深。", "感君來辱意，契我願交心。", "但愧瓊瑶贈，才枯欲嗣音。"]'),
('6f0e3e9b-e1ca-403f-b86b-ead1a79b8358','過嚴州烏龍嶺','范浚','宋','宋诗','song-poetry','','[]','何年龍脅破鱗皴，應是風雷役鬼神。',64,'全唐诗/poet.song.111000.json','["何年龍脅破鱗皴，應是風雷役鬼神。", "曲折鑿開南北路，去來老盡利名人。", "秦雲楚樹青天外，禹穴胥山滄海濱。", "下視蓑城如掌大，市聲啾唧暗紅塵。"]'),
('0410d1ff-fce5-4577-909e-9caad9f0e800','次韵翁承之見寄二首  其一','范浚','宋','宋诗','song-poetry','','[]','人情巇險摧車路，世事變遷鳴屐廊。',64,'全唐诗/poet.song.111000.json','["人情巇險摧車路，世事變遷鳴屐廊。", "自分北宮長糲食，懶從東壁借餘光。", "林廬雪後梅含白，籬落天寒橘孕黄。", "幽意只應君共醉，何時拂石對傾觴。"]'),
('bc5bb703-ef5a-44be-b6a9-4a15ea46050b','次韵翁承之見寄二首  其二','范浚','宋','宋诗','song-poetry','','[]','伊我索居吟雪屋，懷君獨夜步風廊。',64,'全唐诗/poet.song.111000.json','["伊我索居吟雪屋，懷君獨夜步風廊。", "語離尚憶三春暮，共醉曾分一日光。", "忽喜斜封書絹白，更傳妙語色絲黄。", "遥知發興虬松下，白眼看天自舉觴。"]'),
('f213203d-4225-4ace-bdf9-9fcba5e57691','懷曹宗臣併寄','范浚','宋','宋诗','song-poetry','','[]','閉關自喜脫愁籠，未愧柴桑避俗翁。',64,'全唐诗/poet.song.111000.json','["閉關自喜脫愁籠，未愧柴桑避俗翁。", "黄嬭引人千里夢，青奴借我一窗風。", "綠葵紫蓼園蔬課，白葛朱藤野步供。", "尚想故人懷別久，論文安得一樽同。"]'),
('6b2bb453-6d06-43a5-bad5-4936e9ef30fe','次韵姪伯通歲暮即事','范浚','宋','宋诗','song-poetry','','[]','世情分付與東流，含梗徒勞百念浮。',64,'全唐诗/poet.song.111000.json','["世情分付與東流，含梗徒勞百念浮。", "但使心源長寡欲，便知樂地本無憂。", "處身忌作燕巢幕，脫事要如鷹掣韝。", "節臘好同營一醉，幸逢開泰戢戈矛。"]'),
('b46036d7-791f-4d41-9f4f-b75754bdb51d','悼致政樓少師  其一','范浚','宋','宋诗','song-poetry','','[]','雅望題輿早已賢，高風晚歲更超然。',64,'全唐诗/poet.song.111000.json','["雅望題輿早已賢，高風晚歲更超然。", "笑收劍佩遺榮路，獨往山林事引年。", "行馬正看光梓里，卧麟忽歎掩松阡。", "鄉州耆舊今垂盡，忍見山頹重涕漣。"]'),
('2193de98-851a-4c89-b8d4-780f472f45da','悼致政樓少師  其二','范浚','宋','宋诗','song-poetry','','[]','身後儲休世或同，生前有耀孰踰公。',64,'全唐诗/poet.song.111000.json','["身後儲休世或同，生前有耀孰踰公。", "班衣五彩樞臣貴，寶带萬釘天眷隆。", "終始哀榮時共羨，丕揚寵贈會追崇。", "遥瞻素旆愁雲外，慘憺悲歌立晚風。"]'),
('57122d96-3df4-48bd-8c6a-dab0e49d893e','寓居蘭谿地濕卧病','范浚','宋','宋诗','song-poetry','','[]','病怯簾疏雨到床，雨餘山靄上衣裳。',64,'全唐诗/poet.song.111000.json','["病怯簾疏雨到床，雨餘山靄上衣裳。", "宵携冷杖强看月，曉傍暖簷貪向陽。", "禦濕要須謀日飲，乏資深恨值年荒。", "所須藥物真吾事，麥麴山鞠今滿囊。"]'),
('411e272a-6f3e-43a7-8253-6909375a5c65','次韵姪端臣同遊藏春園','范浚','宋','宋诗','song-poetry','','[]','探春著屐犯榛荒，更入名園轉曲塘。',64,'全唐诗/poet.song.111000.json','["探春著屐犯榛荒，更入名園轉曲塘。", "紅認蔬畦憐小甲，白尋梅楥得幽香。", "全同花下迷山簡，只欠池頭語葛强。", "吾土信多行樂地，絕勝酒裏到家鄉。"]'),
('ea2dedca-f5d6-4391-9f35-24cdf990fa18','詠東山','范浚','宋','宋诗','song-poetry','','[]','烟嶂巍巍列翠屏，松山高下鬰葱菁。',32,'全唐诗/poet.song.111000.json','["烟嶂巍巍列翠屏，松山高下鬰葱菁。", "風生萬壑笙竽觸，擬向林間築小亭。"]'),
('53f61a91-2103-4386-bea8-3e7dcd5a806e','次韵姪端方喜雪','范浚','宋','宋诗','song-poetry','','[]','川原恍若白崖天，屑玉輕明瑞有年。',64,'全唐诗/poet.song.111000.json','["川原恍若白崖天，屑玉輕明瑞有年。", "折竹掀轟宵暗積，欺梅艷溢曉相鮮。", "當知破耳衝風出，未似蒙頭正晝眠。", "杲日能憐有貧者，不須更作寄天牋。"]'),
('4ce9fa43-edbf-4af3-93ce-676f0be0635f','送王大聲','范浚','宋','宋诗','song-poetry','','[]','腹藁才名第一流，只今偃蹇困吳州。',64,'全唐诗/poet.song.111000.json','["腹藁才名第一流，只今偃蹇困吳州。", "牛腰但使詩章富，鶴髮寧論歲月遒。", "恥傍朱門隨掉尾，獨尋青篛釣查頭。", "知君高勝如松竹，不遇猶爲瀟灑侯。"]'),
('d3a941b4-3566-4d03-8531-2109a5af53c4','三兄茂載燕兄弟預者六友宜盡觴詠之樂長兄茂寬有詩因次其韵','范浚','宋','宋诗','song-poetry','','[]','南北東西遇合疏，偶然良會足歡娛。',64,'全唐诗/poet.song.111000.json','["南北東西遇合疏，偶然良會足歡娛。", "豹胎供饌斥魚婢，雀舌試湯分酪奴。", "花萼成詩多共賦，竹根有酒不須沽。", "借令六逸無人畫，也勝當年九老圖。"]'),
('9cc84165-be77-453a-8b36-b8ca2ec9253f','禱雨頌','釋德','宋','宋诗','song-poetry','','[]','振法雷，擊法鼓。',16,'全唐诗/poet.song.111000.json','["振法雷，擊法鼓。", "布慈雲，灑甘露。"]'),
('806be448-5d68-46df-b399-f6354038c964','句','釋德','宋','宋诗','song-poetry','','[]','竚看長空垂巨澤，直教四海盡豐登。',16,'全唐诗/poet.song.111000.json','["竚看長空垂巨澤，直教四海盡豐登。"]'),
('c62fc43d-b2c1-4b45-b0ec-790c06aaaa06','悟趙州狗子無佛性話偈','釋南','宋','宋诗','song-poetry','','[]','狗子無佛性，羅睺星入命。',24,'全唐诗/poet.song.111000.json','["狗子無佛性，羅睺星入命。", "不是打殺人，被人打殺定。"]'),
('f7a182ac-15ec-4301-943f-5e9c2c4d546a','謝人','馮觀國','宋','宋诗','song-poetry','','[]','踏遍紅塵四百州，幾多風月是良儔。',32,'全唐诗/poet.song.111000.json','["踏遍紅塵四百州，幾多風月是良儔。", "朝來應笑酡顔叟，道不相侔風馬牛。"]'),
('aff5e785-33da-4178-b677-501380cfb87a','述懷','馮觀國','宋','宋诗','song-poetry','','[]','落魄塵寰觸處然，深藏妙用散神仙。',64,'全唐诗/poet.song.111000.json','["落魄塵寰觸處然，深藏妙用散神仙。", "筆端間作龍蛇走，壺裏常挑日月懸。", "漫假人倫來混世，只將酒盞度流年。", "潛修功行歸何處，笑指瀛洲返洞天。"]'),
('221edfa3-e812-4bea-a5a3-c19c9ac826dd','酒間作','馮觀國','宋','宋诗','song-poetry','','[]','南北東西總是家，自知身命屬煙霞。',32,'全唐诗/poet.song.111000.json','["南北東西總是家，自知身命屬煙霞。", "只因貪戀一杯酒，誤却碧桃千樹花。"]'),
('29056b8b-6196-4cf0-982c-4e5d48906b46','題棟','馮觀國','宋','宋诗','song-poetry','','[]','水非溝壑龍方卧，木是梧桐鳳始栖。',32,'全唐诗/poet.song.111000.json','["水非溝壑龍方卧，木是梧桐鳳始栖。", "莫道男兒無去路，碧霄雲外有仙梯。"]'),
('fae81e7c-c3ad-4b5a-add4-26daab7df593','臨終頌','馮觀國','宋','宋诗','song-poetry','','[]','平生無町畦，任真但落魄。',24,'全唐诗/poet.song.111000.json','["平生無町畦，任真但落魄。", "爛醉是生涯，天地爲棺槨。"]');
